use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Expense {
    pub team: &'static str,
    pub category: &'static str,
    pub amount: i32,
    pub approved: bool,
}

pub fn summarize(expenses: &[Expense]) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();
    let mut count = 0;

    for e in expenses {
        if e.amount <= 0 {
            continue;
        }
        *totals.entry(e.team).or_insert(0) += e.amount;
        count += 1;
    }

    let grand_total: i32 = totals.values().copied().sum();
    let mut out = format!("approved_count={} total={}\n", count, grand_total);

    for (team, total) in totals {
        out.push_str(&format!("{}:{}\n", team, total));
    }

    out
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn summarizes_only_approved_positive_non_misc_in_descending_total_order() {
        let expenses = [
            Expense { team: "ops", category: "travel", amount: 40, approved: true },
            Expense { team: "eng", category: "meals", amount: 25, approved: true },
            Expense { team: "ops", category: "misc", amount: 7, approved: true },
            Expense { team: "eng", category: "supplies", amount: -2, approved: true },
            Expense { team: "sales", category: "travel", amount: 30, approved: false },
            Expense { team: "sales", category: "travel", amount: 12, approved: true },
            Expense { team: "eng", category: "travel", amount: 25, approved: true },
        ];

        let expected = concat!(
            "approved_count=4 total=102\n",
            "eng:50\n",
            "ops:40\n",
            "sales:12\n"
        );

        assert_eq!(summarize(&expenses), expected);
    }

    #[test]
    fn ties_use_team_name_ascending_and_empty_result_has_no_team_lines() {
        let expenses = [
            Expense { team: "beta", category: "travel", amount: 10, approved: true },
            Expense { team: "alpha", category: "travel", amount: 10, approved: true },
            Expense { team: "zeta", category: "misc", amount: 99, approved: true },
            Expense { team: "omega", category: "travel", amount: 8, approved: false },
        ];

        let expected = concat!(
            "approved_count=2 total=20\n",
            "alpha:10\n",
            "beta:10\n"
        );
        assert_eq!(summarize(&expenses), expected);

        let none = [
            Expense { team: "ops", category: "misc", amount: 5, approved: true },
            Expense { team: "eng", category: "travel", amount: 9, approved: false },
            Expense { team: "sales", category: "meals", amount: 0, approved: true },
        ];
        assert_eq!(summarize(&none), "approved_count=0 total=0\n");
    }
}

