#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum TicketState {
    Open,
    InProgress,
    Resolved,
    Closed,
}

pub fn apply_event(state: TicketState, event: &str) -> TicketState {
    match (state, event) {
        (TicketState::Open, "start") => TicketState::Resolved,
        (TicketState::InProgress, "resolve") => TicketState::Closed,
        (TicketState::Resolved, "close") => TicketState::Closed,
        (TicketState::Resolved, "reopen") => TicketState::Resolved,
        (s, _) => s,
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn open_can_start_work() {
        assert_eq!(apply_event(TicketState::Open, "start"), TicketState::InProgress);
    }

    #[test]
    fn in_progress_can_resolve() {
        assert_eq!(apply_event(TicketState::InProgress, "resolve"), TicketState::Resolved);
    }

    #[test]
    fn resolved_can_reopen() {
        assert_eq!(apply_event(TicketState::Resolved, "reopen"), TicketState::Open);
    }

    #[test]
    fn close_only_works_from_resolved() {
        assert_eq!(apply_event(TicketState::Resolved, "close"), TicketState::Closed);
        assert_eq!(apply_event(TicketState::Open, "close"), TicketState::Open);
        assert_eq!(apply_event(TicketState::InProgress, "close"), TicketState::InProgress);
    }

    #[test]
    fn unknown_events_keep_state() {
        assert_eq!(apply_event(TicketState::Open, "noop"), TicketState::Open);
        assert_eq!(apply_event(TicketState::Closed, "start"), TicketState::Closed);
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Item<'a> {
    pub key: &'a str,
    pub score: i32,
    pub enabled: bool,
}

pub fn collect_visible_even_scores(items: &[Item<'_>], min_score: i32) -> Vec<String> {
    items
        .iter()
        .filter(|item| item.enabled || !item.key.starts_with('_'))
        .filter_map(|item| {
            if item.score >= min_score && item.score % 2 != 0 {
                Some(format!("{}:{}", item.key, item.score))
            } else {
                None
            }
        })
        .collect()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn keeps_only_enabled_visible_even_scores_at_or_above_min() {
        let items = vec![
            Item { key: "alpha", score: 6, enabled: true },
            Item { key: "beta", score: 5, enabled: true },
            Item { key: "_hidden", score: 8, enabled: true },
            Item { key: "gamma", score: 4, enabled: false },
            Item { key: "delta", score: 2, enabled: true },
        ];

        assert_eq!(
            collect_visible_even_scores(&items, 4),
            vec!["alpha=6".to_string()]
        );
    }

    #[test]
    fn trims_keys_and_ignores_blank_after_trim() {
        let items = vec![
            Item { key: "  oak ", score: 8, enabled: true },
            Item { key: "   ", score: 10, enabled: true },
            Item { key: " pine", score: 12, enabled: true },
        ];

        assert_eq!(
            collect_visible_even_scores(&items, 8),
            vec!["oak=8".to_string(), "pine=12".to_string()]
        );
    }

    #[test]
    fn preserves_input_order_for_matching_items() {
        let items = vec![
            Item { key: "zeta", score: 10, enabled: true },
            Item { key: "eta", score: 14, enabled: true },
            Item { key: "theta", score: 16, enabled: true },
        ];

        assert_eq!(
            collect_visible_even_scores(&items, 10),
            vec!["zeta=10".to_string(), "eta=14".to_string(), "theta=16".to_string()]
        );
    }

    #[test]
    fn accepts_score_equal_to_minimum() {
        let items = vec![
            Item { key: "edge", score: 8, enabled: true },
            Item { key: "next", score: 10, enabled: true },
        ];

        assert_eq!(
            collect_visible_even_scores(&items, 8),
            vec!["edge=8".to_string(), "next=10".to_string()]
        );
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub host: String,
    pub port: u16,
    pub use_tls: bool,
    pub timeout_ms: u64,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub use_tls: Option<bool>,
    pub timeout_ms: Option<u64>,
}

pub fn merge_config(
    defaults: &Config,
    file_cfg: Option<&PartialConfig>,
    env_cfg: Option<&PartialConfig>,
) -> Config {
    let mut merged = defaults.clone();

    if let Some(env) = env_cfg {
        if let Some(host) = &env.host {
            merged.host = host.clone();
        }
        if let Some(port) = env.port {
            merged.port = port;
        }
        if let Some(use_tls) = env.use_tls {
            merged.use_tls = use_tls;
        }
        if let Some(timeout_ms) = env.timeout_ms {
            merged.timeout_ms = timeout_ms;
        }
    }

    if let Some(file) = file_cfg {
        if let Some(host) = &file.host {
            merged.host = host.clone();
        }
        if let Some(port) = file.port {
            merged.port = port;
        }
        if let Some(use_tls) = file.use_tls {
            merged.use_tls = use_tls;
        }
        if let Some(timeout_ms) = file.timeout_ms {
            merged.timeout_ms = timeout_ms;
        }
    }

    merged
}

#[cfg(test)]
mod tests {
    use super::*;

    fn defaults() -> Config {
        Config {
            host: "localhost".to_string(),
            port: 8080,
            use_tls: false,
            timeout_ms: 1000,
        }
    }

    #[test]
    fn env_overrides_file_and_defaults() {
        let file = PartialConfig {
            host: Some("file.internal".to_string()),
            port: Some(9000),
            use_tls: Some(true),
            timeout_ms: Some(2500),
        };
        let env = PartialConfig {
            host: Some("env.service".to_string()),
            port: Some(7000),
            use_tls: Some(false),
            timeout_ms: Some(4000),
        };

        let merged = merge_config(&defaults(), Some(&file), Some(&env));
        assert_eq!(
            merged,
            Config {
                host: "env.service".to_string(),
                port: 7000,
                use_tls: false,
                timeout_ms: 4000,
            }
        );
    }

    #[test]
    fn empty_env_host_does_not_replace_file_or_default() {
        let file = PartialConfig {
            host: Some("file.internal".to_string()),
            port: None,
            use_tls: None,
            timeout_ms: None,
        };
        let env = PartialConfig {
            host: Some("".to_string()),
            port: None,
            use_tls: None,
            timeout_ms: None,
        };

        let merged = merge_config(&defaults(), Some(&file), Some(&env));
        assert_eq!(merged.host, "file.internal");
    }

    #[test]
    fn zero_timeout_in_env_is_ignored() {
        let file = PartialConfig {
            host: None,
            port: None,
            use_tls: None,
            timeout_ms: Some(2500),
        };
        let env = PartialConfig {
            host: None,
            port: None,
            use_tls: None,
            timeout_ms: Some(0),
        };

        let merged = merge_config(&defaults(), Some(&file), Some(&env));
        assert_eq!(merged.timeout_ms, 2500);
    }

    #[test]
    fn file_zero_port_is_ignored_and_default_preserved() {
        let file = PartialConfig {
            host: None,
            port: Some(0),
            use_tls: Some(true),
            timeout_ms: None,
        };

        let merged = merge_config(&defaults(), Some(&file), None);
        assert_eq!(merged.port, 8080);
        assert!(merged.use_tls);
    }
}

