pub fn can_book(existing: &[(u32, u32)], start: u32, end: u32) -> bool {
    if start > end {
        return false;
    }

    for &(s, e) in existing {
        if start <= e && end >= s {
            return false;
        }
    }

    true
}

#[cfg(test)]
mod tests {
    use super::can_book;

    #[test]
    fn allows_non_overlapping_gap() {
        let existing = vec![(10, 12), (15, 20)];
        assert!(can_book(&existing, 12, 15));
    }

    #[test]
    fn rejects_partial_overlap() {
        let existing = vec![(10, 12), (15, 20)];
        assert!(!can_book(&existing, 11, 16));
    }

    #[test]
    fn rejects_contained_booking() {
        let existing = vec![(30, 40)];
        assert!(!can_book(&existing, 32, 35));
    }

    #[test]
    fn rejects_zero_length_booking() {
        let existing = vec![(5, 8)];
        assert!(!can_book(&existing, 9, 9));
    }

    #[test]
    fn treats_intervals_as_half_open() {
        let existing = vec![(5, 10)];
        assert!(can_book(&existing, 10, 12));
        assert!(can_book(&existing, 3, 5));
    }
}

