#[derive(Debug, PartialEq, Eq)]
pub struct Record {
    pub name: String,
    pub age: u8,
    pub active: bool,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();
    for (idx, raw_line) in input.lines().enumerate() {
        let line = raw_line.trim();
        if line.is_empty() {
            continue;
        }

        let mut name = "";
        let mut age = 0u8;
        let mut active = false;

        for part in line.split(';') {
            let mut it = part.splitn(2, '=');
            let key = it.next().unwrap_or("");
            let value = it.next().unwrap_or("");
            match key {
                "name" => name = value,
                "age" => age = value.parse().unwrap_or(0),
                "active" => active = value == "true",
                _ => {}
            }
        }

        if name.is_empty() {
            return Err(format!("line {} missing name", idx + 1));
        }

        out.push(Record {
            name: name.to_string(),
            age,
            active,
        });
    }
    Ok(out)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn parses_valid_records_and_ignores_comments() {
        let input = "\n# heading\nname=alice;age=30;active=true\n\nname=bob;active=false;age=7\n";
        let got = parse_records(input).unwrap();
        assert_eq!(
            got,
            vec![
                Record {
                    name: "alice".into(),
                    age: 30,
                    active: true,
                },
                Record {
                    name: "bob".into(),
                    age: 7,
                    active: false,
                },
            ]
        );
    }

    #[test]
    fn trims_spaces_and_requires_exactly_three_known_fields() {
        let input = " name = cara ; age = 41 ; active = true ";
        let got = parse_records(input).unwrap();
        assert_eq!(
            got,
            vec![Record {
                name: "cara".into(),
                age: 41,
                active: true,
            }]
        );

        assert!(parse_records("name=d;age=9").is_err());
        assert!(parse_records("name=d;age=9;active=true;extra=x").is_err());
    }

    #[test]
    fn rejects_bad_values_and_duplicate_keys() {
        assert!(parse_records("name=eve;age=200;active=true").is_err());
        assert!(parse_records("name=eve;age=nope;active=true").is_err());
        assert!(parse_records("name=eve;age=20;active=yes").is_err());
        assert!(parse_records("name=eve;name=other;age=20;active=true").is_err());
    }
}

