pub struct Entry<'a> {
    pub name: &'a str,
    pub score: Option<u32>,
    pub active: bool,
}

pub fn collect_tagged_scores(entries: &[Entry<'_>], min_score: u32) -> Vec<String> {
    entries
        .iter()
        .filter_map(|e| e.score.map(|score| (e, score)))
        .filter(|(_, score)| *score > min_score)
        .map(|(e, score)| format!("{}:{}", e.name, score))
        .collect()
}

