use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub team: &'static str,
    pub month: &'static str,
    pub amount: i32,
    pub billable: bool,
}

pub fn build_report(entries: &[Entry]) -> Vec<String> {
    let mut totals: BTreeMap<&str, (i32, usize)> = BTreeMap::new();

    for e in entries {
        let slot = totals.entry(e.team).or_insert((0, 0));
        slot.0 += e.amount;
        slot.1 += 1;
    }

    let mut rows: Vec<_> = totals.into_iter().collect();
    rows.sort_by(|a, b| a.0.cmp(b.0));

    rows
        .into_iter()
        .map(|(team, (amount, count))| format!("{}|{}|{}", team, amount, count))
        .collect()
}

