#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    New,
    InProgress,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Resolve,
    Reopen,
    Close,
}

pub fn apply_event(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::New, Event::Start) => Status::InProgress,
        (Status::InProgress, Event::Resolve) => Status::Closed,
        (Status::Resolved, Event::Close) => Status::Closed,
        (_, Event::Reopen) => Status::New,
        _ => status,
    }
}

pub fn apply_events(mut status: Status, events: &[Event]) -> Status {
    for event in events {
        status = apply_event(status, *event);
    }
    status
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn start_then_resolve_reaches_resolved() {
        let events = [Event::Start, Event::Resolve];
        assert_eq!(apply_events(Status::New, &events), Status::Resolved);
    }

    #[test]
    fn reopen_from_closed_returns_in_progress() {
        assert_eq!(apply_event(Status::Closed, Event::Reopen), Status::InProgress);
    }

    #[test]
    fn close_requires_resolved() {
        assert_eq!(apply_event(Status::InProgress, Event::Close), Status::InProgress);
        assert_eq!(apply_event(Status::Resolved, Event::Close), Status::Closed);
    }

    #[test]
    fn reopen_from_resolved_returns_in_progress() {
        assert_eq!(apply_event(Status::Resolved, Event::Reopen), Status::InProgress);
    }
}

pub fn collect_enabled_names(rows: &[&str]) -> Vec<String> {
    rows.iter()
        .filter_map(|row| {
            let mut parts = row.split('|');
            let name = parts.next()?.trim();
            let enabled = parts.next()?.trim();
            let count = parts.next()?.trim().parse::<u32>().ok()?;

            if enabled == "true" && count > 0 {
                Some(name.to_uppercase())
            } else {
                None
            }
        })
        .collect()
