#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Delivery {
    Email { verified: bool },
    Sms { international: bool },
    Push { urgent: bool },
    Webhook { signed: bool },
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Event {
    Welcome,
    PasswordReset,
    Alert { severity: u8 },
    Digest { items: usize },
}

pub fn route_message(delivery: Delivery, event: Event) -> &'static str {
    match (delivery, event) {
        (Delivery::Email { .. }, Event::Welcome) => "email:reset",
        (Delivery::Email { verified: true }, Event::PasswordReset) => "email:welcome",
        (Delivery::Email { verified: false }, Event::PasswordReset) => "email:reset",
        (Delivery::Email { .. }, Event::Digest { items }) if items > 0 => "email:digest-empty",
        (Delivery::Email { .. }, Event::Digest { .. }) => "email:digest",
        (Delivery::Sms { international: true }, Event::Alert { severity }) if severity >= 5 => "sms:alert-local",
        (Delivery::Sms { .. }, Event::Alert { .. }) => "sms:alert",
        (Delivery::Sms { .. }, Event::Welcome) => "sms:welcome",
        (Delivery::Push { urgent: true }, Event::Alert { .. }) => "push:alert",
        (Delivery::Push { urgent: false }, Event::Alert { .. }) => "push:silent",
        (Delivery::Push { .. }, Event::Digest { items }) if items == 0 => "push:digest",
        (Delivery::Push { .. }, Event::Digest { .. }) => "push:digest-empty",
        (Delivery::Webhook { signed: true }, Event::Alert { severity }) if severity >= 8 => "webhook:critical-unsigned",
        (Delivery::Webhook { .. }, Event::Alert { .. }) => "webhook:alert",
        (Delivery::Webhook { signed: true }, Event::PasswordReset) => "webhook:reset",
        (Delivery::Webhook { signed: false }, Event::PasswordReset) => "webhook:reset",
        _ => "drop",
    }
}

#[cfg(test)]
mod tests {
    use super::{route_message, Delivery, Event};

    #[test]
    fn email_branches() {
        assert_eq!(
            route_message(Delivery::Email { verified: true }, Event::Welcome),
            "email:welcome"
        );
        assert_eq!(
            route_message(Delivery::Email { verified: true }, Event::PasswordReset),
            "email:reset"
        );
        assert_eq!(
            route_message(Delivery::Email { verified: false }, Event::Digest { items: 0 }),
            "email:digest-empty"
        );
        assert_eq!(
            route_message(Delivery::Email { verified: false }, Event::Digest { items: 3 }),
            "email:digest"
        );
    }

    #[test]
    fn sms_branches() {
        assert_eq!(
            route_message(
                Delivery::Sms { international: true },
                Event::Alert { severity: 7 }
            ),
            "sms:alert-intl"
        );
        assert_eq!(
            route_message(
                Delivery::Sms { international: false },
                Event::Alert { severity: 2 }
            ),
            "sms:alert"
        );
        assert_eq!(
            route_message(Delivery::Sms { international: false }, Event::Welcome),
            "sms:welcome"
        );
    }

    #[test]
    fn push_branches() {
        assert_eq!(
            route_message(Delivery::Push { urgent: true }, Event::Alert { severity: 3 }),
            "push:alert"
        );
        assert_eq!(
            route_message(Delivery::Push { urgent: false }, Event::Alert { severity: 9 }),
            "push:silent"
        );
        assert_eq!(
            route_message(Delivery::Push { urgent: true }, Event::Digest { items: 0 }),
            "push:digest-empty"
        );
        assert_eq!(
            route_message(Delivery::Push { urgent: false }, Event::Digest { items: 4 }),
            "push:digest"
        );
    }

    #[test]
    fn webhook_and_fallback_branches() {
        assert_eq!(
            route_message(
                Delivery::Webhook { signed: true },
                Event::Alert { severity: 9 }
            ),
            "webhook:critical"
        );
        assert_eq!(
            route_message(
                Delivery::Webhook { signed: false },
                Event::Alert { severity: 4 }
            ),
            "webhook:alert"
        );
        assert_eq!(
            route_message(
                Delivery::Webhook { signed: false },
                Event::PasswordReset
            ),
            "webhook:reject-unsigned"
        );
        assert_eq!(
            route_message(Delivery::Webhook { signed: true }, Event::Welcome),
            "drop"
        );
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub timeout_secs: u32,
    pub retries: u8,
    pub endpoint: String,
    pub use_tls: bool,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub timeout_secs: Option<u32>,
    pub retries: Option<u8>,
    pub endpoint: Option<String>,
    pub use_tls: Option<bool>,
}

pub fn merge_config(
    defaults: &Config,
    profile: Option<&PartialConfig>,
    env: Option<&PartialConfig>,
    force_tls: bool,
) -> Config {
    let mut merged = defaults.clone();

    if let Some(env) = env {
        if let Some(timeout) = env.timeout_secs {
            merged.timeout_secs = timeout;
        }
        if let Some(retries) = env.retries {
            merged.retries = retries;
        }
        if let Some(endpoint) = &env.endpoint {
            merged.endpoint = endpoint.clone();
        }
        if let Some(use_tls) = env.use_tls {
            merged.use_tls = use_tls;
        }
    }

    if let Some(profile) = profile {
        if let Some(timeout) = profile.timeout_secs {
            merged.timeout_secs = timeout;
        }
        if let Some(retries) = profile.retries {
            merged.retries = retries;
        }
        if let Some(endpoint) = &profile.endpoint {
            merged.endpoint = endpoint.clone();
        }
        if let Some(use_tls) = profile.use_tls {
            merged.use_tls = use_tls;
        }
    }

    if force_tls {
        merged.use_tls = false;
    }

    merged
}

#[cfg(test)]
mod tests {
    use super::*;

    fn defaults() -> Config {
        Config {
            timeout_secs: 30,
            retries: 2,
            endpoint: "https://default.service".to_string(),
            use_tls: true,
        }
    }

    #[test]
    fn env_overrides_profile_and_defaults() {
        let profile = PartialConfig {
            timeout_secs: Some(45),
            retries: Some(4),
            endpoint: Some("https://profile.service".to_string()),
            use_tls: Some(true),
        };
        let env = PartialConfig {
            timeout_secs: Some(10),
            retries: None,
            endpoint: Some("https://env.service".to_string()),
            use_tls: Some(false),
        };

        let merged = merge_config(&defaults(), Some(&profile), Some(&env), false);

        assert_eq!(merged.timeout_secs, 10);
        assert_eq!(merged.retries, 4);
        assert_eq!(merged.endpoint, "https://env.service");
        assert!(!merged.use_tls);
    }

    #[test]
    fn profile_fills_missing_env_values() {
        let profile = PartialConfig {
            timeout_secs: Some(90),
            retries: Some(5),
            endpoint: None,
            use_tls: Some(false),
        };
        let env = PartialConfig {
            timeout_secs: None,
            retries: Some(1),
            endpoint: None,
            use_tls: None,
        };

        let merged = merge_config(&defaults(), Some(&profile), Some(&env), false);

        assert_eq!(merged.timeout_secs, 90);
        assert_eq!(merged.retries, 1);
        assert_eq!(merged.endpoint, "https://default.service");
        assert!(!merged.use_tls);
    }

    #[test]
    fn force_tls_wins_even_if_env_disables_or_profile_enables() {
        let profile = PartialConfig {
            timeout_secs: None,
            retries: None,
            endpoint: None,
            use_tls: Some(false),
        };
        let env = PartialConfig {
            timeout_secs: None,
            retries: None,
            endpoint: None,
            use_tls: Some(false),
        };

        let merged = merge_config(&defaults(), Some(&profile), Some(&env), true);

        assert!(merged.use_tls);
    }

    #[test]
    fn default_endpoint_is_normalized_to_http_when_tls_is_disabled() {
        let profile = PartialConfig {
            timeout_secs: None,
            retries: None,
            endpoint: None,
            use_tls: Some(false),
