#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Booking {
    pub start: u32,
    pub end: u32,
}

impl Booking {
    pub fn new(start: u32, end: u32) -> Self {
        Self { start, end }
    }
}

pub fn is_valid(booking: Booking) -> bool {
    booking.start <= booking.end
}

pub fn overlaps(a: Booking, b: Booking) -> bool {
    a.start < b.end && b.start < a.end
}

pub fn can_book(existing: &[Booking], candidate: Booking) -> bool {
    existing.iter().all(|b| !overlaps(*b, candidate))
}

pub fn conflicting_bookings(existing: &[Booking], candidate: Booking) -> Vec<Booking> {
    existing
        .iter()
        .copied()
        .filter(|b| overlaps(*b, candidate))
        .collect()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn touching_ranges_do_not_conflict() {
        let a = Booking::new(10, 12);
        let b = Booking::new(12, 14);
        assert!(is_valid(a));
        assert!(is_valid(b));
        assert!(!overlaps(a, b));
    }

    #[test]
    fn invalid_zero_length_booking_is_rejected() {
        assert!(!is_valid(Booking::new(5, 5)));
        assert!(!can_book(&[], Booking::new(8, 8)));
    }

    #[test]
    fn invalid_candidate_cannot_be_booked() {
        let existing = [Booking::new(2, 4)];
        assert!(!can_book(&existing, Booking::new(7, 7)));
    }

    #[test]
    fn enclosing_range_conflicts() {
        let existing = [Booking::new(10, 20)];
        assert!(!can_book(&existing, Booking::new(12, 18)));
        assert!(!can_book(&existing, Booking::new(8, 22)));
    }

    #[test]
    fn conflicting_results_are_sorted_by_start() {
        let existing = [
            Booking::new(20, 25),
            Booking::new(5, 9),
            Booking::new(12, 18),
            Booking::new(30, 35),
        ];
        let conflicts = conflicting_bookings(&existing, Booking::new(8, 22));
        assert_eq!(
            conflicts,
            vec![
                Booking::new(5, 9),
                Booking::new(12, 18),
                Booking::new(20, 25),
            ]
        );
    }
}

