#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: &'static str,
    pub points: u32,
    pub wins: u32,
    pub losses: u32,
}

pub fn leaderboard(players: &[Player]) -> Vec<String> {
    let mut rows = players.to_vec();
    rows.sort_by(|a, b| {
        a.points
            .cmp(&b.points)
            .then(a.wins.cmp(&b.wins))
            .then(a.losses.cmp(&b.losses))
            .then(a.name.cmp(&b.name))
    });

    rows.into_iter()
        .enumerate()
        .map(|(i, p)| format!("{}. {} ({} pts, {}-{})", i + 1, p.name, p.points, p.wins, p.losses))
        .collect()
}

#[cfg(test)]
mod tests {
    use super::*;

    fn p(name: &'static str, points: u32, wins: u32, losses: u32) -> Player {
        Player { name, points, wins, losses }
    }

    #[test]
    fn orders_by_points_descending_first() {
        let players = vec![
            p("Beta", 10, 7, 2),
            p("Alpha", 15, 3, 1),
            p("Gamma", 12, 5, 4),
        ];

        assert_eq!(
            leaderboard(&players),
            vec![
                "1. Alpha (15 pts, 3-1)",
                "2. Gamma (12 pts, 5-4)",
                "3. Beta (10 pts, 7-2)",
            ]
        );
    }

    #[test]
    fn breaks_points_ties_by_more_wins() {
        let players = vec![
            p("Atlas", 20, 8, 3),
            p("Blaze", 20, 11, 6),
            p("Comet", 19, 20, 0),
        ];

        assert_eq!(
            leaderboard(&players),
            vec![
                "1. Blaze (20 pts, 11-6)",
                "2. Atlas (20 pts, 8-3)",
                "3. Comet (19 pts, 20-0)",
            ]
        );
    }

    #[test]
    fn breaks_remaining_ties_by_fewer_losses() {
        let players = vec![
            p("Delta", 14, 6, 4),
            p("Echo", 14, 6, 2),
            p("Foxtrot", 14, 5, 0),
        ];

        assert_eq!(
            leaderboard(&players),
            vec![
                "1. Echo (14 pts, 6-2)",
                "2. Delta (14 pts, 6-4)",
                "3. Foxtrot (14 pts, 5-0)",
            ]
        );
    }

    #[test]
    fn final_tiebreak_is_name_ascending() {
        let players = vec![
            p("Zed", 9, 4, 4),
            p("Amy", 9, 4, 4),
            p("Moe", 9, 4, 4),
        ];

        assert_eq!(
            leaderboard(&players),
            vec![
                "1. Amy (9 pts, 4-4)",
                "2. Moe (9 pts, 4-4)",
                "3. Zed (9 pts, 4-4)",
            ]
        );
    }

    #[test]
