use std::collections::BTreeMap;

#[derive(Clone, Debug)]
pub struct Entry {
    pub team: &'static str,
    pub month: u8,
    pub hours: u32,
    pub billable: bool,
}

pub fn monthly_report(entries: &[Entry]) -> String {
    let mut totals: BTreeMap<&str, (u32, u32, usize)> = BTreeMap::new();

    for e in entries {
        let slot = totals.entry(e.team).or_insert((0, 0, 0));
        slot.0 += e.hours;
        if e.billable {
            slot.1 += e.hours;
        }
        slot.2 += 1;
    }

    let mut lines = Vec::new();
    for (team, (total, billable, count)) in totals {
        let avg = total / count as u32;
        lines.push(format!("{}: total={} billable={} avg={}", team, total, billable, avg));
    }
    lines.join("\n")
}

