#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Resolve,
    Reopen,
    Close,
}

pub fn apply_event(status: Status, event: Event) -> Status {
    match event {
        Event::Start => Status::InProgress,
        Event::Resolve => Status::Resolved,
        Event::Reopen => Status::Open,
        Event::Close => Status::Resolved,
    }
}

pub fn apply_events(initial: Status, events: &[Event]) -> Status {
    let mut status = initial;
    for &event in events {
        status = apply_event(status, event);
    }
    status
}

#[cfg(test)]
mod tests {
    use super::{apply_event, apply_events, Event, Status};

    #[test]
    fn valid_transitions_change_state() {
        assert_eq!(apply_event(Status::Open, Event::Start), Status::InProgress);
        assert_eq!(apply_event(Status::InProgress, Event::Resolve), Status::Resolved);
        assert_eq!(apply_event(Status::Resolved, Event::Close), Status::Closed);
        assert_eq!(apply_event(Status::Closed, Event::Reopen), Status::Open);
    }

    #[test]
    fn invalid_transitions_leave_state_unchanged() {
        assert_eq!(apply_event(Status::Open, Event::Resolve), Status::Open);
        assert_eq!(apply_event(Status::Open, Event::Close), Status::Open);
        assert_eq!(apply_event(Status::Resolved, Event::Start), Status::Resolved);
        assert_eq!(apply_event(Status::Closed, Event::Close), Status::Closed);
    }

    #[test]
    fn event_sequences_respect_intermediate_state() {
        let events = [Event::Start, Event::Resolve, Event::Close];
        assert_eq!(apply_events(Status::Open, &events), Status::Closed);

        let skipped = [Event::Resolve, Event::Close];
        assert_eq!(apply_events(Status::Open, &skipped), Status::Open);

        let reopen = [Event::Start, Event::Resolve, Event::Close, Event::Reopen];
        assert_eq!(apply_events(Status::Open, &reopen), Status::Open);
    }
}

