#[derive(Debug, PartialEq, Eq)]
pub struct Record {
    pub name: String,
    pub count: u32,
    pub enabled: bool,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();
    for (idx, raw_line) in input.lines().enumerate() {
        let line = raw_line.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }

        let parts: Vec<&str> = line.split('|').collect();
        if parts.len() != 3 {
            return Err(format!("line {}: expected 3 fields", idx + 1));
        }

        let name = parts[0].to_string();
        if name.is_empty() {
            return Err(format!("line {}: empty name", idx + 1));
        }

        let count: u32 = parts[1]
            .parse()
            .map_err(|_| format!("line {}: invalid count", idx + 1))?;

        let enabled = match parts[2] {
            "true" => true,
            "false" => false,
            _ => return Err(format!("line {}: invalid enabled flag", idx + 1)),
        };

        out.push(Record { name, count, enabled });
    }
    Ok(out)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn parses_valid_input_with_comments_and_blank_lines() {
        let input = "\n# comment\n alice | 3 | true \n\n bob|0|false\n";
        let records = parse_records(input).unwrap();
        assert_eq!(
            records,
            vec![
                Record {
                    name: "alice".into(),
                    count: 3,
                    enabled: true,
                },
                Record {
                    name: "bob".into(),
                    count: 0,
                    enabled: false,
                },
            ]
        );
    }

    #[test]
    fn rejects_uppercase_name() {
        let err = parse_records("Alice|2|true").unwrap_err();
        assert_eq!(err, "line 1: invalid name");
    }

    #[test]
    fn rejects_name_with_internal_space() {
        let err = parse_records("two words|2|true").unwrap_err();
        assert_eq!(err, "line 1: invalid name");
    }

    #[test]
    fn rejects_leading_zero_count() {
        let err = parse_records("alice|03|true").unwrap_err();
        assert_eq!(err, "line 1: invalid count");
    }

    #[test]
    fn rejects_non_canonical_bool() {
        let err = parse_records("alice|2|TRUE").unwrap_err();
        assert_eq!(err, "line 1: invalid enabled flag");
    }
}

