use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale {
    pub rep: &'static str,
    pub month: u8,
    pub amount: i32,
    pub refunded: bool,
}

pub fn build_report(sales: &[Sale]) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();
    let mut counts: BTreeMap<&str, usize> = BTreeMap::new();

    for sale in sales {
        if sale.amount <= 0 {
            continue;
        }
        *totals.entry(sale.rep).or_insert(0) += sale.amount;
        *counts.entry(sale.rep).or_insert(0) += 1;
    }

    let mut rows: Vec<_> = totals.into_iter().collect();
    rows.sort_by(|a, b| a.0.cmp(b.0));

    let mut out = String::new();
    for (rep, total) in rows {
        let count = counts.get(rep).copied().unwrap_or(0);
        out.push_str(&format!("{}: total={} sales={} avg={}\n", rep, total, count, total / count as i32));
    }
    out
}

