pub fn parse_records(input: &str) -> Result<Vec<(String, u8, bool)>, String> {
    let mut out = Vec::new();
    for (idx, line) in input.lines().enumerate() {
        if line.is_empty() {
            continue;
        }
        let parts: Vec<_> = line.split('|').collect();
        if parts.len() != 3 {
            return Err(format!("line {}: expected 3 fields", idx + 1));
        }
        let name = parts[0].to_string();
        let level: u8 = parts[1].parse().map_err(|_| format!("line {}: bad level", idx + 1))?;
        let enabled = match parts[2] {
            "true" => true,
            "false" => false,
            _ => return Err(format!("line {}: bad enabled", idx + 1)),
        };
        out.push((name, level, enabled));
    }
    Ok(out)
}

