#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub name: String,
    pub score: i32,
    pub wins: u32,
}

pub fn leaderboard(entries: &[Entry]) -> Vec<String> {
    let mut latest: HashMap<&str, &Entry> = HashMap::new();
    for entry in entries {
        latest.insert(entry.name.as_str(), entry);
    }

    let mut rows: Vec<&Entry> = latest.into_values().collect();
    rows.sort_by(|a, b| {
        a.score
            .cmp(&b.score)
            .then(a.wins.cmp(&b.wins))
            .then(a.name.cmp(&b.name))
    });

    rows.into_iter()
        .enumerate()
        .map(|(idx, e)| format!("{}. {} ({}, {})", idx + 1, e.name, e.score, e.wins))
        .collect()
}

