#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum TicketState {
    New,
    InProgress,
    Blocked,
    Done,
}

#[derive(Debug, Clone, Copy)]
pub enum Event {
    Start,
    Block,
    Unblock,
    Complete,
    Reopen,
}

pub fn apply_event(state: TicketState, event: Event) -> TicketState {
    match (state, event) {
        (TicketState::New, Event::Start) => TicketState::InProgress,
        (TicketState::InProgress, Event::Block) => TicketState::Blocked,
        (TicketState::Blocked, Event::Unblock) => TicketState::New,
        (_, Event::Complete) => TicketState::Done,
        (TicketState::Done, Event::Reopen) => TicketState::Blocked,
        _ => state,
    }
}

pub fn run_events(mut state: TicketState, events: &[Event]) -> TicketState {
    for &event in events {
        state = apply_event(state, event);
    }
    state
}

#[cfg(test)]
