    fn blocked_ticket_returns_to_in_progress() {
        let events = [Event::Start, Event::Block, Event::Unblock];
        assert_eq!(run_events(TicketState::New, &events), TicketState::InProgress);
    }

    #[test]
    fn reopen_done_ticket_goes_back_to_in_progress() {
        let events = [Event::Reopen];
        assert_eq!(run_events(TicketState::Done, &events), TicketState::InProgress);
    }

    #[test]
    fn cannot_complete_directly_from_new() {
        let events = [Event::Complete];
        assert_eq!(run_events(TicketState::New, &events), TicketState::New);
    }
}

pub fn select_positive_scores(items: &[(&str, Option<i32>)], min_len: usize) -> Vec<String> {
    items
        .iter()
        .filter_map(|(name, score)| {
            let value = score.unwrap_or(0);
            if value >= 0 && name.len() >= min_len {
                Some(format!("{}:{}", name.to_ascii_uppercase(), value))
            } else {
                None
            }
        })
        .collect()
}

