#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub use_tls: Option<bool>,
    pub retries: Option<u8>,
}

pub fn merge_config(base: &Config, env: &PartialConfig, override_cfg: &PartialConfig) -> Config {
    Config {
        host: base.host.clone(),
        port: override_cfg.port.or(env.port).unwrap_or(base.port),
        use_tls: env.use_tls.or(override_cfg.use_tls).unwrap_or(base.use_tls),
        retries: override_cfg.retries.unwrap_or(base.retries),
    }
}

