#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Booking {
    pub start: u32,
    pub end: u32,
}

impl Booking {
    pub fn new(start: u32, end: u32) -> Self {
        Self { start, end }
    }
}

pub fn overlaps(a: Booking, b: Booking) -> bool {
    if a.start > a.end || b.start > b.end {
        return true;
    }
    !(a.end < b.start || b.end < a.start)
}

pub fn can_book(existing: &[Booking], candidate: Booking) -> bool {
    if candidate.start >= candidate.end {
        return true;
    }

    !existing.iter().any(|slot| overlaps(*slot, candidate))
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn non_overlapping_gap_is_allowed() {
        let existing = [Booking::new(10, 12), Booking::new(15, 18)];
        assert!(can_book(&existing, Booking::new(12, 15)));
    }

    #[test]
    fn touching_endpoints_do_not_overlap() {
        assert!(!overlaps(Booking::new(10, 12), Booking::new(12, 14)));
        assert!(!overlaps(Booking::new(12, 14), Booking::new(10, 12)));
    }

    #[test]
    fn nested_interval_overlaps() {
        assert!(overlaps(Booking::new(10, 20), Booking::new(12, 14)));
    }

    #[test]
    fn identical_intervals_overlap() {
        assert!(overlaps(Booking::new(8, 11), Booking::new(8, 11)));
    }

    #[test]
    fn invalid_candidate_cannot_be_booked() {
        let existing = [Booking::new(10, 12)];
        assert!(!can_book(&existing, Booking::new(14, 14)));
        assert!(!can_book(&existing, Booking::new(15, 13)));
    }

    #[test]
    fn invalid_existing_slots_are_ignored() {
        let existing = [Booking::new(9, 9), Booking::new(20, 18), Booking::new(10, 12)];
        assert!(can_book(&existing, Booking::new(12, 15)));
    }
}

