pub fn parse_record(line: &str) -> Result<(String, u16, bool), String> {
    let parts: Vec<&str> = line.split('|').collect();
    if parts.len() != 3 {
        return Err("expected 3 fields".into());
    }

    let name = parts[0].to_string();
    if name.is_empty() {
        return Err("empty name".into());
    }

    let count: u16 = parts[1].parse().map_err(|_| "bad count".to_string())?;

    let active = match parts[2] {
        "true" => true,
        "false" => false,
        _ => return Err("bad active".into()),
    };

    Ok((name, count, active))
}

