pub struct Competitor {
    pub name: String,
    pub score: u32,
    pub wins: u32,
    pub penalty: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedCompetitor {
    pub place: usize,
    pub name: String,
    pub score: u32,
    pub wins: u32,
    pub penalty: u32,
}

pub fn rank_competitors(entries: &[Competitor]) -> Vec<RankedCompetitor> {
    let mut items = entries.to_vec();
    items.sort_by(|a, b| {
        a.score
            .cmp(&b.score)
            .then(a.wins.cmp(&b.wins))
            .then(a.penalty.cmp(&b.penalty))
            .then(a.name.cmp(&b.name))
    });

    items
        .into_iter()
        .enumerate()
        .map(|(idx, c)| RankedCompetitor {
            place: idx + 1,
            name: c.name,
            score: c.score,
            wins: c.wins,
            penalty: c.penalty,
        })
        .collect()
}

