pub fn summarize(entries: &[Entry]) -> String {
    let mut groups: BTreeMap<&str, (u32, u32)> = BTreeMap::new();

    for entry in entries {
        let key = entry.member;
        let row = groups.entry(key).or_insert((0, 0));
        row.0 += entry.hours;
        if entry.billable {
            row.1 += entry.hours;
        }
