use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale {
    pub rep: &'static str,
    pub region: &'static str,
    pub amount: i32,
    pub refunded: bool,
}

pub fn summarize_sales(sales: &[Sale]) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();
    let mut refunds = 0;

    for sale in sales {
        *totals.entry(sale.region).or_insert(0) += sale.amount;
        if sale.refunded {
            refunds += 1;
        }
    }

    let overall: i32 = totals.values().copied().sum();
    let top_region = totals
        .iter()
        .max_by_key(|(_, total)| *total)
        .map(|(region, _)| *region)
        .unwrap_or("none");

    let region_lines = totals
        .iter()
        .map(|(region, total)| format!("{}={}", region, total))
        .collect::<Vec<_>>()
        .join(",");

    format!(
        "regions:[{}]; overall={}; refunds={}; top={}",
        region_lines, overall, refunds, top_region
    )
}

