        let sales = vec![
            Sale { rep: "Ana", region: "West", amount: 50, refunded: false },
            Sale { rep: "Ben", region: "East", amount: 90, refunded: false },
            Sale { rep: "Cal", region: "West", amount: 40, refunded: true },
            Sale { rep: "Dee", region: "North", amount: 0, refunded: false },
            Sale { rep: "Eli", region: "South", amount: -5, refunded: false },
            Sale { rep: "Fay", region: "West", amount: 20, refunded: false },
        ];

        assert_eq!(
            summarize_sales(&sales),
            "regions:[East=90,West=70]; overall=160; refunds=1; top=East"
        );
    }

    #[test]
    fn top_region_uses_lexicographic_tiebreak_and_empty_input_is_stable() {
        let tied = vec![
            Sale { rep: "Ana", region: "West", amount: 30, refunded: false },
            Sale { rep: "Ben", region: "East", amount: 30, refunded: false },
            Sale { rep: "Cal", region: "South", amount: 10, refunded: true },
        ];

        assert_eq!(
            summarize_sales(&tied),
            "regions:[East=30,West=30]; overall=60; refunds=1; top=East"
        );

        let empty: Vec<Sale> = vec![];
        assert_eq!(
            summarize_sales(&empty),
            "regions:[]; overall=0; refunds=0; top=none"
        );
