pub struct Config {
    pub endpoint: Option<String>,
    pub timeout_secs: Option<u32>,
    pub retries: Option<u8>,
    pub use_tls: Option<bool>,
}

impl Config {
    pub fn new() -> Self {
        Self {
            endpoint: None,
            timeout_secs: None,
            retries: None,
            use_tls: None,
        }
    }
}

pub fn merge_config(defaults: &Config, profile: &Config, overrides: &Config) -> Config {
    let mut merged = Config::new();

    merged.endpoint = profile.endpoint.clone().or_else(|| defaults.endpoint.clone());
    merged.timeout_secs = profile.timeout_secs.or(defaults.timeout_secs);
    merged.retries = profile.retries.or(defaults.retries);
    merged.use_tls = if overrides.use_tls == Some(false) {
        defaults.use_tls
    } else {
        overrides.use_tls.or(profile.use_tls).or(defaults.use_tls)
    };

    if overrides.timeout_secs.unwrap_or(0) > 0 {
        merged.timeout_secs = overrides.timeout_secs;
    }

    if overrides.retries.unwrap_or(0) > 0 {
        merged.retries = overrides.retries;
    }

    if let Some(ref endpoint) = profile.endpoint {
        if !endpoint.is_empty() {
            merged.endpoint = Some(endpoint.clone());
        }
    }

    merged
}

