#[derive(Debug, PartialEq, Eq)]
pub struct Record {
    pub name: String,
    pub age: u8,
    pub active: bool,
    pub tags: Vec<String>,
}

pub fn parse_record(line: &str) -> Result<Record, String> {
    let mut name = String::new();
    let mut age = 0u8;
    let mut active = false;
    let mut tags = Vec::new();

    for part in line.split(';') {
        if part.is_empty() {
            continue;
        }
        let (key, value) = part
            .split_once('=')
            .ok_or_else(|| format!("invalid field: {part}"))?;
        match key {
            "name" => name = value.to_string(),
            "age" => age = value.parse::<u8>().map_err(|_| "invalid age".to_string())?,
            "active" => active = value == "true",
            "tags" => {
                tags = value
                    .split(',')
                    .filter(|s| !s.is_empty())
                    .map(|s| s.to_string())
                    .collect();
            }
            _ => {}
        }
    }

    Ok(Record {
        name,
        age,
        active,
        tags,
    })
}

