use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub category: &'static str,
    pub amount: i32,
    pub flagged: bool,
}

pub fn summarize(entries: &[Entry]) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();
    let mut flagged_counts: BTreeMap<&str, usize> = BTreeMap::new();
    let mut skipped = 0usize;

    for entry in entries {
        if entry.amount == 0 {
            continue;
        }

        if entry.amount < 0 {
            skipped += 1;
            continue;
        }

        *totals.entry(entry.category).or_insert(0) += entry.amount;
        if entry.flagged {
            *flagged_counts.entry(entry.category).or_insert(0) += 1;
        }
    }

    let mut lines = Vec::new();
    for (category, total) in totals {
        let flagged = flagged_counts.get(category).copied().unwrap_or(0);
        lines.push(format!("{}: total={} flagged={}", category, total, flagged));
    }

    lines.push(format!("grand_total={}", lines.len()));
    lines.push(format!("skipped={}", skipped));
    lines.join("\n")
}

