#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Event {
    Connected { secure: bool },
    Message { urgent: bool, bytes: usize },
    Retry { count: u8 },
    Shutdown { graceful: bool },
}

pub fn action_for(event: Event) -> &'static str {
    match event {
        Event::Connected { secure: true } => "open",
        Event::Connected { secure: false } => "open",
        Event::Message { urgent: true, bytes } if bytes > 0 => "queue",
        Event::Message { urgent: false, .. } => "ignore",
        Event::Message { urgent: true, bytes: 0 } => "deliver",
        Event::Retry { count } if count >= 3 => "retry",
        Event::Retry { .. } => "retry",
        Event::Shutdown { graceful: true } => "abort",
        Event::Shutdown { graceful: false } => "close",
    }
}

#[cfg(test)]
