    use super::{action_for, Event};

    #[test]
    fn connected_distinguishes_secure_handshake() {
        assert_eq!(action_for(Event::Connected { secure: true }), "handshake");
        assert_eq!(action_for(Event::Connected { secure: false }), "open");
    }

    #[test]
    fn message_branches_cover_urgent_and_empty_cases() {
        assert_eq!(
            action_for(Event::Message {
                urgent: true,
                bytes: 12,
            }),
            "deliver"
        );
        assert_eq!(
            action_for(Event::Message {
                urgent: true,
                bytes: 0,
            }),
            "drop"
        );
        assert_eq!(
            action_for(Event::Message {
                urgent: false,
                bytes: 8,
            }),
            "queue"
        );
    }

    #[test]
    fn retry_count_changes_decision() {
        assert_eq!(action_for(Event::Retry { count: 0 }), "retry");
        assert_eq!(action_for(Event::Retry { count: 3 }), "backoff");
    }

    #[test]
    fn shutdown_respects_graceful_flag() {
        assert_eq!(action_for(Event::Shutdown { graceful: true }), "close");
        assert_eq!(action_for(Event::Shutdown { graceful: false }), "abort");
    }
}

