use std::cmp::Ordering;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: &'static str,
    pub score: u32,
    pub wins: u32,
    pub losses: u32,
}

pub fn leaderboard(players: &[Player]) -> Vec<String> {
    let mut rows = players.to_vec();
    rows.sort_by(|a, b| compare_players(a, b));
    rows.into_iter()
        .map(|p| format!("{}:{}-{} ({})", p.name, p.wins, p.losses, p.score))
        .collect()
}

fn compare_players(a: &Player, b: &Player) -> Ordering {
    a.score.cmp(&b.score)
        .then_with(|| a.wins.cmp(&b.wins))
        .then_with(|| b.losses.cmp(&a.losses))
        .then_with(|| b.name.cmp(a.name))
}

