pub struct Record {
    pub name: String,
    pub score: u32,
    pub active: bool,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();
    for (idx, raw_line) in input.lines().enumerate() {
        let line = raw_line.trim();
        if line.is_empty() {
            continue;
        }

        let parts: Vec<&str> = line.split('|').collect();
        if parts.len() != 3 {
            return Err(format!("line {}: expected 3 fields", idx + 1));
        }

        let name = parts[0].to_string();

        let score = parts[1]
            .parse::<u32>()
            .map_err(|_| format!("line {}: invalid score", idx + 1))?;

        let active = match parts[2] {
            "active" => true,
            "inactive" => false,
            _ => return Err(format!("line {}: invalid status", idx + 1)),
        };

        out.push(Record { name, score, active });
    }
    Ok(out)
}

