#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Settings {
    pub host: String,
    pub port: u16,
    pub tls: bool,
    pub retries: u8,
}

#[derive(Debug, Clone, Default)]
pub struct PartialSettings {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub tls: Option<bool>,
    pub retries: Option<u8>,
}

pub fn merge_settings(
    defaults: &Settings,
    env: Option<&PartialSettings>,
    user: Option<&PartialSettings>,
) -> Settings {
    let mut merged = defaults.clone();

    if let Some(layer) = user {
        if let Some(host) = &layer.host {
            merged.host = host.clone();
        }
        if let Some(port) = layer.port {
            merged.port = port;
        }
        if let Some(tls) = layer.tls {
            merged.tls = tls;
        }
        if let Some(retries) = layer.retries {
            merged.retries = retries;
        }
    }

    if let Some(layer) = env {
        if let Some(host) = &layer.host {
            merged.host = host.clone();
        }
        if let Some(port) = layer.port {
            merged.port = port;
        }
        if let Some(tls) = layer.tls {
            merged.tls = tls;
        }
        if let Some(retries) = layer.retries {
            merged.retries = retries;
        }
    }

    if merged.port == 0 {
        merged.port = defaults.port;
    }

    if merged.retries == 0 {
        merged.retries = defaults.retries;
    }

    merged
}

