use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Record {
    pub dept: &'static str,
    pub hours: u32,
    pub billable: bool,
}

pub fn summarize(records: &[Record]) -> String {
    let mut totals: BTreeMap<&str, (u32, u32)> = BTreeMap::new();

    for r in records {
        let entry = totals.entry(r.dept).or_insert((0, 0));
        entry.0 += r.hours;
        if r.billable {
            entry.1 += r.hours;
        }
    }

    let mut out = String::new();
    for (dept, (total, billable)) in totals {
        out.push_str(&format!("{}: total={} billable={} utilization={}%; ", dept, total, billable, (billable * 100) / total));
    }
    out
}

