#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Channel {
    Email,
    Sms,
    Push,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Priority {
    Low,
    Normal,
    High,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum DeliveryState {
    Draft,
    Queued,
    Sent,
    Failed,
}

pub fn next_action(channel: Channel, priority: Priority, state: DeliveryState, retries: u8) -> &'static str {
    match state {
        DeliveryState::Draft => "store",
        DeliveryState::Queued => match channel {
            Channel::Email => {
                if priority == Priority::High {
                    "expedite"
                } else {
                    "send"
                }
            }
            Channel::Sms => {
                if retries > 0 {
                    "retry"
                } else {
                    "send"
                }
            }
            Channel::Push => "store",
        },
        DeliveryState::Sent => "archive",
        DeliveryState::Failed => match priority {
            Priority::High => "drop",
            _ => {
                if retries >= 3 {
                    "drop"
                } else {
                    "retry"
                }
            }
        },
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn queued_email_high_priority_is_expedited() {
        assert_eq!(
            next_action(Channel::Email, Priority::High, DeliveryState::Queued, 0),
            "expedite"
        );
    }

    #[test]
    fn queued_push_is_sent_normally() {
        assert_eq!(
            next_action(Channel::Push, Priority::Normal, DeliveryState::Queued, 0),
            "send"
        );
    }

    #[test]
    fn failed_high_priority_with_budget_retries() {
        assert_eq!(
            next_action(Channel::Sms, Priority::High, DeliveryState::Failed, 1),
            "retry"
        );
    }

    #[test]
    fn failed_low_priority_after_many_retries_drops() {
        assert_eq!(
            next_action(Channel::Email, Priority::Low, DeliveryState::Failed, 3),
            "drop"
        );
    }

    #[test]
    fn draft_goes_to_queue_for_high_priority() {
        assert_eq!(
            next_action(Channel::Email, Priority::High, DeliveryState::Draft, 0),
            "queue"
        );
    }

    #[test]
    fn sent_is_archived() {
        assert_eq!(
            next_action(Channel::Sms, Priority::Normal, DeliveryState::Sent, 0),
            "archive"
        );
    }
}

