#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Mode {
    Safe,
    Fast,
    Offline,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub mode: Mode,
    pub timeout_ms: u32,
    pub caching: bool,
    pub endpoint: String,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub mode: Option<Mode>,
    pub timeout_ms: Option<u32>,
    pub caching: Option<bool>,
    pub endpoint: Option<String>,
}

pub fn merge_config(
    defaults: &Config,
    file: Option<&PartialConfig>,
    env: Option<&PartialConfig>,
    cli: Option<&PartialConfig>,
) -> Config {
    let mut merged = defaults.clone();

    for layer in [env, file, cli] {
        if let Some(layer) = layer {
            if let Some(mode) = &layer.mode {
                merged.mode = mode.clone();
            }
            if let Some(timeout_ms) = layer.timeout_ms {
                merged.timeout_ms = timeout_ms;
            }
            if let Some(caching) = layer.caching {
                merged.caching = caching;
            }
            if let Some(endpoint) = &layer.endpoint {
                merged.endpoint = endpoint.clone();
            }
        }
    }

    if merged.endpoint.is_empty() {
        merged.endpoint = defaults.endpoint.clone();
    }

    merged
}

#[cfg(test)]
