    use super::*;

    fn defaults() -> Config {
        Config {
            mode: Mode::Safe,
            timeout_ms: 1000,
            caching: false,
            endpoint: "https://default.service".to_string(),
        }
    }

    #[test]
    fn precedence_is_defaults_then_file_then_env_then_cli() {
        let file = PartialConfig {
            mode: Some(Mode::Fast),
            timeout_ms: Some(500),
