            endpoint: Some("https://file.service".to_string()),
        };
        let env = PartialConfig {
            mode: None,
            timeout_ms: Some(250),
            caching: Some(false),
            endpoint: Some("https://env.service".to_string()),
        };
        let cli = PartialConfig {
            mode: Some(Mode::Safe),
            timeout_ms: None,
            caching: None,
            endpoint: Some("https://cli.service".to_string()),
        };

        let merged = merge_config(&defaults(), Some(&file), Some(&env), Some(&cli));

        assert_eq!(merged.mode, Mode::Safe);
        assert_eq!(merged.timeout_ms, 250);
        assert!(!merged.caching);
        assert_eq!(merged.endpoint, "https://cli.service");
    }

    #[test]
    fn offline_mode_forces_cache_off_and_uses_zero_timeout() {
