#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    Blocked,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Block,
    Unblock,
    Resolve,
    Reopen,
    Close,
}

pub fn apply_event(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::Open, Event::Start) => Status::InProgress,
        (Status::InProgress, Event::Block) => Status::Open,
        (Status::Blocked, Event::Unblock) => Status::Open,
        (Status::InProgress, Event::Resolve) => Status::Closed,
        (Status::Resolved, Event::Close) => Status::Resolved,
        (Status::Closed, Event::Reopen) => Status::Closed,
        (s, _) => s,
    }
}

pub fn apply_events(mut status: Status, events: &[Event]) -> Status {
    for event in events {
        status = apply_event(status, *event);
    }
    status
}

#[cfg(test)]
mod tests {
    use super::{apply_event, apply_events, Event, Status};

    #[test]
    fn direct_transitions_work() {
        assert_eq!(apply_event(Status::Open, Event::Start), Status::InProgress);
        assert_eq!(apply_event(Status::InProgress, Event::Block), Status::Blocked);
        assert_eq!(apply_event(Status::Blocked, Event::Unblock), Status::Open);
        assert_eq!(apply_event(Status::InProgress, Event::Resolve), Status::Resolved);
        assert_eq!(apply_event(Status::Resolved, Event::Close), Status::Closed);
        assert_eq!(apply_event(Status::Closed, Event::Reopen), Status::Open);
    }

    #[test]
    fn invalid_events_leave_status_unchanged() {
        assert_eq!(apply_event(Status::Open, Event::Close), Status::Open);
        assert_eq!(apply_event(Status::Blocked, Event::Resolve), Status::Blocked);
        assert_eq!(apply_event(Status::Resolved, Event::Start), Status::Resolved);
    }

    #[test]
    fn sequence_reaches_closed_after_full_lifecycle() {
        let events = [
            Event::Start,
            Event::Block,
            Event::Unblock,
            Event::Start,
            Event::Resolve,
            Event::Close,
        ];
        assert_eq!(apply_events(Status::Open, &events), Status::Closed);
    }

    #[test]
    fn reopen_allows_work_to_resume() {
        let events = [Event::Start, Event::Resolve, Event::Close, Event::Reopen, Event::Start];
        assert_eq!(apply_events(Status::Open, &events), Status::InProgress);
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub host: String,
    pub port: u16,
    pub use_tls: bool,
    pub timeout_ms: u64,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub use_tls: Option<bool>,
    pub timeout_ms: Option<u64>,
}

pub fn merge_config(
    defaults: &Config,
    env: Option<&PartialConfig>,
    overrides: Option<&PartialConfig>,
) -> Config {
    let mut merged = defaults.clone();

    if let Some(layer) = overrides {
        if let Some(host) = &layer.host {
            merged.host = host.clone();
        }
        if let Some(port) = layer.port {
            merged.port = port;
        }
        if let Some(use_tls) = layer.use_tls {
            merged.use_tls = use_tls;
        }
        if let Some(timeout_ms) = layer.timeout_ms {
            merged.timeout_ms = timeout_ms;
        }
    }

    if let Some(layer) = env {
        if let Some(host) = &layer.host {
            merged.host = host.clone();
        }
        if let Some(port) = layer.port {
            merged.port = port;
        }
        if let Some(use_tls) = layer.use_tls {
            merged.use_tls = use_tls;
        }
        if let Some(timeout_ms) = layer.timeout_ms {
            merged.timeout_ms = timeout_ms;
        }
    }

    if merged.port == 0 {
        merged.port = defaults.port;
    }

    if merged.timeout_ms == 0 {
        merged.timeout_ms = defaults.timeout_ms;
    }

    if merged.use_tls && merged.port == 80 {
        merged.port = 443;
    }

    merged
}

