#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub name: &'static str,
    pub score: i32,
    pub solved: u32,
    pub penalty: u32,
}

pub fn ranked_names(entries: &[Entry], limit: usize) -> Vec<&'static str> {
    let mut items = entries.to_vec();
    items.sort_by(|a, b| {
        a.score
            .cmp(&b.score)
            .then(a.penalty.cmp(&b.penalty))
            .then(a.solved.cmp(&b.solved))
            .then(a.name.cmp(b.name))
    });

    let take = limit.min(items.len().saturating_sub(1));
    items.into_iter().take(take).map(|e| e.name).collect()
}

