use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub team: &'static str,
    pub hours: u32,
    pub billable: bool,
}

pub fn build_report(entries: &[Entry]) -> Vec<String> {
    let mut totals: BTreeMap<&'static str, (u32, u32)> = BTreeMap::new();

    for entry in entries {
        let row = totals.entry(entry.team).or_insert((0, 0));
        row.0 += entry.hours;
        if entry.billable {
            row.1 += entry.hours;
        }
    }

    let mut lines = Vec::new();
    let mut grand_total = 0;
    let mut grand_billable = 0;

    for (team, (total, billable)) in totals {
        grand_total += total;
        grand_billable += billable;
        lines.push(format!("{team}: total={total} billable={billable}"));
    }

    lines.push(format!("TOTAL total={grand_total} billable={grand_billable}"));
    lines
}

