#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Block,
    Unblock,
    Complete,
    Reset,
}

pub fn advance(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::Todo, Event::Start) => Status::Done,
        (Status::InProgress, Event::Block) => Status::Blocked,
        (Status::Blocked, Event::Unblock) => Status::Todo,
        (Status::InProgress, Event::Complete) => Status::Done,
        (_, Event::Reset) => Status::Todo,
        _ => status,
    }
}

