pub struct Entry {
    pub key: String,
    pub value: i32,
    pub enabled: bool,
}

pub fn parse_entries(input: &str) -> Result<Vec<Entry>, String> {
    let mut out = Vec::new();
    for (idx, raw_line) in input.lines().enumerate() {
        let line = raw_line.trim();
        if line.is_empty() {
            continue;
        }

        let parts: Vec<&str> = line.split(',').collect();
        if parts.len() != 3 {
            return Err(format!("line {}: expected 3 fields", idx + 1));
        }

        let key = parts[0].to_string();
        if key.is_empty() {
            return Err(format!("line {}: empty key", idx + 1));
        }

        let value: i32 = parts[1]
            .parse()
            .map_err(|_| format!("line {}: invalid value", idx + 1))?;

        let enabled = match parts[2] {
            "true" => true,
            "false" => false,
            _ => return Err(format!("line {}: invalid enabled flag", idx + 1)),
        };

        out.push(Entry { key, value, enabled });
    }
    Ok(out)
}

