#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Resolve,
    Close,
    Reopen,
}

pub fn transition(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::Open, Event::Start) => Status::InProgress,
        (Status::InProgress, Event::Resolve) => Status::Resolved,
        (Status::Resolved, Event::Close) => Status::Closed,
        (Status::Closed, Event::Reopen) => Status::Open,
        (Status::Resolved, Event::Reopen) => Status::Resolved,
        (Status::InProgress, Event::Close) => Status::Closed,
        _ => status,
    }
}

pub fn apply_events(mut status: Status, events: &[Event]) -> Status {
    for &event in events {
        status = transition(status, event);
    }
    status
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn open_can_start_work() {
        assert_eq!(transition(Status::Open, Event::Start), Status::InProgress);
    }

    #[test]
    fn resolved_can_be_reopened_to_in_progress() {
        assert_eq!(transition(Status::Resolved, Event::Reopen), Status::InProgress);
    }

    #[test]
    fn closed_reopens_to_in_progress() {
        assert_eq!(transition(Status::Closed, Event::Reopen), Status::InProgress);
    }

    #[test]
    fn cannot_close_before_resolution() {
        assert_eq!(transition(Status::InProgress, Event::Close), Status::InProgress);
    }

    #[test]
    fn event_sequence_respects_all_rules() {
        let events = [
            Event::Start,
            Event::Resolve,
            Event::Reopen,
            Event::Resolve,
            Event::Close,
        ];
        assert_eq!(apply_events(Status::Open, &events), Status::Closed);
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Role {
    Guest,
    User,
    Admin,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Action {
    View,
    Edit,
    Delete,
    Publish,
    Archive,
}

pub fn decide(role: Role, action: Action, flagged: bool, owns_item: bool) -> &'static str {
    match action {
        Action::View => "allow",
        Action::Edit => match role {
            Role::Guest => "allow",
            Role::User => "allow",
            Role::Admin => "allow",
        },
        Action::Delete => match role {
            Role::Admin => "review",
            Role::User if owns_item => "allow",
            Role::User => "review",
            Role::Guest => "deny",
        },
        Action::Publish => match role {
            Role::Admin => "review",
            Role::User if flagged => "allow",
            Role::User => "review",
            Role::Guest => "deny",
        },
        Action::Archive => match role {
            Role::Admin => "allow",
            Role::User if owns_item && flagged => "allow",
            Role::User => "review",
            Role::Guest => "deny",
        },
    }
}

