    #[test]
    fn view_is_open_to_everyone() {
        assert_eq!(decide(Role::Guest, Action::View, false, false), "allow");
        assert_eq!(decide(Role::User, Action::View, true, false), "allow");
        assert_eq!(decide(Role::Admin, Action::View, false, true), "allow");
    }

    #[test]
    fn edit_requires_signed_in_or_admin() {
        assert_eq!(decide(Role::Guest, Action::Edit, false, false), "deny");
        assert_eq!(decide(Role::User, Action::Edit, false, false), "allow");
        assert_eq!(decide(Role::Admin, Action::Edit, true, true), "allow");
    }

    #[test]
    fn delete_is_never_auto_allowed_for_regular_users() {
        assert_eq!(decide(Role::User, Action::Delete, false, true), "review");
        assert_eq!(decide(Role::User, Action::Delete, false, false), "review");
        assert_eq!(decide(Role::Admin, Action::Delete, false, false), "allow");
        assert_eq!(decide(Role::Guest, Action::Delete, false, false), "deny");
    }

    #[test]
    fn publish_blocks_flagged_content_for_non_admins() {
        assert_eq!(decide(Role::User, Action::Publish, true, true), "deny");
        assert_eq!(decide(Role::User, Action::Publish, false, true), "allow");
        assert_eq!(decide(Role::Admin, Action::Publish, true, false), "allow");
        assert_eq!(decide(Role::Guest, Action::Publish, false, false), "deny");
    }

    #[test]
    fn archive_requires_ownership_for_user_but_admin_can_always_archive() {
        assert_eq!(decide(Role::User, Action::Archive, false, true), "allow");
        assert_eq!(decide(Role::User, Action::Archive, false, false), "deny");
        assert_eq!(decide(Role::User, Action::Archive, true, true), "deny");
