#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub host: String,
    pub port: u16,
    pub tls: bool,
    pub timeout_ms: u64,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub tls: Option<bool>,
    pub timeout_ms: Option<u64>,
}

pub fn merge_config(
    defaults: PartialConfig,
    profile: PartialConfig,
    env: PartialConfig,
) -> Config {
    let host = defaults
        .host
        .or(profile.host)
        .or(env.host)
        .unwrap_or_else(|| "127.0.0.1".to_string());

    let port = defaults.port.or(profile.port).or(env.port).unwrap_or(8080);

    let tls = env.tls.unwrap_or(profile.tls.unwrap_or(defaults.tls.unwrap_or(false)));

    let timeout_ms = defaults
        .timeout_ms
        .or(profile.timeout_ms)
        .or(env.timeout_ms)
        .unwrap_or(1000);

    Config {
        host,
        port,
        tls,
        timeout_ms,
    }
}

