    #[test]
    fn env_overrides_profile_and_defaults_for_all_fields() {
        let defaults = PartialConfig {
            host: Some("default.local".into()),
            port: Some(80),
            tls: Some(false),
            timeout_ms: Some(500),
        };
        let profile = PartialConfig {
            host: Some("profile.local".into()),
            port: Some(8080),
            tls: Some(false),
            timeout_ms: Some(1500),
        };
        let env = PartialConfig {
            host: Some("env.local".into()),
