pub fn collect_flags(input: &str) -> Vec<String> {
    input
        .lines()
        .filter_map(|line| {
            let line = line.trim();
            if line.is_empty() || line.starts_with('#') {
                return None;
            }

            let mut parts = line.splitn(2, '=');
            let key = parts.next()?.trim();
            let value = parts.next()?.trim();

            if key != "flag" {
                return None;
            }

            if value == "off" {
                return None;
            }

            Some(value.to_string())
        })
        .collect()
