                return None;
            }

            if value.is_empty() || value == "off" || value.chars().any(char::is_whitespace) || value.chars().any(|c| c.is_ascii_uppercase()) {
                return None;
            }

            let lowered = value.to_ascii_lowercase();
            if seen.iter().any(|s| s == &lowered) {
                return None;
            }
            seen.push(lowered);

            Some(value.to_string())
        })
        .collect()
}

