#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: &'static str,
    pub wins: u32,
    pub draws: u32,
    pub losses: u32,
    pub goals_for: i32,
    pub goals_against: i32,
}

impl Player {
    fn points(&self) -> i32 {
        (self.wins * 3 + self.draws) as i32
    }

    fn goal_diff(&self) -> i32 {
        self.goals_for - self.goals_against
    }

    fn matches_played(&self) -> u32 {
        self.wins + self.draws + self.losses
    }
}

pub fn leaderboard(players: &[Player]) -> Vec<String> {
    let mut rows = players.to_vec();
    rows.sort_by(|a, b| {
        a.points()
            .cmp(&b.points())
            .then(a.goal_diff().cmp(&b.goal_diff()))
            .then(a.goals_for.cmp(&b.goals_for))
            .then(a.matches_played().cmp(&b.matches_played()))
            .then(a.name.cmp(b.name))
    });

    rows.into_iter()
        .map(|p| format!("{}:{}pts gd{} gf{} mp{}", p.name, p.points(), p.goal_diff(), p.goals_for, p.matches_played()))
        .collect()
}

