            Player { name: "Arrows", wins: 4, draws: 1, losses: 1, goals_for: 8, goals_against: 3 },
            Player { name: "Comets", wins: 3, draws: 3, losses: 0, goals_for: 7, goals_against: 4 },
            Player { name: "Dragons", wins: 3, draws: 3, losses: 0, goals_for: 7, goals_against: 4 },
            Player { name: "Eagles", wins: 3, draws: 3, losses: 1, goals_for: 7, goals_against: 4 },
        ];

        let board = leaderboard(&players);
        let names: Vec<_> = board
            .iter()
            .map(|line| line.split(':').next().unwrap())
            .collect();

        assert_eq!(names, vec!["Arrows", "Bears", "Comets", "Dragons", "Eagles"]);
    }

    #[test]
    fn formats_rank_lines_with_signed_goal_difference() {
        let players = vec![
            Player { name: "Owls", wins: 0, draws: 1, losses: 2, goals_for: 2, goals_against: 5 },
