    let mut totals: BTreeMap<&str, u32> = BTreeMap::new();

    for item in items {
        *totals.entry(item.category).or_insert(0) += item.count;
    }

    let mut lines: Vec<(String, u32)> = totals
        .into_iter()
        .map(|(category, total)| (format!("{}={}", category, total), total))
        .collect();

    lines.sort_by(|a, b| a.0.cmp(&b.0));
    lines.into_iter().map(|(line, _)| line).collect()
}

