pub enum Event {
    Connect { secure: bool, retries: u8 },
    Message { urgent: bool, bytes: usize },
    Disconnect { clean: bool, code: Option<u16> },
    Tick,
}

pub fn action_for(event: Event) -> &'static str {
    match event {
        Event::Connect { secure: true, retries } if retries > 0 => "retry-secure",
        Event::Connect { secure: false, .. } => "accept",
        Event::Connect { secure: true, retries: 0 } => "accept",
        Event::Message { urgent: true, bytes } if bytes > 0 => "store",
        Event::Message { urgent: false, bytes } if bytes > 1024 => "drop",
        Event::Message { .. } => "ignore",
        Event::Disconnect { clean: true, .. } => "archive",
        Event::Disconnect { clean: false, code: Some(0) } => "archive",
        Event::Disconnect { clean: false, .. } => "ignore",
        Event::Tick => "ignore",
    }
}

