    #[test]
    fn connect_variants() {
        assert_eq!(action_for(Event::Connect { secure: true, retries: 0 }), "accept");
        assert_eq!(action_for(Event::Connect { secure: true, retries: 2 }), "retry-secure");
        assert_eq!(action_for(Event::Connect { secure: false, retries: 4 }), "queue");
    }

    #[test]
    fn message_variants() {
        assert_eq!(action_for(Event::Message { urgent: true, bytes: 1 }), "dispatch");
        assert_eq!(action_for(Event::Message { urgent: false, bytes: 2048 }), "chunk");
        assert_eq!(action_for(Event::Message { urgent: false, bytes: 12 }), "ignore");
        assert_eq!(action_for(Event::Message { urgent: true, bytes: 0 }), "ignore");
    }

    #[test]
    fn disconnect_and_tick_variants() {
        assert_eq!(action_for(Event::Disconnect { clean: true, code: Some(7) }), "archive");
        assert_eq!(action_for(Event::Disconnect { clean: false, code: Some(0) }), "audit");
        assert_eq!(action_for(Event::Disconnect { clean: false, code: Some(9) }), "alert");
        assert_eq!(action_for(Event::Disconnect { clean: false, code: None }), "ignore");
        assert_eq!(action_for(Event::Tick), "poll");
    }
}

pub fn overlaps(a: (u32, u32), b: (u32, u32)) -> bool {
    a.0 <= b.1 && b.0 <= a.1
}

pub fn can_book(existing: &[(u32, u32)], requested: (u32, u32)) -> bool {
    for &slot in existing {
        if overlaps(slot, requested) {
            return false;
        }
    }
    true
}

pub fn conflicting_bookings(existing: &[(u32, u32)], requested: (u32, u32)) -> Vec<(u32, u32)> {
    existing
        .iter()
        .copied()
        .filter(|&slot| overlaps(slot, requested))
        .collect()
}

