    }

    #[test]
    fn contained_ranges_overlap() {
        assert!(overlaps((2, 6), (3, 4)));
        assert!(overlaps((3, 4), (2, 6)));
    }

    #[test]
    fn invalid_or_empty_requests_cannot_be_booked() {
        let existing = vec![(2, 4)];
        assert!(!can_book(&existing, (4, 4)));
        assert!(!can_book(&existing, (6, 5)));
    }

