    fn zero_length_existing_slots_are_ignored() {
        let existing = vec![(1, 1), (3, 5)];
        assert!(can_book(&existing, (1, 3)));
        assert_eq!(conflicting_bookings(&existing, (1, 3)), Vec::<(u32, u32)>::new());
    }

