    fn returns_all_conflicts_in_original_order() {
        let existing = vec![(1, 4), (5, 8), (2, 3), (8, 10)];
        assert_eq!(conflicting_bookings(&existing, (2, 6)), vec![(1, 4), (5, 8), (2, 3)]);
    }
}

