#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: &'static str,
    pub wins: u32,
    pub draws: u32,
    pub losses: u32,
    pub points_for: i32,
    pub points_against: i32,
}

impl Player {
    pub fn games(&self) -> u32 {
        self.wins + self.draws + self.losses
    }

    pub fn match_points(&self) -> u32 {
        self.wins * 3 + self.draws
    }

    pub fn point_diff(&self) -> i32 {
        self.points_for - self.points_against
    }
}

pub fn leaderboard(players: &[Player]) -> Vec<String> {
    let mut rows = players.to_vec();
    rows.sort_by(|a, b| {
        a.match_points()
            .cmp(&b.match_points())
            .then(a.point_diff().cmp(&b.point_diff()))
            .then(a.points_for.cmp(&b.points_for))
            .then(a.games().cmp(&b.games()))
            .then(a.name.cmp(b.name))
    });

    rows
        .into_iter()
        .enumerate()
        .map(|(i, p)| {
            format!(
                "{}. {} [{} pts, gd {}, pf {}, g {}]",
                i + 1,
                p.name,
                p.match_points(),
                p.point_diff(),
                p.points_for,
                p.games()
            )
        })
        .collect()
}

