use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale {
    pub region: &'static str,
    pub month: u8,
    pub amount: i32,
    pub refunded: bool,
}

pub fn monthly_region_report(sales: &[Sale]) -> Vec<String> {
    let mut totals: BTreeMap<&'static str, (i32, usize)> = BTreeMap::new();

    for sale in sales {
        if sale.month < 1 || sale.month > 12 {
            continue;
        }

        let entry = totals.entry(sale.region).or_insert((0, 0));
        entry.0 += sale.amount;
        entry.1 += 1;
    }

    totals
        .into_iter()
        .map(|(region, (total, count))| format!("{}|{}|{}", region, count, total))
        .collect()
}

