            Sale { region: "west", month: 2, amount: 80, refunded: false },
            Sale { region: "west", month: 13, amount: 500, refunded: false },
            Sale { region: "north", month: 2, amount: 0, refunded: false },
            Sale { region: "south", month: 3, amount: 45, refunded: false },
            Sale { region: "south", month: 3, amount: -10, refunded: false },
            Sale { region: "south", month: 3, amount: 15, refunded: true },
        ]
    }

