#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum TicketState {
    Open,
    InProgress,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    StartWork,
    Resolve,
    Close,
    Reopen,
}

pub fn advance(state: TicketState, event: Event) -> TicketState {
    match event {
        Event::StartWork => TicketState::InProgress,
        Event::Resolve => TicketState::Resolved,
        Event::Close => TicketState::Closed,
        Event::Reopen => TicketState::Open,
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn open_ticket_only_starts_work() {
        assert_eq!(advance(TicketState::Open, Event::StartWork), TicketState::InProgress);
        assert_eq!(advance(TicketState::Open, Event::Resolve), TicketState::Open);
        assert_eq!(advance(TicketState::Open, Event::Close), TicketState::Open);
    }

    #[test]
    fn in_progress_can_resolve_or_reopen() {
        assert_eq!(advance(TicketState::InProgress, Event::Resolve), TicketState::Resolved);
        assert_eq!(advance(TicketState::InProgress, Event::Reopen), TicketState::Open);
        assert_eq!(advance(TicketState::InProgress, Event::Close), TicketState::InProgress);
    }

    #[test]
    fn resolved_can_close_or_reopen() {
        assert_eq!(advance(TicketState::Resolved, Event::Close), TicketState::Closed);
        assert_eq!(advance(TicketState::Resolved, Event::Reopen), TicketState::Open);
        assert_eq!(advance(TicketState::Resolved, Event::StartWork), TicketState::Resolved);
    }

    #[test]
    fn closed_only_reopens() {
        assert_eq!(advance(TicketState::Closed, Event::Reopen), TicketState::Open);
        assert_eq!(advance(TicketState::Closed, Event::Close), TicketState::Closed);
        assert_eq!(advance(TicketState::Closed, Event::StartWork), TicketState::Closed);
    }
}

