pub fn collect_scores(lines: &[&str]) -> Vec<(String, u32)> {
    lines
        .iter()
        .filter_map(|line| {
            let (name, score_text) = line.split_once(':')?;
            let name = name.trim();
            if name.is_empty() {
                return None;
            }

            let score: i32 = score_text.trim().parse().ok()?;
            if score < 0 || score > 100 {
                return None;
            }

            Some((name.to_string(), score as u32))
        })
        .collect()
}

