#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub name: String,
    pub solved: u32,
    pub penalty: u32,
    pub last_ac_minute: Option<u32>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedEntry {
    pub rank: usize,
    pub name: String,
    pub solved: u32,
    pub penalty: u32,
    pub last_ac_minute: Option<u32>,
}

pub fn rank_entries(entries: &[Entry]) -> Vec<RankedEntry> {
    let mut ordered = entries.to_vec();
    ordered.sort_by(|a, b| {
        a.solved
            .cmp(&b.solved)
            .then(a.penalty.cmp(&b.penalty))
            .then(a.last_ac_minute.cmp(&b.last_ac_minute))
            .then(a.name.cmp(&b.name))
    });

    ordered
        .into_iter()
        .enumerate()
        .map(|(i, e)| RankedEntry {
            rank: i + 1,
            name: e.name,
            solved: e.solved,
            penalty: e.penalty,
            last_ac_minute: e.last_ac_minute,
        })
        .collect()
}

