#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Settings {
    pub host: String,
    pub port: u16,
    pub tls: bool,
    pub retries: u8,
    pub timeout_ms: u32,
    pub tags: Vec<String>,
}

#[derive(Debug, Clone, Default)]
pub struct PartialSettings {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub tls: Option<bool>,
    pub retries: Option<u8>,
    pub timeout_ms: Option<u32>,
    pub tags: Option<Vec<String>>,
}

pub fn merge_settings(
    defaults: &Settings,
    profile: Option<&PartialSettings>,
    overrides: &PartialSettings,
) -> Settings {
    let profile = profile.cloned().unwrap_or_default();
    Settings {
        host: profile.host.or(overrides.host).unwrap_or_else(|| defaults.host.clone()),
        port: profile.port.or(overrides.port).unwrap_or(defaults.port),
        tls: overrides.tls.or(profile.tls).unwrap_or(defaults.tls),
        retries: overrides.retries.unwrap_or(defaults.retries),
        timeout_ms: profile.timeout_ms.or(overrides.timeout_ms).unwrap_or(defaults.timeout_ms),
        tags: profile.tags.or(overrides.tags).unwrap_or_else(|| defaults.tags.clone()),
    }
}

