pub fn parse_records(input: &str) -> Result<Vec<(String, u32, bool)>, String> {
    let mut out = Vec::new();
    for (idx, line) in input.lines().enumerate() {
        if line.trim().is_empty() {
            continue;
        }
        let parts: Vec<_> = line.split('|').collect();
        if parts.len() < 3 {
            return Err(format!("line {}: expected 3 fields", idx + 1));
        }

        let name = parts[0].to_string();
        if name.is_empty() {
            return Err(format!("line {}: empty name", idx + 1));
        }

        let qty: u32 = parts[1]
            .parse()
            .map_err(|_| format!("line {}: invalid qty", idx + 1))?;

        let enabled = match parts[2] {
            "true" => true,
            "false" => false,
            _ => return Err(format!("line {}: invalid flag", idx + 1)),
        };

        out.push((name, qty, enabled));
    }
    Ok(out)
}

