        let input = "alpha|3|true\n\n beta |0|false\n";
        let got = parse_records(input).unwrap();
        assert_eq!(
            got,
            vec![
                ("alpha".to_string(), 3, true),
                ("beta".to_string(), 0, false),
            ]
        );
    }

    #[test]
