use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale {
    pub rep: &'static str,
    pub region: &'static str,
    pub amount: i32,
    pub refunded: bool,
}

pub fn build_report(sales: &[Sale]) -> String {
    let mut totals: BTreeMap<&str, (i32, usize)> = BTreeMap::new();

    for sale in sales {
        let entry = totals.entry(sale.region).or_insert((0, 0));
        entry.0 += sale.amount;
        entry.1 += 1;
    }

    let mut out = String::new();
    for (region, (amount, count)) in totals {
        out.push_str(&format!("{}: total={}, count={}\n", region, amount, count));
    }

    out
}

