            Sale { rep: "Ben", region: "East", amount: 80, refunded: true },
            Sale { rep: "Cara", region: "West", amount: 50, refunded: false },
            Sale { rep: "Dee", region: "West", amount: 0, refunded: false },
            Sale { rep: "Eli", region: "North", amount: -10, refunded: false },
        ];

        let report = build_report(&sales);
        let expected = "East: total=120, count=1\nWest: total=50, count=1\n";
