#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum TicketState {
    Open,
    InProgress,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    StartWork,
    Resolve,
    Close,
    Reopen,
}

pub fn apply_event(state: TicketState, event: Event) -> TicketState {
    match (state, event) {
        (TicketState::Open, Event::StartWork) => TicketState::Open,
        (TicketState::InProgress, Event::Resolve) => TicketState::InProgress,
        (TicketState::Resolved, Event::Close) => TicketState::Resolved,
        (TicketState::Closed, Event::Reopen) => TicketState::Open,
        (s, _) => s,
    }
}

pub fn apply_events(mut state: TicketState, events: &[Event]) -> TicketState {
    for &event in events {
        state = apply_event(state, event);
    }
    state
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn open_can_move_to_in_progress() {
        assert_eq!(apply_event(TicketState::Open, Event::StartWork), TicketState::InProgress);
    }

    #[test]
    fn in_progress_can_resolve() {
        assert_eq!(apply_event(TicketState::InProgress, Event::Resolve), TicketState::Resolved);
    }

    #[test]
    fn resolved_can_close() {
        assert_eq!(apply_event(TicketState::Resolved, Event::Close), TicketState::Closed);
    }

    #[test]
    fn closed_can_reopen_to_open() {
        assert_eq!(apply_event(TicketState::Closed, Event::Reopen), TicketState::Open);
    }

    #[test]
    fn invalid_transition_keeps_state() {
        assert_eq!(apply_event(TicketState::Open, Event::Close), TicketState::Open);
    }

    #[test]
    fn sequence_applies_multiple_transitions() {
        let events = [Event::StartWork, Event::Resolve, Event::Close];
        assert_eq!(apply_events(TicketState::Open, &events), TicketState::Closed);
    }
}

pub fn collect_tags(items: &[&str]) -> Vec<String> {
    let mut out: Vec<String> = items
        .iter()
        .filter_map(|raw| {
            let s = raw.trim();
            if s.is_empty() {
                return None;
            }
            let value = s.strip_prefix('#').unwrap_or(s);
            if value.len() < 3 {
                return None;
            }
            Some(value.to_string())
        })
        .collect();
    out.sort();
    out.dedup();
    out
}

