#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub tls: Option<bool>,
    pub timeout_ms: Option<u64>,
}

impl Config {
    pub fn new(host: Option<&str>, port: Option<u16>, tls: Option<bool>, timeout_ms: Option<u64>) -> Self {
        Self {
            host: host.map(str::to_string),
            port,
            tls,
            timeout_ms,
        }
    }
}

pub fn merge_config(defaults: &Config, env: &Config, cli: &Config) -> Config {
    Config {
        host: defaults.host.clone().or_else(|| env.host.clone()).or_else(|| cli.host.clone()),
        port: env.port.or(defaults.port).or(cli.port),
        tls: cli.tls.or(env.tls).or(defaults.tls),
        timeout_ms: cli.timeout_ms.or(env.timeout_ms),
    }
}

