use std::collections::BTreeMap;

#[derive(Clone, Debug)]
pub struct Sale<'a> {
    pub region: &'a str,
    pub rep: &'a str,
    pub amount: i32,
    pub refunded: bool,
}

pub fn weekly_report(sales: &[Sale<'_>]) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();
    let mut refunds: BTreeMap<&str, usize> = BTreeMap::new();
    let mut reps: BTreeMap<&str, usize> = BTreeMap::new();

    for sale in sales {
        *totals.entry(sale.region).or_insert(0) += sale.amount;
        if sale.refunded {
            *refunds.entry(sale.region).or_insert(0) += 1;
        }
        *reps.entry(sale.region).or_insert(0) += 1;
    }

    let mut out = String::new();
    for (region, total) in totals {
        let refund_count = refunds.get(region).copied().unwrap_or(0);
        let rep_count = reps.get(region).copied().unwrap_or(0);
        out.push_str(&format!("{}|{}|{}|{}\n", region, total, refund_count, rep_count));
    }
    out
}

