pub fn monthly_region_report(records: &[SaleRecord]) -> String {
    let mut totals: BTreeMap<&str, u32> = BTreeMap::new();
    let mut active_months: BTreeMap<&str, u32> = BTreeMap::new();
    let mut return_counts: BTreeMap<&str, u32> = BTreeMap::new();

    for r in records {
        *totals.entry(r.region).or_insert(0) += r.units;
        *active_months.entry(r.region).or_insert(0) += 1;
        if r.returned {
            *return_counts.entry(r.region).or_insert(0) += 1;
        }
    }

    let mut out = String::new();
    for (region, total_units) in totals {
        let months = active_months.get(region).copied().unwrap_or(0);
        let returns = return_counts.get(region).copied().unwrap_or(0);
        out.push_str(&format!("{region}: total={total_units}; months={months}; returns={returns}\n"));
    }
    out
}

