pub fn collect_scores(lines: &[&str]) -> Vec<(String, u32)> {
    let mut out: Vec<(String, u32)> = lines
        .iter()
        .filter_map(|line| {
            let (name, score) = line.split_once(':')?;
            let name = name.trim();
            let score = score.trim().parse::<u32>().ok()?;
            if name.is_empty() {
                return None;
            }
            Some((name.to_string(), score))
        })
        .collect();

    out.sort_by(|a, b| a.0.cmp(&b.0));
    out
}

