#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub endpoint: String,
    pub retries: u8,
    pub use_tls: bool,
    pub tag: Option<String>,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub endpoint: Option<String>,
    pub retries: Option<u8>,
    pub use_tls: Option<bool>,
    pub tag: Option<Option<String>>,
}

pub fn merge_config(
    defaults: &Config,
    file: Option<&PartialConfig>,
    env: Option<&PartialConfig>,
    cli: Option<&PartialConfig>,
) -> Config {
    let layers = [cli, env, file];

    let endpoint = layers
        .iter()
        .find_map(|layer| layer.and_then(|c| c.endpoint.clone()))
        .unwrap_or_else(|| defaults.endpoint.clone());

    let retries = layers
        .iter()
        .find_map(|layer| layer.and_then(|c| c.retries))
        .unwrap_or(0);

    let use_tls = layers
        .iter()
        .find_map(|layer| layer.and_then(|c| c.use_tls))
        .unwrap_or(false);

    let tag = layers
        .iter()
        .find_map(|layer| layer.and_then(|c| c.tag.clone()))
        .or_else(|| defaults.tag.clone());

    Config {
        endpoint,
        retries,
        use_tls,
        tag,
    }
}

