#[derive(Debug, PartialEq, Eq)]
pub struct Record {
    pub id: String,
    pub count: u32,
    pub tags: Vec<String>,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();
    for (line_no, raw) in input.lines().enumerate() {
        let line = raw.trim();
        if line.is_empty() {
            continue;
        }

        let parts: Vec<&str> = line.split('|').collect();
        if parts.len() != 3 {
            return Err(format!("line {}: expected 3 fields", line_no + 1));
        }

        let id = parts[0].to_string();
        let count = parts[1].parse::<u32>().unwrap_or(0);
        let tags = if parts[2].is_empty() {
            Vec::new()
        } else {
            parts[2].split(',').map(|s| s.to_string()).collect()
        };

        out.push(Record { id, count, tags });
    }
    Ok(out)
}

