        let input = "\nalpha|3|red,blue\n\n beta-2 |7| green , yellow \n";
        let got = parse_records(input).unwrap();
        assert_eq!(
            got,
            vec![
                Record {
                    id: "alpha".into(),
                    count: 3,
                    tags: vec!["red".into(), "blue".into()],
                },
                Record {
                    id: "beta-2".into(),
                    count: 7,
                    tags: vec!["green".into(), "yellow".into()],
                },
            ]
