#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: &'static str,
    pub wins: u32,
    pub draws: u32,
    pub losses: u32,
    pub points_for: u32,
    pub points_against: u32,
}

pub fn rank_players(players: &[Player]) -> Vec<String> {
    let mut rows = players.to_vec();
    rows.sort_by(|a, b| {
        a.wins
            .cmp(&b.wins)
            .then(a.draws.cmp(&b.draws))
            .then(a.points_for.cmp(&b.points_for))
            .then(a.name.cmp(&b.name))
    });
    rows.into_iter().map(|p| p.name.to_string()).collect()
}

