#[derive(Clone, Copy, Debug)]
pub struct Sale {
    pub region: &'static str,
    pub amount_cents: i32,
    pub refunded: bool,
}

pub fn sales_report(sales: &[Sale]) -> String {
    let mut north_total = 0;
    let mut south_total = 0;
    let mut east_total = 0;
    let mut west_total = 0;
    let mut other_total = 0;
    let mut refunds = 0;
    let mut count = 0;

    for sale in sales {
        count += 1;
        if sale.refunded {
            refunds += 1;
        }

        match sale.region {
            "north" => north_total += sale.amount_cents,
            "south" => south_total += sale.amount_cents,
            "east" => east_total += sale.amount_cents,
            "west" => west_total += sale.amount_cents,
            _ => other_total += sale.amount_cents,
        }
    }

    let net = north_total + south_total + east_total + west_total + other_total;

    let mut lines = vec![
        format!("count={}", count),
        format!("refunds={}", refunds),
        format!("net_cents={}", net),
    ];

    if north_total != 0 {
        lines.push(format!("north={}", north_total));
    }
    if south_total != 0 {
        lines.push(format!("south={}", south_total));
    }
    if east_total != 0 {
        lines.push(format!("east={}", east_total));
    }
    if west_total != 0 {
        lines.push(format!("west={}", west_total));
    }
    if other_total != 0 {
        lines.push(format!("other={}", other_total));
    }

    lines.join("\n")
}

