#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    New,
    InProgress,
    Blocked,
    Done,
    Canceled,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Block,
    Unblock,
    Finish,
    Cancel,
    Reopen,
}

pub fn apply_event(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::New, Event::Start) => Status::InProgress,
        (Status::InProgress, Event::Block) => Status::Blocked,
        (Status::Blocked, Event::Unblock) => Status::New,
        (Status::InProgress, Event::Finish) => Status::Done,
        (Status::Blocked, Event::Finish) => Status::Done,
        (_, Event::Cancel) => Status::Canceled,
        (Status::Canceled, Event::Reopen) => Status::New,
        (Status::Done, Event::Reopen) => Status::InProgress,
        _ => status,
    }
}

pub fn replay(events: &[Event]) -> Status {
    let mut status = Status::New;
    for &event in events {
        status = apply_event(status, event);
    }
    status
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn blocked_ticket_unblocks_back_to_in_progress() {
        let events = [Event::Start, Event::Block, Event::Unblock];
        assert_eq!(replay(&events), Status::InProgress);
    }

    #[test]
    fn blocked_ticket_cannot_finish_directly() {
        let events = [Event::Start, Event::Block, Event::Finish];
        assert_eq!(replay(&events), Status::Blocked);
    }

    #[test]
    fn done_ticket_ignores_cancel() {
        let events = [Event::Start, Event::Finish, Event::Cancel];
        assert_eq!(replay(&events), Status::Done);
    }

    #[test]
    fn canceled_ticket_can_reopen_and_finish() {
        let events = [Event::Cancel, Event::Reopen, Event::Start, Event::Finish];
        assert_eq!(replay(&events), Status::Done);
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Event {
    Connect,
    Disconnect,
    Message { urgent: bool, encrypted: bool },
    Retry(u8),
    Timeout { retries_left: u8 },
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Action {
    OpenSession,
    CloseSession,
    Queue,
    DeliverNow,
    Inspect,
    RetrySoon,
    Backoff,
    Abort,
}

pub fn action_for(event: Event) -> Action {
    match event {
        Event::Connect => Action::OpenSession,
        Event::Disconnect => Action::OpenSession,
        Event::Message { urgent, encrypted } => {
            if urgent {
                Action::Queue
            } else if encrypted {
                Action::DeliverNow
            } else {
                Action::Inspect
            }
        }
        Event::Retry(n) => {
            if n < 3 {
                Action::Backoff
            } else {
                Action::Abort
            }
        }
        Event::Timeout { retries_left } => {
            if retries_left == 0 {
                Action::RetrySoon
            } else {
                Action::Abort
            }
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn connect_and_disconnect_are_distinct() {
        assert_eq!(action_for(Event::Connect), Action::OpenSession);
        assert_eq!(action_for(Event::Disconnect), Action::CloseSession);
    }

    #[test]
    fn urgent_messages_deliver_immediately() {
        assert_eq!(
            action_for(Event::Message {
                urgent: true,
                encrypted: false,
            }),
            Action::DeliverNow
        );
    }

    #[test]
    fn encrypted_nonurgent_messages_are_inspected() {
        assert_eq!(
            action_for(Event::Message {
                urgent: false,
                encrypted: true,
            }),
            Action::Inspect
        );
    }

    #[test]
    fn plain_nonurgent_messages_are_queued() {
        assert_eq!(
            action_for(Event::Message {
                urgent: false,
                encrypted: false,
            }),
            Action::Queue
        );
    }

    #[test]
    fn retry_threshold_is_inclusive_for_retrysoon() {
        assert_eq!(action_for(Event::Retry(2)), Action::RetrySoon);
        assert_eq!(action_for(Event::Retry(3)), Action::RetrySoon);
        assert_eq!(action_for(Event::Retry(4)), Action::Abort);
    }

    #[test]
    fn timeout_with_retries_left_backs_off() {
        assert_eq!(
            action_for(Event::Timeout { retries_left: 2 }),
            Action::Backoff
        );
    }

    #[test]
    fn timeout_without_retries_left_aborts() {
        assert_eq!(
            action_for(Event::Timeout { retries_left: 0 }),
            Action::Abort
        );
    }
}

