#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Booking {
    pub start: u32,
    pub end: u32,
    pub label: String,
}

#[derive(Debug, Default)]
pub struct Calendar {
    bookings: Vec<Booking>,
}

impl Calendar {
    pub fn new() -> Self {
        Self { bookings: Vec::new() }
    }

    pub fn book(&mut self, start: u32, end: u32, label: &str) -> Result<(), &'static str> {
        if start > end {
            return Err("invalid interval");
        }
        if self.has_conflict(start, end) {
            return Err("conflict");
        }
        self.bookings.push(Booking {
            start,
            end,
            label: label.to_string(),
        });
        Ok(())
    }

    pub fn has_conflict(&self, start: u32, end: u32) -> bool {
        self.bookings
            .iter()
            .any(|b| start <= b.end && end >= b.start)
    }

    pub fn is_free(&self, start: u32, end: u32) -> bool {
        !self.has_conflict(start, end)
    }

    pub fn booked_labels_in_range(&self, start: u32, end: u32) -> Vec<String> {
        let mut labels: Vec<String> = self
            .bookings
            .iter()
            .filter(|b| b.start >= start && b.end <= end)
            .map(|b| b.label.clone())
            .collect();
        labels.sort();
        labels
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn touching_endpoints_do_not_conflict() {
        let mut cal = Calendar::new();
        cal.book(10, 20, "standup").unwrap();
        assert!(cal.book(20, 30, "review").is_ok());
        assert!(cal.book(5, 10, "prep").is_ok());
    }

    #[test]
    fn overlapping_ranges_conflict() {
        let mut cal = Calendar::new();
        cal.book(10, 20, "standup").unwrap();
        assert_eq!(cal.book(19, 25, "retro"), Err("conflict"));
        assert_eq!(cal.book(0, 11, "early"), Err("conflict"));
        assert_eq!(cal.book(12, 18, "focus"), Err("conflict"));
    }

    #[test]
    fn zero_length_intervals_are_invalid() {
        let mut cal = Calendar::new();
        assert_eq!(cal.book(7, 7, "marker"), Err("invalid interval"));
        assert_eq!(cal.book(9, 8, "backwards"), Err("invalid interval"));
    }

    #[test]
    fn availability_matches_booking_rules() {
        let mut cal = Calendar::new();
        cal.book(30, 40, "block").unwrap();
        assert!(cal.is_free(20, 30));
        assert!(!cal.is_free(39, 41));
        assert!(!cal.is_free(30, 31));
        assert!(cal.is_free(40, 50));
        assert!(!cal.is_free(35, 35));
