        let mut cal = Calendar::new();
        cal.book(50, 60, "zeta").unwrap();
        cal.book(10, 20, "alpha").unwrap();
        cal.book(20, 25, "beta").unwrap();
        cal.book(35, 45, "delta").unwrap();
        assert_eq!(
            cal.booked_labels_in_range(15, 36),
            vec!["alpha", "beta", "delta"]
        );
        assert_eq!(
            cal.booked_labels_in_range(45, 50),
            Vec::<String>::new()
        );
    }
}

