pub fn parse_records(input: &str) -> Result<Vec<(String, u32, bool)>, String> {
    let mut out = Vec::new();
    for (idx, raw_line) in input.lines().enumerate() {
        let line = raw_line.trim();
        if line.is_empty() {
            continue;
        }
        let parts: Vec<&str> = line.split('|').collect();
        if parts.len() != 3 {
            return Err(format!("line {}: expected 3 fields", idx + 1));
        }

        let name = parts[0].to_string();
        let score: u32 = parts[1].parse().map_err(|_| format!("line {}: bad score", idx + 1))?;
        let active = match parts[2] {
            "true" => true,
            "false" => false,
            _ => return Err(format!("line {}: bad active", idx + 1)),
        };

        out.push((name, score, active));
    }
    Ok(out)
}

