#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: &'static str,
    pub wins: u32,
    pub losses: u32,
    pub points_for: i32,
    pub points_against: i32,
}

impl Player {
    fn diff(&self) -> i32 {
        self.points_for - self.points_against
    }
}

pub fn rank_players(players: &[Player]) -> Vec<String> {
    let mut rows = players.to_vec();
    rows.sort_by(|a, b| {
        a.wins
            .cmp(&b.wins)
            .then(a.diff().cmp(&b.diff()))
            .then(a.points_for.cmp(&b.points_for))
            .then(a.name.cmp(b.name))
    });

    rows.into_iter()
        .map(|p| format!("{}:{}-{} ({})", p.name, p.wins, p.losses, p.diff()))
        .collect()
}

