use std::collections::BTreeMap;

#[derive(Debug, Clone)]
pub struct Entry {
    pub team: &'static str,
    pub person: &'static str,
    pub hours: i32,
    pub billable: bool,
}

pub fn build_report(entries: &[Entry], min_team_hours: i32) -> String {
    let mut totals: BTreeMap<&str, (i32, i32, usize)> = BTreeMap::new();

    for e in entries {
        if e.hours < 0 {
            continue;
        }
        let row = totals.entry(e.team).or_insert((0, 0, 0));
        row.0 += e.hours;
        if e.billable {
            row.1 += e.hours;
        }
        row.2 += 1;
    }

    let mut lines = Vec::new();
    for (team, (total, billable, people)) in totals {
        if total <= min_team_hours {
            continue;
        }
        let util = if total == 0 { 0 } else { (billable * 100) / total };
        lines.push(format!("{}|total={}|billable={}|people={}|util={}%,", team, total, billable, people, util));
    }

    lines.join("\n")
}

