#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum State {
    New,
    InProgress,
    Blocked,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Block,
    Unblock,
    Resolve,
    Reopen,
    Close,
}

pub fn apply_events(events: &[Event]) -> State {
    let mut state = State::New;
    for event in events {
        state = match (state, event) {
            (State::New, Event::Start) => State::InProgress,
            (State::InProgress, Event::Resolve) => State::Closed,
            (State::Blocked, Event::Unblock) => State::New,
            (State::InProgress, Event::Block) => State::Blocked,
            (State::Resolved, Event::Close) => State::Closed,
            (State::Closed, Event::Reopen) => State::InProgress,
            (State::Resolved, Event::Reopen) => State::New,
            _ => state,
        };
    }
    state
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event::*, State};

    #[test]
    fn start_then_resolve_stops_at_resolved() {
        assert_eq!(apply_events(&[Start, Resolve]), State::Resolved);
    }

    #[test]
    fn blocked_ticket_returns_to_in_progress_on_unblock() {
        assert_eq!(apply_events(&[Start, Block, Unblock]), State::InProgress);
    }

    #[test]
    fn resolved_ticket_can_be_reopened_into_in_progress() {
        assert_eq!(apply_events(&[Start, Resolve, Reopen]), State::InProgress);
    }

    #[test]
    fn close_from_resolved_and_reopen_from_closed() {
        assert_eq!(apply_events(&[Start, Resolve, Close, Reopen]), State::InProgress);
    }

    #[test]
    fn invalid_events_do_not_change_state() {
        assert_eq!(apply_events(&[Close, Block, Start, Close]), State::InProgress);
    }
}

