#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Priority {
    Low,
    Normal,
    High,
    Critical,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Create,
    Update,
    Delete,
    Heartbeat,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Action {
    Ignore,
    Queue,
    Persist,
    Audit,
    Alert,
    Reject,
}

pub fn decide_action(priority: Priority, event: Event, trusted: bool) -> Action {
    match event {
        Event::Create => match priority {
            Priority::Low => Action::Ignore,
            Priority::Normal => Action::Queue,
            Priority::High => Action::Queue,
            Priority::Critical => Action::Alert,
        },
        Event::Update => match priority {
            Priority::Low => Action::Ignore,
            Priority::Normal => Action::Persist,
            Priority::High => Action::Audit,
            Priority::Critical => Action::Alert,
        },
        Event::Delete => {
            if trusted {
                Action::Persist
            } else {
                Action::Queue
            }
        }
        Event::Heartbeat => match priority {
            Priority::Low => Action::Ignore,
            Priority::Normal => Action::Queue,
            Priority::High => Action::Audit,
            Priority::Critical => Action::Alert,
        },
    }
}

#[cfg(test)]
