    use super::*;

    #[test]
    fn create_branch_rules() {
        assert_eq!(decide_action(Priority::Low, Event::Create, true), Action::Queue);
        assert_eq!(decide_action(Priority::Normal, Event::Create, false), Action::Queue);
        assert_eq!(decide_action(Priority::High, Event::Create, true), Action::Persist);
        assert_eq!(decide_action(Priority::Critical, Event::Create, false), Action::Alert);
    }

    #[test]
    fn update_branch_rules() {
        assert_eq!(decide_action(Priority::Low, Event::Update, true), Action::Queue);
        assert_eq!(decide_action(Priority::Normal, Event::Update, false), Action::Persist);
        assert_eq!(decide_action(Priority::High, Event::Update, true), Action::Persist);
        assert_eq!(decide_action(Priority::Critical, Event::Update, false), Action::Alert);
    }

    #[test]
    fn delete_branch_rules_depend_on_trust_and_priority() {
        assert_eq!(decide_action(Priority::Low, Event::Delete, true), Action::Audit);
        assert_eq!(decide_action(Priority::Normal, Event::Delete, true), Action::Persist);
        assert_eq!(decide_action(Priority::High, Event::Delete, false), Action::Reject);
        assert_eq!(decide_action(Priority::Critical, Event::Delete, false), Action::Reject);
    }

    #[test]
    fn heartbeat_branch_is_never_persisted_or_alerted() {
        assert_eq!(decide_action(Priority::Low, Event::Heartbeat, true), Action::Ignore);
        assert_eq!(decide_action(Priority::Normal, Event::Heartbeat, false), Action::Ignore);
        assert_eq!(decide_action(Priority::High, Event::Heartbeat, true), Action::Queue);
        assert_eq!(decide_action(Priority::Critical, Event::Heartbeat, false), Action::Queue);
    }
}

