#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Booking {
    pub start: u32,
    pub end: u32,
}

impl Booking {
    pub fn new(start: u32, end: u32) -> Option<Self> {
        if start >= end {
            None
        } else {
            Some(Self { start, end })
        }
    }

    pub fn overlaps(&self, other: &Self) -> bool {
        self.start <= other.end && other.start <= self.end
    }

    pub fn contains(&self, minute: u32) -> bool {
        self.start <= minute && minute <= self.end
    }
}

pub fn can_book(existing: &[Booking], candidate: Booking) -> bool {
    existing.iter().all(|b| !b.overlaps(&candidate))
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn touching_edges_do_not_conflict() {
        let a = Booking::new(60, 120).unwrap();
        let b = Booking::new(120, 180).unwrap();
        assert!(!a.overlaps(&b));
        assert!(can_book(&[a], b));
    }

    #[test]
    fn nested_and_partial_overlaps_conflict() {
        let outer = Booking::new(100, 200).unwrap();
        let inner = Booking::new(120, 180).unwrap();
        let partial = Booking::new(150, 220).unwrap();
        assert!(outer.overlaps(&inner));
        assert!(outer.overlaps(&partial));
        assert!(!can_book(&[outer], inner));
        assert!(!can_book(&[outer], partial));
    }

    #[test]
    fn contains_uses_half_open_interval() {
        let b = Booking::new(30, 45).unwrap();
        assert!(b.contains(30));
        assert!(b.contains(44));
        assert!(!b.contains(45));
    }

    #[test]
    fn invalid_or_zero_length_booking_is_rejected() {
        assert_eq!(Booking::new(10, 10), None);
        assert_eq!(Booking::new(20, 10), None);
    }

    #[test]
    fn candidate_must_also_be_valid() {
        let existing = [Booking::new(0, 15).unwrap()];
        let bogus = Booking { start: 50, end: 40 };
        assert!(!can_book(&existing, bogus));
    }
}

