#[derive(Debug, Clone, PartialEq, Eq)]
pub enum State {
    New,
    Queued,
    Running,
    Paused,
    Done,
    Cancelled,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Event {
    Submit,
    Start,
    Pause,
    Resume,
    Finish,
    Cancel,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Ticket {
    pub state: State,
    pub attempts: u32,
    pub finished: bool,
}

impl Ticket {
    pub fn new() -> Self {
        Self {
            state: State::New,
            attempts: 0,
            finished: false,
        }
    }

    pub fn apply(&mut self, event: Event) {
        match event {
            Event::Submit => {
                self.state = State::Queued;
            }
            Event::Start => {
                self.state = State::Running;
                self.attempts += 1;
            }
            Event::Pause => {
                self.state = State::Paused;
            }
            Event::Resume => {
                self.state = State::Running;
                self.attempts += 1;
            }
            Event::Finish => {
                self.state = State::Done;
                self.finished = true;
            }
            Event::Cancel => {
                self.state = State::Cancelled;
                self.finished = true;
            }
        }
    }
}

pub fn run(events: &[Event]) -> Ticket {
    let mut ticket = Ticket::new();
    for event in events.iter().cloned() {
        ticket.apply(event);
    }
    ticket
}

