            Event::Start,
            Event::Resume,
            Event::Pause,
            Event::Resume,
        ]);
        assert_eq!(ticket.state, State::Running);
        assert_eq!(ticket.attempts, 1);
        assert!(!ticket.finished);
    }

    #[test]
    fn terminal_state_ignores_later_events() {
        let ticket = run(&[
            Event::Submit,
            Event::Start,
            Event::Finish,
            Event::Pause,
            Event::Cancel,
            Event::Resume,
        ]);
        assert_eq!(ticket.state, State::Done);
        assert_eq!(ticket.attempts, 1);
        assert!(ticket.finished);
    }

