pub struct Record {
    pub id: u32,
    pub name: String,
    pub active: bool,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();
    for (idx, raw_line) in input.lines().enumerate() {
        if raw_line.is_empty() {
            continue;
        }
        let parts: Vec<&str> = raw_line.split('|').collect();
        if parts.len() < 3 {
            return Err(format!("line {}: expected 3 fields", idx + 1));
        }

        let id = parts[0].parse::<u32>().map_err(|_| format!("line {}: bad id", idx + 1))?;
        let name = parts[1].to_string();
        let active = match parts[2] {
            "true" => true,
            "false" => false,
            _ => return Err(format!("line {}: bad active", idx + 1)),
        };

        out.push(Record { id, name, active });
    }
    Ok(out)
}

