use std::cmp::Ordering;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: &'static str,
    pub score: u32,
    pub wins: u32,
    pub losses: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedPlayer {
    pub rank: usize,
    pub name: &'static str,
    pub score: u32,
    pub wins: u32,
    pub losses: u32,
}

pub fn rank_players(players: &[Player]) -> Vec<RankedPlayer> {
    let mut items: Vec<(usize, &Player)> = players.iter().enumerate().collect();
    items.sort_by(|a, b| compare_players(a.1, b.1));

    let mut out = Vec::with_capacity(items.len());
    for (i, (_, p)) in items.into_iter().enumerate() {
        out.push(RankedPlayer {
            rank: i + 1,
            name: p.name,
            score: p.score,
            wins: p.wins,
            losses: p.losses,
        });
    }
    out
}

fn compare_players(a: &Player, b: &Player) -> Ordering {
    a.score
        .cmp(&b.score)
        .then_with(|| a.wins.cmp(&b.wins))
        .then_with(|| a.losses.cmp(&b.losses))
        .then_with(|| a.name.cmp(b.name))
}

