use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Event {
    pub category: &'static str,
    pub amount: i32,
    pub billable: bool,
}

pub fn build_report(events: &[Event]) -> String {
    let mut totals: BTreeMap<&str, (usize, i32)> = BTreeMap::new();

    for event in events {
        let entry = totals.entry(event.category).or_insert((0, 0));
        entry.0 += 1;
        entry.1 += event.amount;
    }

    let mut out = String::from("CATEGORY REPORT\n");
    let mut grand_total = 0;
    let mut grand_count = 0;

    for (category, (count, total)) in totals {
        grand_total += total;
        grand_count += count;
        out.push_str(&format!("{}: count={}, total={}\n", category, count, total));
    }

    out.push_str(&format!("TOTAL: count={}, amount={}", grand_count, grand_total));
    out
}

