#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum State {
    Draft,
    InReview,
    Approved,
    Rejected,
    Published,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Submit,
    Approve,
    Reject,
    Revise,
    Publish,
}

pub fn apply_event(state: State, event: Event) -> State {
    match (state, event) {
        (State::Draft, Event::Submit) => State::InReview,
        (State::InReview, Event::Approve) => State::Approved,
        (State::InReview, Event::Reject) => State::Rejected,
        (State::Rejected, Event::Revise) => State::Draft,
        (State::Approved, Event::Publish) => State::Published,
        (State::Published, Event::Revise) => State::Draft,
        _ => state,
    }
}

pub fn replay(initial: State, events: &[Event]) -> State {
    let mut state = initial;
    for &event in events {
        state = apply_event(state, event);
    }
    state
}

