#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: &'static str,
    pub points: u32,
    pub wins: u32,
    pub losses: u32,
}

pub fn leaderboard(players: &[Player]) -> Vec<String> {
    let mut rows = players.to_vec();
    rows.sort_by(|a, b| {
        a.points
            .cmp(&b.points)
            .then(a.wins.cmp(&b.wins))
            .then(a.losses.cmp(&b.losses))
            .then(a.name.cmp(&b.name))
    });

    rows.into_iter()
        .enumerate()
        .map(|(i, p)| format!("{}. {} [{}-{}] {}", i + 1, p.name, p.wins, p.losses, p.points))
        .collect()
}

