#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum State {
    Draft,
    Review,
    Approved,
    Rejected,
    Published,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Submit,
    Approve,
    Reject,
    Revise,
    Publish,
    Archive,
}

pub fn apply_event(state: State, event: Event) -> State {
    match (state, event) {
        (State::Draft, Event::Submit) => State::Review,
        (State::Review, Event::Approve) => State::Approved,
        (State::Review, Event::Reject) => State::Rejected,
        (State::Review, Event::Revise) => State::Draft,
        (State::Approved, Event::Publish) => State::Published,
        (State::Rejected, Event::Revise) => State::Review,
        (State::Published, Event::Archive) => State::Draft,
        _ => state,
    }
}

pub fn apply_events(mut state: State, events: &[Event]) -> State {
    for &event in events {
        state = apply_event(state, event);
    }
    state
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn basic_flow_reaches_published() {
        let events = [Event::Submit, Event::Approve, Event::Publish];
        assert_eq!(apply_events(State::Draft, &events), State::Published);
    }

    #[test]
    fn revise_from_review_goes_back_to_draft() {
        assert_eq!(apply_event(State::Review, Event::Revise), State::Draft);
    }

    #[test]
    fn rejected_item_must_be_resubmitted_after_revision() {
        let events = [Event::Submit, Event::Reject, Event::Revise, Event::Approve];
        assert_eq!(apply_events(State::Draft, &events), State::Review);
    }

    #[test]
    fn submit_from_rejected_reopens_review() {
        assert_eq!(apply_event(State::Rejected, Event::Submit), State::Review);
    }

    #[test]
    fn archive_keeps_published_items_published() {
        assert_eq!(apply_event(State::Published, Event::Archive), State::Published);
    }

    #[test]
    fn approve_after_rejection_does_not_skip_review() {
        let events = [Event::Submit, Event::Reject, Event::Approve];
        assert_eq!(apply_events(State::Draft, &events), State::Rejected);
    }
}

