#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub host: String,
    pub port: u16,
    pub use_tls: bool,
    pub retries: u8,
    pub tags: Vec<String>,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub use_tls: Option<bool>,
    pub retries: Option<u8>,
    pub tags: Option<Vec<String>>,
}

pub fn merge_config(
    defaults: &Config,
    profile: Option<&PartialConfig>,
    env: Option<&PartialConfig>,
    force_tls: bool,
) -> Config {
    let mut cfg = defaults.clone();

    if let Some(p) = profile {
        if let Some(host) = &p.host {
            cfg.host = host.clone();
        }
        if let Some(port) = p.port {
            cfg.port = port;
        }
        if let Some(use_tls) = p.use_tls {
            cfg.use_tls = use_tls;
        }
        if let Some(retries) = p.retries {
            cfg.retries = retries;
        }
        if let Some(tags) = &p.tags {
            cfg.tags = tags.clone();
        }
    }

    if let Some(e) = env {
        if let Some(host) = &e.host {
            cfg.host = host.clone();
        }
        if let Some(use_tls) = e.use_tls {
            cfg.use_tls = use_tls;
        }
        if let Some(retries) = e.retries {
            cfg.retries = retries;
        }
        if let Some(tags) = &e.tags {
            cfg.tags.extend(tags.clone());
        }
    }

    if force_tls {
        cfg.use_tls = false;
    }

    cfg
}

