#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Booking {
    pub start: u32,
    pub end: u32,
    pub canceled: bool,
}

impl Booking {
    pub fn new(start: u32, end: u32) -> Self {
        Self {
            start,
            end,
            canceled: false,
        }
    }
}

pub fn can_book(existing: &[Booking], candidate: Booking) -> bool {
    if candidate.start > candidate.end {
        return true;
    }

    for b in existing {
        if b.canceled {
            continue;
        }

        if candidate.start <= b.end && b.start <= candidate.end {
            return false;
        }
    }

    true
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn adjacent_ranges_do_not_conflict() {
        let existing = vec![Booking::new(10, 20)];
        assert!(can_book(&existing, Booking::new(20, 25)));
        assert!(can_book(&existing, Booking::new(5, 10)));
    }

    #[test]
    fn overlapping_ranges_conflict() {
        let existing = vec![Booking::new(10, 20)];
        assert!(!can_book(&existing, Booking::new(19, 25)));
        assert!(!can_book(&existing, Booking::new(5, 11)));
        assert!(!can_book(&existing, Booking::new(12, 18)));
    }

    #[test]
    fn canceled_bookings_are_ignored() {
        let mut b = Booking::new(10, 20);
        b.canceled = true;
        let existing = vec![b];
        assert!(can_book(&existing, Booking::new(15, 18)));
    }

    #[test]
