pub struct Entry {
    pub team: &'static str,
    pub person: &'static str,
    pub hours: u32,
    pub billable: bool,
}

pub fn build_report(entries: &[Entry]) -> String {
    let mut rows: Vec<(&str, usize, u32)> = Vec::new();

    for entry in entries {
        if !entry.billable {
            continue;
        }

        if let Some((_, people, hours)) = rows.iter_mut().find(|(team, _, _)| *team == entry.team) {
            *people += 1;
            *hours += entry.hours;
        } else {
            rows.push((entry.team, 1, entry.hours));
        }
    }

    rows.sort_by(|a, b| a.0.cmp(b.0));

    let mut out = String::new();
    for (team, people, hours) in rows {
        out.push_str(&format!("{}: {} people, {}h\n", team, people, hours));
    }
    out
}

