#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    StartWork,
    Resolve,
    Close,
    Reopen,
}

pub fn apply_event(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::Open, Event::StartWork) => Status::Open,
        (Status::Open, Event::Resolve) => Status::Resolved,
        (Status::InProgress, Event::Resolve) => Status::Closed,
        (Status::Resolved, Event::Close) => Status::Closed,
        (Status::Closed, Event::Reopen) => Status::Open,
        (s, _) => s,
    }
}

pub fn apply_events(mut status: Status, events: &[Event]) -> Status {
    for &event in events {
        status = apply_event(status, event);
    }
    status
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn start_work_moves_open_to_in_progress() {
        assert_eq!(apply_event(Status::Open, Event::StartWork), Status::InProgress);
    }

    #[test]
    fn resolve_does_not_skip_close_step() {
        assert_eq!(apply_event(Status::InProgress, Event::Resolve), Status::Resolved);
    }

    #[test]
    fn reopen_from_closed_returns_to_in_progress() {
        assert_eq!(apply_event(Status::Closed, Event::Reopen), Status::InProgress);
    }

    #[test]
    fn illegal_transitions_leave_state_unchanged() {
        assert_eq!(apply_event(Status::Open, Event::Close), Status::Open);
        assert_eq!(apply_event(Status::Resolved, Event::StartWork), Status::Resolved);
    }

    #[test]
    fn event_sequence_uses_all_transition_rules() {
        let events = [
            Event::StartWork,
            Event::Resolve,
            Event::Close,
            Event::Reopen,
            Event::Resolve,
        ];
        assert_eq!(apply_events(Status::Open, &events), Status::Resolved);
    }
}

pub fn summarize_inventory(lines: &[&str]) -> Vec<String> {
    let mut rows: Vec<(String, i32)> = lines
        .iter()
        .filter_map(|line| {
            let mut parts = line.split('|');
            let category = parts.next()?;
            let active = parts.next()?;
            let qty = parts.next()?.parse::<i32>().ok()?;
            let name = parts.next()?;

            if active != "yes" {
                return None;
            }
            if qty < 0 {
                return None;
            }
            if category == "archived" {
                return None;
            }

            Some((format!("{}:{}", category, name), qty))
        })
        .collect();

    rows.sort_by(|a, b| a.0.cmp(&b.0));

    rows.into_iter()
        .map(|(label, qty)| format!("{}={}", label, qty))
        .collect()
}

