pub struct Config {
    pub host: String,
    pub port: u16,
    pub tls: bool,
    pub retries: u8,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub tls: Option<bool>,
    pub retries: Option<u8>,
}

pub fn merge_config(
    defaults: &Config,
    file: Option<&PartialConfig>,
    env: Option<&PartialConfig>,
    cli: Option<&PartialConfig>,
) -> Config {
    let mut merged = defaults.clone();

    if let Some(layer) = cli {
        apply_layer(&mut merged, layer);
    }
    if let Some(layer) = env {
        apply_layer(&mut merged, layer);
    }
    if let Some(layer) = file {
        apply_layer(&mut merged, layer);
    }

    merged
}

fn apply_layer(out: &mut Config, layer: &PartialConfig) {
    if let Some(host) = &layer.host {
        out.host = host.clone();
    }
    if let Some(port) = layer.port {
        out.port = port;
    }
    if let Some(tls) = layer.tls {
        if tls {
            out.tls = true;
        }
    }
    if let Some(retries) = layer.retries {
        if retries > 0 {
            out.retries = retries;
        }
    }
}

