#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Booking {
    pub start: u32,
    pub end: u32,
}

impl Booking {
    pub fn new(start: u32, end: u32) -> Self {
        Self { start, end }
    }
}

pub fn can_book(existing: &[Booking], candidate: Booking) -> bool {
    if candidate.start > candidate.end {
        return true;
    }

    for b in existing {
        if overlaps(*b, candidate) {
            return false;
        }
    }

    true
}

fn overlaps(a: Booking, b: Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

pub fn conflicting_bookings(existing: &[Booking], candidate: Booking) -> Vec<Booking> {
    let mut out = Vec::new();
    for b in existing {
        if overlaps(*b, candidate) {
            out.push(*b);
        }
    }
    out
}

pub fn normalize_booking(mut booking: Booking) -> Booking {
    if booking.start > booking.end {
        booking.start = booking.end;
    }
    booking
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn back_to_back_bookings_do_not_conflict() {
        let existing = [Booking::new(10, 20), Booking::new(25, 30)];
        assert!(can_book(&existing, Booking::new(20, 25)));
        assert_eq!(conflicting_bookings(&existing, Booking::new(20, 25)), vec![]);
    }

    #[test]
    fn interior_overlap_blocks_booking() {
        let existing = [Booking::new(10, 20), Booking::new(30, 40)];
        assert!(!can_book(&existing, Booking::new(12, 18)));
        assert_eq!(conflicting_bookings(&existing, Booking::new(12, 18)), vec![Booking::new(10, 20)]);
    }

    #[test]
    fn spanning_candidate_collects_all_conflicts_in_input_order() {
        let existing = [Booking::new(40, 50), Booking::new(10, 20), Booking::new(25, 35)];
        let conflicts = conflicting_bookings(&existing, Booking::new(15, 45));
        assert_eq!(conflicts, vec![Booking::new(40, 50), Booking::new(10, 20), Booking::new(25, 35)]);
    }

    #[test]
    fn touching_zero_length_booking_at_edge_is_allowed() {
        let existing = [Booking::new(5, 10)];
        assert!(can_book(&existing, Booking::new(10, 10)));
        assert_eq!(conflicting_bookings(&existing, Booking::new(10, 10)), vec![]);
    }

