#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Priority {
    Low,
    Normal,
    High,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Message { urgent: bool, retries: u8 },
    Timeout { elapsed_secs: u64 },
    Disconnect { graceful: bool },
    Error { code: u16, transient: bool },
}

pub fn action_for(event: Event, priority: Priority) -> &'static str {
    match event {
        Event::Message { urgent, retries } => {
            if retries > 0 {
                "queue"
            } else if urgent {
                "queue"
            } else {
                "deliver"
            }
        }
        Event::Timeout { elapsed_secs } => {
            if elapsed_secs >= 30 {
                "drop"
            } else {
                "wait"
            }
        }
        Event::Disconnect { graceful } => {
            if graceful {
                "alert"
            } else {
                "close"
            }
        }
        Event::Error { code, transient } => {
            if transient {
                "retry"
            } else if code >= 500 {
                "ignore"
            } else {
                "alert"
            }
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn message_branch_respects_urgent_retries_and_priority() {
        assert_eq!(action_for(Event::Message { urgent: false, retries: 0 }, Priority::Normal), "deliver");
        assert_eq!(action_for(Event::Message { urgent: true, retries: 0 }, Priority::Low), "expedite");
        assert_eq!(action_for(Event::Message { urgent: false, retries: 2 }, Priority::Normal), "retry");
        assert_eq!(action_for(Event::Message { urgent: true, retries: 3 }, Priority::High), "escalate");
    }

    #[test]
    fn timeout_branch_uses_priority_thresholds() {
        assert_eq!(action_for(Event::Timeout { elapsed_secs: 29 }, Priority::Normal), "wait");
        assert_eq!(action_for(Event::Timeout { elapsed_secs: 30 }, Priority::Low), "drop");
        assert_eq!(action_for(Event::Timeout { elapsed_secs: 20 }, Priority::High), "alert");
    }

    #[test]
    fn disconnect_branch_maps_graceful_and_ungraceful() {
        assert_eq!(action_for(Event::Disconnect { graceful: true }, Priority::Low), "close");
        assert_eq!(action_for(Event::Disconnect { graceful: false }, Priority::Normal), "alert");
    }

    #[test]
    fn error_branch_distinguishes_transient_server_and_client_cases() {
        assert_eq!(action_for(Event::Error { code: 404, transient: false }, Priority::Normal), "ignore");
        assert_eq!(action_for(Event::Error { code: 503, transient: false }, Priority::Normal), "alert");
        assert_eq!(action_for(Event::Error { code: 429, transient: true }, Priority::Normal), "retry");
        assert_eq!(action_for(Event::Error { code: 503, transient: true }, Priority::High), "escalate");
    }
}

