            .cmp(&b.points)
            .then(a.goal_diff.cmp(&b.goal_diff))
            .then(a.goals_for.cmp(&b.goals_for))
            .then(a.name.cmp(&b.name))
    });

    items
        .into_iter()
        .enumerate()
        .map(|(idx, t)| format!("{}. {} ({})", idx + 1, t.name, t.points))
        .collect()
}

