use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale<'a> {
    pub dept: &'a str,
    pub rep: &'a str,
    pub amount: i32,
    pub refunded: bool,
}

pub fn summarize_sales(sales: &[Sale<'_>]) -> Vec<String> {
    let mut by_dept: BTreeMap<&str, (i32, usize)> = BTreeMap::new();

    for sale in sales {
        let entry = by_dept.entry(sale.dept).or_insert((0, 0));
        if sale.refunded {
            entry.0 += sale.amount;
        } else {
            entry.0 += sale.amount;
            entry.1 += 1;
        }
    }

    let mut lines = Vec::new();
    for (dept, (total, count)) in by_dept {
        let avg = if count == 0 { 0 } else { total / count as i32 };
        lines.push(format!("{dept}: total={total}, sales={count}, avg={avg}"));
    }
    lines
}

#[cfg(test)]
