    #[test]
    fn groups_departments_and_reports_totals() {
        let sales = [
            Sale { dept: "Books", rep: "Ann", amount: 30, refunded: false },
            Sale { dept: "Games", rep: "Ben", amount: 50, refunded: false },
            Sale { dept: "Books", rep: "Ann", amount: 10, refunded: true },
            Sale { dept: "Books", rep: "Cara", amount: 25, refunded: false },
        ];

        let lines = summarize_sales(&sales);
        assert_eq!(lines, vec![
            "Books: total=45, sales=2, avg=22",
            "Games: total=50, sales=1, avg=50",
        ]);
    }

    #[test]
    fn excludes_departments_with_no_non_refunded_sales() {
        let sales = [
            Sale { dept: "Garden", rep: "Di", amount: 40, refunded: true },
            Sale { dept: "Electronics", rep: "Eli", amount: 90, refunded: false },
        ];

        let lines = summarize_sales(&sales);
        assert_eq!(lines, vec!["Electronics: total=90, sales=1, avg=90"]);
    }

    #[test]
    fn sorts_by_total_desc_then_department_name() {
        let sales = [
            Sale { dept: "Clothing", rep: "A", amount: 40, refunded: false },
            Sale { dept: "Books", rep: "B", amount: 40, refunded: false },
            Sale { dept: "Games", rep: "C", amount: 70, refunded: false },
        ];

        let lines = summarize_sales(&sales);
        assert_eq!(lines, vec![
            "Games: total=70, sales=1, avg=70",
            "Books: total=40, sales=1, avg=40",
            "Clothing: total=40, sales=1, avg=40",
        ]);
    }

