#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub endpoint: String,
    pub timeout_ms: u32,
    pub retries: u8,
    pub headers: Vec<(String, String)>,
    pub features: Vec<String>,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub endpoint: Option<String>,
    pub timeout_ms: Option<u32>,
    pub retries: Option<u8>,
    pub headers: Option<Vec<(String, String)>>,
    pub features: Option<Vec<String>>,
    pub clear_features: bool,
}

pub fn merge_config(
    base: &Config,
    env: Option<&PartialConfig>,
    profile: Option<&PartialConfig>,
    cli: Option<&PartialConfig>,
) -> Config {
    let mut out = base.clone();

    for layer in [env, profile, cli] {
        if let Some(layer) = layer {
            if let Some(v) = &layer.endpoint {
                out.endpoint = v.clone();
            }
            if let Some(v) = layer.timeout_ms {
                out.timeout_ms = v;
            }
            if let Some(v) = layer.retries {
                out.retries = v;
            }
            if let Some(v) = &layer.headers {
                out.headers.extend(v.clone());
            }
            if layer.clear_features {
                out.features = base.features.clone();
            }
            if let Some(v) = &layer.features {
                out.features.extend(v.clone());
            }
        }
    }

    out
}

