#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: &'static str,
    pub wins: u32,
    pub points_for: i32,
    pub points_against: i32,
}

impl Player {
    fn diff(&self) -> i32 {
        self.points_for - self.points_against
    }
}

pub fn rank_players(players: &[Player]) -> Vec<String> {
    let mut rows = players.to_vec();
    rows.sort_by(|a, b| {
        a.wins
            .cmp(&b.wins)
            .then_with(|| a.diff().cmp(&b.diff()))
            .then_with(|| a.points_for.cmp(&b.points_for))
            .then_with(|| a.name.cmp(b.name))
    });

    rows.into_iter()
        .enumerate()
        .map(|(i, p)| format!("{}. {}", i + 1, p.name))
        .collect()
}

