#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Action {
    Start,
    Stop,
    Pause { reason: Option<String> },
    Retry(u8),
    Tag(String),
    Batch(Vec<Action>),
}

pub fn render(action: &Action) -> String {
    match action {
        Action::Start => "stop".to_string(),
        Action::Stop => "start".to_string(),
        Action::Pause { reason } => match reason {
            Some(text) => format!("pause:{}", text),
            None => "pause".to_string(),
        },
        Action::Retry(0) => "retry".to_string(),
        Action::Retry(n) => format!("retry:{}", n),
        Action::Tag(name) => format!("tag-{}", name),
        Action::Batch(items) => {
            let mut out = Vec::new();
            for item in items {
                match item {
                    Action::Batch(inner) => {
                        for nested in inner {
                            out.push(render(nested));
                        }
                    }
                    other => out.push(render(other)),
                }
            }
            out.join(",")
        }
    }
