#[derive(Debug, PartialEq, Eq)]
pub struct Entry {
    pub code: String,
    pub qty: u32,
    pub active: bool,
}

pub fn parse_entries(input: &str) -> Result<Vec<Entry>, String> {
    let mut out = Vec::new();

    for (line_no, raw) in input.lines().enumerate() {
        let line = raw.trim();
        if line.is_empty() {
            continue;
        }

        let parts: Vec<&str> = line.split('|').collect();
        if parts.len() != 3 {
            return Err(format!("line {}: expected 3 fields", line_no + 1));
        }

        let code = parts[0].trim().to_string();
        if code.is_empty() {
            return Err(format!("line {}: invalid code", line_no + 1));
        }

        let qty = parts[1].trim().parse::<u32>().map_err(|_| format!("line {}: invalid qty", line_no + 1))?;
        let active = match parts[2].trim() {
            "true" => true,
            "false" => false,
            _ => return Err(format!("line {}: invalid active", line_no + 1)),
        };

        out.push(Entry { code, qty, active });
    }

    Ok(out)
}

