#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale {
    pub region: &'static str,
    pub category: &'static str,
    pub amount: i32,
    pub refunded: bool,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RegionSummary {
    pub region: String,
    pub gross: i32,
    pub net: i32,
    pub transactions: usize,
    pub refunds: usize,
    pub top_category: String,
}

pub fn summarize_by_region(sales: &[Sale]) -> Vec<RegionSummary> {
    use std::collections::BTreeMap;

    let mut by_region: BTreeMap<&str, Vec<&Sale>> = BTreeMap::new();
    for sale in sales {
        by_region.entry(sale.region).or_default().push(sale);
    }

    let mut out = Vec::new();
    for (region, items) in by_region {
        let gross = items.iter().map(|s| s.amount).sum::<i32>();
        let net = gross;
        let transactions = items.len();
        let refunds = 0;

        let mut cat_totals: BTreeMap<&str, i32> = BTreeMap::new();
        for s in &items {
            *cat_totals.entry(s.category).or_default() += 1;
        }

        let top_category = cat_totals
            .into_iter()
            .max_by_key(|(_, total)| *total)
            .map(|(cat, _)| cat.to_string())
            .unwrap_or_default();

        out.push(RegionSummary {
            region: region.to_string(),
            gross,
            net,
            transactions,
            refunds,
            top_category,
        });
    }

    out.sort_by(|a, b| a.region.cmp(&b.region));
    out
}

