#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    New,
    InProgress,
    Blocked,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Block,
    Unblock,
    Resolve,
    Reopen,
    Close,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::New;

    for event in events {
        status = match (status, event) {
            (Status::New, Event::Start) => Status::InProgress,
            (Status::New, Event::Close) => Status::Closed,
            (Status::InProgress, Event::Block) => Status::Blocked,
            (Status::InProgress, Event::Resolve) => Status::Resolved,
            (Status::InProgress, Event::Close) => Status::Closed,
            (Status::Blocked, Event::Resolve) => Status::Resolved,
            (Status::Blocked, Event::Close) => Status::Closed,
            (Status::Resolved, Event::Reopen) => Status::New,
            (Status::Resolved, Event::Close) => Status::Closed,
            (Status::Closed, Event::Reopen) => Status::InProgress,
            _ => status,
        };
    }

    status
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event, Status};

    #[test]
    fn starts_work_from_new() {
        assert_eq!(apply_events(&[Event::Start]), Status::InProgress);
    }

    #[test]
    fn unblock_returns_to_in_progress() {
        assert_eq!(
            apply_events(&[Event::Start, Event::Block, Event::Unblock]),
            Status::InProgress
        );
    }

    #[test]
    fn blocked_ticket_cannot_resolve_directly() {
        assert_eq!(
            apply_events(&[Event::Start, Event::Block, Event::Resolve]),
            Status::Blocked
        );
    }

    #[test]
    fn close_requires_resolution() {
        assert_eq!(apply_events(&[Event::Close]), Status::New);
        assert_eq!(
            apply_events(&[Event::Start, Event::Close]),
            Status::InProgress
        );
    }

    #[test]
    fn reopen_from_resolved_goes_to_in_progress() {
        assert_eq!(
            apply_events(&[Event::Start, Event::Resolve, Event::Reopen]),
            Status::InProgress
        );
    }

    #[test]
    fn closed_ticket_stays_closed_even_if_reopened() {
        assert_eq!(
            apply_events(&[Event::Start, Event::Resolve, Event::Close, Event::Reopen]),
            Status::Closed
        );
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Action {
    Create,
    Update,
    Delete,
    Archive,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Mode {
    Strict,
    Lenient,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    New,
    Existing,
    Missing,
    Archived,
}

pub fn outcome(action: Action, mode: Mode, status: Status, dry_run: bool) -> &'static str {
    match action {
        Action::Create => match (status, dry_run) {
            (Status::Missing, false) => "created",
            (Status::Missing, true) => "would_create",
            (Status::New, _) => "noop",
            (Status::Existing, Mode::Strict == mode) if !dry_run => "error_exists",
            (Status::Existing, _) => "noop",
            (Status::Archived, _) => "error_archived",
        },
        Action::Update => match status {
            Status::Existing => {
                if dry_run { "would_update" } else { "updated" }
            }
            Status::New => "updated",
            Status::Missing => {
                if mode == Mode::Lenient { "noop" } else { "error_missing" }
            }
            Status::Archived => "updated",
        },
        Action::Delete => match (status, mode, dry_run) {
            (Status::Existing, _, true) => "would_delete",
            (Status::Existing, _, false) => "deleted",
            (Status::Missing, Mode::Lenient, _) => "noop",
            (Status::Missing, Mode::Strict, _) => "error_missing",
            (Status::Archived, _, _) => "noop",
            (Status::New, _, _) => "deleted",
        },
        Action::Archive => match status {
            Status::Existing => if dry_run { "would_archive" } else { "archived" },
            Status::Archived => "noop",
            Status::Missing => "error_missing",
            Status::New => "archived",
        },
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn create_behavior() {
        assert_eq!(outcome(Action::Create, Mode::Strict, Status::Missing, false), "created");
        assert_eq!(outcome(Action::Create, Mode::Strict, Status::Missing, true), "would_create");
        assert_eq!(outcome(Action::Create, Mode::Strict, Status::Existing, false), "error_exists");
        assert_eq!(outcome(Action::Create, Mode::Lenient, Status::Existing, false), "noop");
        assert_eq!(outcome(Action::Create, Mode::Lenient, Status::Archived, true), "error_archived");
    }

    #[test]
    fn update_behavior() {
        assert_eq!(outcome(Action::Update, Mode::Strict, Status::Existing, false), "updated");
        assert_eq!(outcome(Action::Update, Mode::Strict, Status::Existing, true), "would_update");
        assert_eq!(outcome(Action::Update, Mode::Strict, Status::Missing, false), "error_missing");
        assert_eq!(outcome(Action::Update, Mode::Lenient, Status::Missing, true), "noop");
        assert_eq!(outcome(Action::Update, Mode::Lenient, Status::Archived, false), "error_archived");
    }

    #[test]
    fn delete_behavior() {
        assert_eq!(outcome(Action::Delete, Mode::Strict, Status::Existing, false), "deleted");
        assert_eq!(outcome(Action::Delete, Mode::Lenient, Status::Existing, true), "would_delete");
        assert_eq!(outcome(Action::Delete, Mode::Lenient, Status::Missing, false), "noop");
