#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Booking {
    pub start: u32,
    pub end: u32,
}

#[derive(Debug, Default)]
pub struct Calendar {
    bookings: Vec<Booking>,
}

impl Calendar {
    pub fn new() -> Self {
        Self { bookings: Vec::new() }
    }

    pub fn book(&mut self, start: u32, end: u32) -> bool {
        if start > end {
            return false;
        }

        let next = Booking { start, end };
        if self.bookings.iter().any(|b| overlaps(*b, next)) {
            return false;
        }

        self.bookings.push(next);
        self.bookings.sort_by_key(|b| b.start);
        true
    }

    pub fn booking_count(&self) -> usize {
        self.bookings.len()
    }

    pub fn bookings(&self) -> &[Booking] {
        &self.bookings
    }

    pub fn free_gaps(&self, window_start: u32, window_end: u32) -> Vec<Booking> {
        if window_start >= window_end {
            return Vec::new();
        }

        let mut gaps = Vec::new();
        let mut cursor = window_start;

        for b in &self.bookings {
            if b.end < window_start || b.start > window_end {
                continue;
            }

            if cursor < b.start {
                gaps.push(Booking {
                    start: cursor,
                    end: b.start,
                });
            }

            if b.end > cursor {
                cursor = b.end;
            }
        }

        if cursor < window_end {
            gaps.push(Booking {
                start: cursor,
                end: window_end,
            });
        }

        gaps
    }
}

fn overlaps(a: Booking, b: Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn allows_back_to_back_half_open_bookings() {
        let mut cal = Calendar::new();
        assert!(cal.book(10, 20));
        assert!(cal.book(20, 30));
        assert_eq!(cal.booking_count(), 2);
    }

    #[test]
    fn rejects_true_overlap_inside_existing() {
        let mut cal = Calendar::new();
        assert!(cal.book(10, 20));
        assert!(!cal.book(12, 18));
        assert_eq!(cal.booking_count(), 1);
    }

    #[test]
    fn rejects_zero_length_booking() {
        let mut cal = Calendar::new();
        assert!(!cal.book(15, 15));
        assert_eq!(cal.booking_count(), 0);
    }

    #[test]
    fn gaps_are_clipped_to_window_and_ignore_outside_bookings() {
        let mut cal = Calendar::new();
        assert!(cal.book(5, 10));
        assert!(cal.book(15, 18));
        assert!(cal.book(30, 40));

        let gaps = cal.free_gaps(8, 35);
        assert_eq!(
            gaps,
            vec![
                Booking { start: 10, end: 15 },
                Booking { start: 18, end: 30 },
            ]
        );
    }

    #[test]
    fn full_window_covered_means_no_gaps() {
        let mut cal = Calendar::new();
        assert!(cal.book(10, 20));
        assert!(cal.book(20, 25));

        let gaps = cal.free_gaps(12, 24);
        assert!(gaps.is_empty());
    }
}

