use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ReportRow {
    pub region: String,
    pub orders: usize,
    pub shipped_qty: u32,
    pub revenue_cents: u32,
}

pub fn summarize_sales(input: &str) -> Vec<ReportRow> {
    let mut map: BTreeMap<String, ReportRow> = BTreeMap::new();

    for line in input.lines() {
        let line = line.trim();
        if line.is_empty() {
            continue;
        }

        let mut parts = line.split('|');
        let region = parts.next().unwrap_or("").trim();
        let status = parts.next().unwrap_or("").trim();
        let qty = parts.next().unwrap_or("0").trim().parse::<u32>().unwrap_or(0);
        let price = parts.next().unwrap_or("0").trim().parse::<u32>().unwrap_or(0);

        let row = map.entry(region.to_string()).or_insert_with(|| ReportRow {
            region: region.to_string(),
            orders: 0,
            shipped_qty: 0,
            revenue_cents: 0,
        });

        row.orders += 1;
        row.shipped_qty += qty;
        row.revenue_cents += qty * price;

        if status == "returned" {
            row.revenue_cents = row.revenue_cents.saturating_sub(qty * price);
        }
    }

    let mut rows: Vec<_> = map.into_values().collect();
    rows.sort_by(|a, b| a.region.cmp(&b.region));
    rows
}

