#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Draft,
    Ready,
    InProgress,
    Blocked,
    Done,
    Archived,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Submit,
    Start,
    Block,
    Unblock,
    Complete,
    Archive,
    Reopen,
}

pub fn apply_event(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::Draft, Event::Submit) => Status::InProgress,
        (Status::Ready, Event::Start) => Status::InProgress,
        (Status::InProgress, Event::Block) => Status::Blocked,
        (Status::Blocked, Event::Unblock) => Status::Draft,
        (Status::InProgress, Event::Complete) => Status::Archived,
        (Status::Done, Event::Archive) => Status::Archived,
        (Status::Done, Event::Reopen) => Status::Ready,
        (Status::Archived, Event::Reopen) => Status::Draft,
        _ => status,
    }
}

pub fn apply_events(initial: Status, events: &[Event]) -> Status {
    let mut status = Status::Draft;
    for &event in events {
        status = apply_event(status, event);
    }
    status
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn submit_moves_draft_to_ready() {
        assert_eq!(apply_event(Status::Draft, Event::Submit), Status::Ready);
    }

    #[test]
    fn complete_moves_in_progress_to_done() {
        assert_eq!(apply_event(Status::InProgress, Event::Complete), Status::Done);
    }

    #[test]
    fn unblock_restores_ready_state() {
        assert_eq!(apply_event(Status::Blocked, Event::Unblock), Status::Ready);
    }

    #[test]
    fn archived_reopen_goes_to_ready() {
        assert_eq!(apply_event(Status::Archived, Event::Reopen), Status::Ready);
    }

    #[test]
    fn apply_events_uses_provided_initial_state() {
        let events = [Event::Complete];
        assert_eq!(apply_events(Status::InProgress, &events), Status::Done);
    }

    #[test]
    fn full_happy_path_reaches_archived() {
        let events = [Event::Submit, Event::Start, Event::Complete, Event::Archive];
        assert_eq!(apply_events(Status::Draft, &events), Status::Archived);
    }

    #[test]
    fn blocked_then_unblocked_can_finish() {
        let events = [Event::Submit, Event::Start, Event::Block, Event::Unblock, Event::Start, Event::Complete];
        assert_eq!(apply_events(Status::Draft, &events), Status::Done);
    }

    #[test]
    fn reopen_after_archive_requires_restart() {
        let events = [Event::Submit, Event::Start, Event::Complete, Event::Archive, Event::Reopen, Event::Start, Event::Complete];
        assert_eq!(apply_events(Status::Draft, &events), Status::Done);
    }
}

pub struct Record<'a> {
    pub active: bool,
    pub tag: &'a str,
    pub label: &'a str,
    pub value: &'a str,
}

pub fn select_values(records: &[Record], wanted_tag: &str) -> Vec<String> {
    records
        .iter()
        .filter(|r| !r.active || r.tag != wanted_tag)
        .map(|r| (r.label, r.value.parse::<i32>().unwrap_or(0)))
        .filter(|(_, n)| *n >= 0)
        .map(|(label, n)| format!("{}={}", label, n))
        .collect()
}

