pub fn parse_valid_ids(input: &str) -> Vec<String> {
    let mut out = Vec::new();
    for line in input.lines() {
        let line = line.trim();
        if line.is_empty() {
            continue;
        }

        let mut id = None;
        let mut qty = None;
        let mut active = None;
        let mut malformed = false;

        for part in line.split(';') {
            let mut kv = part.splitn(2, '=');
            let key = kv.next().unwrap_or("");
            let value = kv.next().unwrap_or("");
            match key {
                "id" => id = Some(value.to_string()),
                "qty" => qty = value.parse::<u32>().ok(),
                "active" => active = Some(value == "true"),
                _ => malformed = true,
            }
        }

        if malformed {
            continue;
        }

        if let (Some(id), Some(qty), Some(active)) = (id, qty, active) {
            if active && qty > 0 {
                out.push(id);
            }
        }
    }
    out
}

