use std::collections::BTreeMap;

#[derive(Clone, Debug)]
pub struct Sale<'a> {
    pub region: &'a str,
    pub amount: i32,
    pub refunded: bool,
}

pub fn build_report(sales: &[Sale<'_>]) -> String {
    let mut totals: BTreeMap<&str, (i32, usize, usize)> = BTreeMap::new();

    for sale in sales {
        let entry = totals.entry(sale.region).or_insert((0, 0, 0));
        entry.0 += sale.amount;
        entry.1 += 1;
        if sale.refunded {
            entry.2 += 1;
        }
    }

    let mut lines = Vec::new();
    for (region, (net, orders, refunds)) in totals {
        lines.push(format!("{} | net={} | orders={} | refunds={}", region, net, orders, refunds));
    }

    let grand_total: i32 = sales.iter().map(|s| s.amount).sum();
    lines.push(format!("TOTAL | net={} | regions={}", grand_total, lines.len()));
    lines.join("\n")
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn groups_regions_sorts_and_adds_total() {
        let sales = [
            Sale { region: "west", amount: 120, refunded: false },
            Sale { region: "east", amount: 80, refunded: false },
            Sale { region: "west", amount: 20, refunded: true },
            Sale { region: "north", amount: 50, refunded: false },
            Sale { region: "east", amount: 10, refunded: true },
        ];

        let report = build_report(&sales);
        let expected = "east | net=70 | orders=1 | refunds=1\nnorth | net=50 | orders=1 | refunds=0\nwest | net=100 | orders=1 | refunds=1\nTOTAL | net=220 | regions=3";
        assert_eq!(report, expected);
    }

    #[test]
    fn skips_zero_net_regions_but_keeps_total_from_positive_sales() {
        let sales = [
            Sale { region: "south", amount: 30, refunded: false },
            Sale { region: "south", amount: 30, refunded: true },
            Sale { region: "east", amount: 40, refunded: false },
        ];

        let report = build_report(&sales);
        let expected = "east | net=40 | orders=1 | refunds=0\nTOTAL | net=70 | regions=1";
        assert_eq!(report, expected);
    }

    #[test]
    fn empty_input_reports_only_zero_total() {
        let report = build_report(&[]);
        assert_eq!(report, "TOTAL | net=0 | regions=0");
    }
}

