pub fn collect_visible_metrics(lines: &[&str]) -> Vec<String> {
    let mut out: Vec<String> = lines
        .iter()
        .filter_map(|line| {
            let line = line.trim();
            if line.is_empty() || line.starts_with('#') {
                return None;
            }

            let (key, value) = line.split_once('=')?;
            let key = key.trim();
            let value = value.trim();

            if key.is_empty() {
                return None;
            }

            let num: i32 = value.parse().ok()?;
            if num < 0 {
                return None;
            }

            Some(format!("{}:{}", key, num))
        })
        .collect();

    out.sort();
    out
}

