#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Booking {
    pub room: String,
    pub start: u32,
    pub end: u32,
    pub canceled: bool,
}

impl Booking {
    pub fn new(room: &str, start: u32, end: u32) -> Self {
        Self {
            room: room.to_string(),
            start,
            end,
            canceled: false,
        }
    }
}

pub fn validate_booking(b: &Booking) -> bool {
    b.start <= b.end
}

pub fn overlaps(a: &Booking, b: &Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

pub fn can_schedule(existing: &[Booking], candidate: &Booking) -> bool {
    if !validate_booking(candidate) {
        return false;
    }

    for current in existing {
        if overlaps(current, candidate) {
            return false;
        }
    }

    true
}

pub fn conflicting_rooms(existing: &[Booking], candidate: &Booking) -> Vec<String> {
    let mut rooms = Vec::new();
    for current in existing {
        if overlaps(current, candidate) {
            rooms.push(current.room.clone());
        }
    }
    rooms.sort();
    rooms
}

