        let existing = vec![Booking::new("A", 10, 20)];
        let candidate = Booking::new("A", 19, 22);
        assert!(!can_schedule(&existing, &candidate));
        assert_eq!(conflicting_rooms(&existing, &candidate), vec!["A"]);
    }

