#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: String,
    pub wins: u32,
    pub losses: u32,
}

pub fn leaderboard(players: &[Player]) -> Vec<(usize, String)> {
    let mut items = players.to_vec();
    items.sort_by(|a, b| {
        a.wins
            .cmp(&b.wins)
            .then(a.losses.cmp(&b.losses))
            .then(b.name.cmp(&a.name))
    });

    items
        .into_iter()
        .enumerate()
        .map(|(idx, p)| (idx, p.name))
        .collect()
}

