use std::collections::BTreeMap;

#[derive(Clone, Debug)]
pub struct Order {
    pub category: &'static str,
    pub units: u32,
    pub unit_price_cents: u32,
    pub shipped: bool,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct CategorySummary {
    pub orders: u32,
    pub units: u32,
    pub revenue_cents: u32,
}

pub fn weekly_report(orders: &[Order]) -> String {
    let mut groups: BTreeMap<&str, CategorySummary> = BTreeMap::new();

    for order in orders {
        let entry = groups.entry(order.category).or_insert(CategorySummary {
            orders: 0,
            units: 0,
            revenue_cents: 0,
        });
        entry.orders += 1;
        entry.units += 1;
        entry.revenue_cents += order.unit_price_cents;
    }

    let mut out = String::from("category | orders | units | revenue\n");
    let mut total_orders = 0;
    let mut total_units = 0;
    let mut total_revenue = 0;

    for (category, summary) in groups {
        total_orders += summary.orders;
        total_units += summary.units;
        total_revenue += summary.revenue_cents;
        out.push_str(&format!(
            "{} | {} | {} | ${}.{:02}\n",
            category,
            summary.orders,
            summary.units,
            summary.revenue_cents / 100,
            summary.revenue_cents % 100
        ));
    }

    out.push_str(&format!(
        "TOTAL | {} | {} | ${}.{:02}",
        total_orders,
        total_units,
        total_revenue / 100,
        total_revenue % 100
    ));

    out
}

