pub fn collect_tags(input: &[&str]) -> Vec<String> {
    input
        .iter()
        .filter_map(|raw| {
            let trimmed = raw.trim();
            if trimmed.is_empty() || trimmed.starts_with('#') {
                return None;
            }

            let body = if let Some((_, rest)) = trimmed.split_once(':') {
                rest
            } else {
                trimmed
            };

            let tag = body.trim();
            if tag.len() < 3 {
                return None;
