#[derive(Clone, Debug, Default, PartialEq, Eq)]
pub struct Config {
    pub endpoint: Option<String>,
    pub retries: Option<u8>,
    pub timeout_ms: Option<u32>,
    pub feature_enabled: Option<bool>,
    pub tags: Vec<String>,
}

pub fn merge_config(
    defaults: &Config,
    profile: Option<&Config>,
    env: Option<&Config>,
    override_cfg: Option<&Config>,
) -> Config {
    let mut out = defaults.clone();

    if let Some(p) = profile {
        if p.endpoint.is_some() {
            out.endpoint = p.endpoint.clone();
        }
        if p.retries.is_some() {
            out.retries = p.retries;
        }
        if p.timeout_ms.is_some() {
            out.timeout_ms = p.timeout_ms;
        }
        if p.feature_enabled.is_some() {
            out.feature_enabled = p.feature_enabled;
        }
        if !p.tags.is_empty() {
            out.tags = p.tags.clone();
        }
    }

    if let Some(e) = env {
        if e.endpoint.is_some() {
            out.endpoint = e.endpoint.clone();
        }
        if e.retries.is_some() {
            out.retries = e.retries;
        }
        if e.timeout_ms.is_some() {
            out.timeout_ms = e.timeout_ms;
        }
        if e.feature_enabled == Some(true) {
            out.feature_enabled = e.feature_enabled;
        }
        if !e.tags.is_empty() {
            out.tags.extend(e.tags.clone());
        }
    }

    if let Some(o) = override_cfg {
        if o.endpoint.is_some() {
            out.endpoint = o.endpoint.clone();
        }
        if o.retries.is_some() {
            out.retries = o.retries;
        }
        if o.timeout_ms.is_some() {
            out.timeout_ms = o.timeout_ms;
        }
        if o.feature_enabled == Some(true) {
            out.feature_enabled = o.feature_enabled;
        }
        if !o.tags.is_empty() {
            out.tags.extend(o.tags.clone());
        }
    }

    out
}

