#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Record {
    pub id: u32,
    pub kind: String,
    pub active: bool,
    pub tags: Vec<String>,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();
    for (line_no, raw) in input.lines().enumerate() {
        let line = raw.trim();
        if line.is_empty() {
            continue;
        }

        let parts: Vec<&str> = line.split('|').collect();
        if parts.len() != 4 {
            return Err(format!("line {}: expected 4 fields", line_no + 1));
        }

        let id: u32 = parts[0]
            .trim()
            .parse()
            .map_err(|_| format!("line {}: invalid id", line_no + 1))?;

        let kind = parts[1].trim().to_string();

        let active = parts[2].trim() == "true";

        let tags = if parts[3].trim().is_empty() {
            Vec::new()
        } else {
            parts[3].split(',').map(|s| s.trim().to_string()).collect()
        };

        out.push(Record {
            id,
            kind,
            active,
            tags,
        });
    }
    Ok(out)
}

