use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Record {
    pub category: &'static str,
    pub amount: i32,
    pub approved: bool,
}

pub fn category_report(records: &[Record]) -> String {
    let mut totals: BTreeMap<&str, (usize, i32)> = BTreeMap::new();

    for record in records {
        let entry = totals.entry(record.category).or_insert((0, 0));
        entry.0 += 1;
        entry.1 += record.amount;
    }

    let mut lines = Vec::new();
    let mut grand_count = 0usize;
    let mut grand_total = 0i32;

    for (category, (count, total)) in totals {
        lines.push(format!("{}: count={}, total={}", category, count, total));
        grand_count += count;
        grand_total += total;
    }

    lines.push(format!("grand: count={}, total={}", grand_count, grand_total));
    lines.join("\n")
}

