#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    New,
    InProgress,
    Blocked,
    Resolved,
    Closed,
    Reopened,
    Cancelled,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Event {
    Start,
    Block,
    Unblock,
    Resolve,
    Close,
    Reopen,
    Cancel,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::New;
    for event in events {
        status = match event {
            Event::Start => Status::InProgress,
            Event::Block => Status::Blocked,
            Event::Unblock => Status::New,
            Event::Resolve => Status::Resolved,
            Event::Close => Status::Closed,
            Event::Reopen => Status::InProgress,
            Event::Cancel => Status::Cancelled,
        };
    }
    status
}

