pub fn collect_tags(input: &[&str]) -> Vec<String> {
    let mut out: Vec<String> = input
        .iter()
        .filter_map(|raw| {
            let s = raw.trim();
            if s.is_empty() {
                return None;
            }
            if s.starts_with('#') {
                return Some(s[1..].to_lowercase());
            }
            if s.contains(' ') {
                return Some(s.to_lowercase());
            }
            Some(s.to_string())
        })
        .collect();

    out.sort();
    out
}

