#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Action {
    Create { urgent: bool },
    Update { fields: usize },
    Delete { soft: bool },
    Archive,
}

pub fn dispatch(action: Action) -> &'static str {
    match action {
        Action::Create { urgent: _ } => "enqueue",
        Action::Update { fields } if fields == 0 => "write",
        Action::Update { fields: _ } => "skip",
        Action::Delete { soft } => {
            if soft {
                "purge"
            } else {
                "trash"
            }
        }
        Action::Archive => "store",
    }
}

#[cfg(test)]
mod tests {
    use super::{dispatch, Action};

    #[test]
    fn create_branch_distinguishes_urgent() {
        assert_eq!(dispatch(Action::Create { urgent: false }), "enqueue");
        assert_eq!(dispatch(Action::Create { urgent: true }), "page");
    }

    #[test]
    fn update_branch_checks_zero_and_nonzero() {
        assert_eq!(dispatch(Action::Update { fields: 0 }), "skip");
        assert_eq!(dispatch(Action::Update { fields: 3 }), "write");
    }

    #[test]
    fn delete_branch_uses_soft_flag() {
        assert_eq!(dispatch(Action::Delete { soft: true }), "trash");
        assert_eq!(dispatch(Action::Delete { soft: false }), "purge");
    }

    #[test]
    fn archive_branch_is_stable() {
        assert_eq!(dispatch(Action::Archive), "store");
    }
}

