use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale<'a> {
    pub region: &'a str,
    pub category: &'a str,
    pub amount: i32,
    pub refunded: bool,
}

pub fn monthly_report(sales: &[Sale<'_>]) -> String {
    let mut grouped: BTreeMap<&str, (i32, usize)> = BTreeMap::new();

    for sale in sales {
        if sale.amount <= 0 {
            continue;
        }
        let entry = grouped.entry(sale.region).or_insert((0, 0));
        entry.0 += sale.amount;
        entry.1 += 1;
    }

    let mut out = String::new();
    for (region, (total, count)) in grouped {
        out.push_str(&format!("{} total={} count={}\n", region, total, count));
    }
    out
}

