#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Resolve,
    Close,
    Reopen,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::Open;
    for event in events {
        status = match (status, *event) {
            (Status::Open, Event::Start) => Status::InProgress,
            (Status::Open, Event::Resolve) => Status::Resolved,
            (Status::Open, Event::Close) => Status::Closed,
            (Status::Open, Event::Reopen) => Status::Open,
            (Status::InProgress, Event::Start) => Status::InProgress,
            (Status::InProgress, Event::Resolve) => Status::Resolved,
            (Status::InProgress, Event::Close) => Status::Closed,
            (Status::InProgress, Event::Reopen) => Status::Open,
            (Status::Resolved, Event::Start) => Status::InProgress,
            (Status::Resolved, Event::Resolve) => Status::Resolved,
            (Status::Resolved, Event::Close) => Status::Resolved,
            (Status::Resolved, Event::Reopen) => Status::Open,
            (Status::Closed, Event::Start) => Status::InProgress,
            (Status::Closed, Event::Resolve) => Status::Resolved,
            (Status::Closed, Event::Close) => Status::Closed,
            (Status::Closed, Event::Reopen) => Status::Open,
        };
    }
    status
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event, Status};

    #[test]
    fn close_requires_resolved_first() {
        assert_eq!(apply_events(&[Event::Start, Event::Close]), Status::InProgress);
        assert_eq!(apply_events(&[Event::Close]), Status::Open);
    }

    #[test]
    fn reopen_from_in_progress_keeps_working_state() {
        assert_eq!(apply_events(&[Event::Start, Event::Reopen]), Status::InProgress);
    }

    #[test]
    fn closed_tickets_ignore_non_reopen_events() {
        assert_eq!(
            apply_events(&[Event::Start, Event::Resolve, Event::Close, Event::Start, Event::Resolve]),
            Status::Closed
        );
    }

    #[test]
    fn resolved_can_be_closed_or_reopened() {
        assert_eq!(apply_events(&[Event::Start, Event::Resolve, Event::Close]), Status::Closed);
        assert_eq!(apply_events(&[Event::Start, Event::Resolve, Event::Reopen]), Status::Open);
    }
}

