use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale {
    pub region: &'static str,
    pub rep: &'static str,
    pub amount: i32,
    pub refunded: bool,
}

pub fn region_report(sales: &[Sale], min_net: i32) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();
    let mut counts: BTreeMap<&str, usize> = BTreeMap::new();
    let mut refunds: BTreeMap<&str, usize> = BTreeMap::new();

    for sale in sales {
        *totals.entry(sale.region).or_insert(0) += sale.amount;
        *counts.entry(sale.region).or_insert(0) += 1;
        if sale.refunded {
            *refunds.entry(sale.region).or_insert(0) += 1;
        }
    }

    let mut rows: Vec<(&str, i32, usize, usize)> = totals
        .iter()
        .map(|(region, total)| {
            (
                *region,
                *total,
                counts.get(region).copied().unwrap_or(0),
                refunds.get(region).copied().unwrap_or(0),
            )
        })
        .collect();

    rows.sort_by(|a, b| a.0.cmp(b.0));

    let mut out = String::new();
    for (region, net, count, refunded_count) in rows {
        if net <= min_net {
            continue;
        }
        out.push_str(&format!("{region}: net={net}; orders={count}; refunds={refunded_count}\n"));
    }

    if out.is_empty() {
        "no qualifying regions".to_string()
    } else {
        out
    }
}

