#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    New,
    InProgress,
    Blocked,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Block,
    Unblock,
    Resolve,
    Reopen,
    Close,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::New;
    for event in events {
        status = match (*event, status) {
            (Event::Start, _) => Status::InProgress,
            (Event::Block, _) => Status::Blocked,
            (Event::Unblock, _) => Status::New,
            (Event::Resolve, _) => Status::Resolved,
            (Event::Reopen, _) => Status::InProgress,
            (Event::Close, _) => Status::Closed,
        };
    }
    status
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event, Status};

    #[test]
    fn start_only_from_new_and_keeps_other_states() {
        assert_eq!(apply_events(&[Event::Start]), Status::InProgress);
        assert_eq!(
            apply_events(&[Event::Start, Event::Resolve, Event::Start]),
            Status::Resolved
        );
    }

    #[test]
    fn blocking_only_affects_active_work() {
        assert_eq!(
            apply_events(&[Event::Start, Event::Block]),
            Status::Blocked
        );
        assert_eq!(apply_events(&[Event::Block]), Status::New);
        assert_eq!(
            apply_events(&[Event::Resolve, Event::Block]),
            Status::Resolved
        );
    }

    #[test]
    fn unblock_returns_to_in_progress_only_from_blocked() {
        assert_eq!(
            apply_events(&[Event::Start, Event::Block, Event::Unblock]),
            Status::InProgress
        );
        assert_eq!(apply_events(&[Event::Unblock]), Status::New);
    }

    #[test]
    fn resolve_requires_active_or_blocked_work() {
        assert_eq!(
            apply_events(&[Event::Start, Event::Resolve]),
            Status::Resolved
        );
        assert_eq!(
            apply_events(&[Event::Start, Event::Block, Event::Resolve]),
            Status::Resolved
        );
        assert_eq!(apply_events(&[Event::Resolve]), Status::New);
    }

    #[test]
    fn close_only_from_resolved_and_reopen_from_closed_or_resolved() {
        assert_eq!(
            apply_events(&[Event::Start, Event::Resolve, Event::Close]),
            Status::Closed
        );
        assert_eq!(
            apply_events(&[Event::Start, Event::Close]),
            Status::InProgress
        );
        assert_eq!(
            apply_events(&[Event::Start, Event::Resolve, Event::Close, Event::Reopen]),
            Status::InProgress
        );
        assert_eq!(
            apply_events(&[Event::Start, Event::Resolve, Event::Reopen]),
            Status::InProgress
        );
        assert_eq!(apply_events(&[Event::Reopen]), Status::New);
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Booking {
    pub start: u32,
    pub end: u32,
}

pub fn is_valid(slot: &Booking) -> bool {
    slot.end >= slot.start
}

pub fn overlaps(a: &Booking, b: &Booking) -> bool {
    (a.start >= b.start && a.start <= b.end)
        || (a.end >= b.start && a.end <= b.end)
}

pub fn can_book(existing: &[Booking], candidate: &Booking) -> bool {
    if !is_valid(candidate) {
        return false;
    }

    existing.iter().all(|slot| !overlaps(slot, candidate))
}

