    #[test]
    fn touching_edges_do_not_overlap() {
        let a = Booking { start: 10, end: 20 };
        let b = Booking { start: 20, end: 30 };
        assert!(!overlaps(&a, &b));
        assert!(can_book(&[a], &b));
    }

    #[test]
    fn containment_counts_as_overlap() {
        let outer = Booking { start: 10, end: 30 };
        let inner = Booking { start: 15, end: 20 };
        assert!(overlaps(&outer, &inner));
        assert!(!can_book(&[outer], &inner));
    }

