    fn rejects_zero_length_or_reversed_slots() {
        assert!(!is_valid(&Booking { start: 7, end: 7 }));
        assert!(!is_valid(&Booking { start: 9, end: 4 }));
        assert!(!can_book(&[], &Booking { start: 5, end: 5 }));
    }

    #[test]
    fn valid_non_overlapping_candidate_is_allowed() {
        let existing = [
            Booking { start: 2, end: 5 },
            Booking { start: 8, end: 10 },
        ];
        let candidate = Booking { start: 5, end: 8 };
        assert!(can_book(&existing, &candidate));
    }
