#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player<'a> {
    pub name: &'a str,
    pub wins: u32,
    pub draws: u32,
    pub losses: u32,
}

fn points(p: &Player<'_>) -> u32 {
    p.wins * 3 + p.draws
}

pub fn leaderboard(players: &[Player<'_>]) -> Vec<String> {
    let mut items = players.to_vec();
    items.sort_by(|a, b| {
        points(a)
            .cmp(&points(b))
            .then(a.wins.cmp(&b.wins))
            .then(a.losses.cmp(&b.losses))
            .then(a.name.cmp(b.name))
    });

    items
        .into_iter()
        .enumerate()
        .map(|(i, p)| format!("{}. {} ({})", i + 1, p.name, points(&p)))
        .collect()
}

