use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale {
    pub region: &'static str,
    pub rep: &'static str,
    pub units: u32,
    pub refunded: bool,
}

pub fn build_report(sales: &[Sale]) -> String {
    let mut by_region: BTreeMap<&str, (u32, u32)> = BTreeMap::new();

    for sale in sales {
        let entry = by_region.entry(sale.region).or_insert((0, 0));
        entry.0 += 1;
        entry.1 += sale.units;
    }

    let mut out = String::new();
    for (region, (orders, units)) in by_region {
        out.push_str(&format!("{}: orders={}, units={}\n", region, orders, units));
    }
    out.push_str(&format!("TOTAL orders={} units={}", sales.len(), sales.iter().map(|s| s.units).sum::<u32>()));
    out
}

