#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Draft,
    Submitted,
    Paid,
    Shipped,
    Cancelled,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Event {
    Submit,
    Pay,
    Ship,
    Cancel,
    Reopen,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Order {
    pub status: Status,
    pub note_count: u32,
    pub history: Vec<Status>,
}

impl Order {
    pub fn new() -> Self {
        Self {
            status: Status::Draft,
            note_count: 0,
            history: vec![Status::Draft],
        }
    }

    pub fn apply(&mut self, event: Event) -> bool {
        let next = match (self.status, event) {
            (Status::Draft, Event::Submit) => Some(Status::Submitted),
            (Status::Submitted, Event::Pay) => Some(Status::Paid),
            (Status::Paid, Event::Ship) => Some(Status::Shipped),
            (_, Event::Cancel) => Some(Status::Cancelled),
            (Status::Cancelled, Event::Reopen) => Some(Status::Submitted),
            _ => None,
        };

        if let Some(status) = next {
            self.status = status;
            self.history.push(status);
            self.note_count += 1;
            true
        } else {
            false
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn invalid_cancel_from_shipped_is_rejected() {
        let mut order = Order::new();
        assert!(order.apply(Event::Submit));
        assert!(order.apply(Event::Pay));
        assert!(order.apply(Event::Ship));
        assert!(!order.apply(Event::Cancel));
        assert_eq!(order.status, Status::Shipped);
        assert_eq!(order.history, vec![Status::Draft, Status::Submitted, Status::Paid, Status::Shipped]);
        assert_eq!(order.note_count, 3);
    }

    #[test]
    fn invalid_events_do_not_mutate() {
        let mut order = Order::new();
        assert!(!order.apply(Event::Pay));
        assert_eq!(order.status, Status::Draft);
        assert_eq!(order.history, vec![Status::Draft]);
        assert_eq!(order.note_count, 0);
    }

    #[test]
    fn reopen_returns_to_draft_and_can_resubmit() {
        let mut order = Order::new();
        assert!(order.apply(Event::Submit));
        assert!(order.apply(Event::Cancel));
        assert!(order.apply(Event::Reopen));
        assert_eq!(order.status, Status::Draft);
        assert_eq!(order.history, vec![Status::Draft, Status::Submitted, Status::Cancelled, Status::Draft]);
        assert!(order.apply(Event::Submit));
        assert_eq!(order.status, Status::Submitted);
    }

    #[test]
    fn note_count_tracks_only_customer_visible_changes() {
        let mut order = Order::new();
        assert!(order.apply(Event::Submit));
        assert!(order.apply(Event::Pay));
        assert!(order.apply(Event::Cancel));
        assert_eq!(order.note_count, 2);
        assert_eq!(order.history, vec![Status::Draft, Status::Submitted, Status::Paid, Status::Cancelled]);
    }

    #[test]
    fn draft_cannot_be_cancelled() {
        let mut order = Order::new();
        assert!(!order.apply(Event::Cancel));
        assert_eq!(order.status, Status::Draft);
        assert_eq!(order.history, vec![Status::Draft]);
        assert_eq!(order.note_count, 0);
    }
}

