pub fn collect_metric_keys(lines: &[&str]) -> Vec<String> {
    let mut out: Vec<String> = lines
        .iter()
        .filter_map(|line| {
            let mut parts = line.split('|');
            let kind = parts.next()?;
            let key = parts.next()?;
            let value = parts.next()?;

            if kind != "metric" {
                return None;
            }
            if value.parse::<i32>().ok()? < 0 {
                return None;
            }

            Some(key.to_string())
        })
        .collect();
    out.sort();
    out
}

