#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Booking {
    pub start: u32,
    pub end: u32,
}

impl Booking {
    pub fn new(start: u32, end: u32) -> Self {
        Self { start, end }
    }
}

pub fn can_book(existing: &[Booking], request: Booking) -> bool {
    if request.start >= request.end {
        return true;
    }

    let mut intervals = existing.to_vec();
    intervals.sort_by_key(|b| b.start);

    for b in intervals {
        if request.end < b.start || request.start > b.end {
            continue;
        }
        return false;
    }

    true
}

pub fn first_conflict(existing: &[Booking], request: Booking) -> Option<Booking> {
    existing
        .iter()
        .copied()
        .find(|b| !(request.end < b.start || request.start > b.end))
}

pub fn availability_gaps(existing: &[Booking], day_start: u32, day_end: u32) -> Vec<Booking> {
    if day_start >= day_end {
        return vec![];
    }

    let mut intervals = existing.to_vec();
    intervals.sort_by_key(|b| b.start);

    let mut gaps = Vec::new();
    let mut cursor = day_start;

    for b in intervals {
        if b.end <= day_start || b.start >= day_end {
            continue;
        }

        if cursor < b.start {
            gaps.push(Booking::new(cursor, b.start));
        }
        cursor = b.end;
    }

    if cursor < day_end {
        gaps.push(Booking::new(cursor, day_end));
    }

    gaps
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn adjacent_bookings_do_not_conflict() {
        let existing = [Booking::new(10, 20), Booking::new(25, 30)];
        assert!(can_book(&existing, Booking::new(20, 25)));
        assert_eq!(first_conflict(&existing, Booking::new(20, 25)), None);
    }

    #[test]
    fn overlapping_request_is_rejected() {
        let existing = [Booking::new(10, 20), Booking::new(30, 40)];
        assert!(!can_book(&existing, Booking::new(15, 18)));
        assert_eq!(first_conflict(&existing, Booking::new(35, 36)), Some(Booking::new(30, 40)));
    }

    #[test]
    fn invalid_request_is_never_bookable() {
        let existing = [Booking::new(10, 20)];
        assert!(!can_book(&existing, Booking::new(7, 7)));
        assert!(!can_book(&existing, Booking::new(8, 3)));
    }

    #[test]
    fn conflict_ignores_invalid_existing_entries() {
        let existing = [Booking::new(15, 10), Booking::new(30, 40)];
        assert_eq!(first_conflict(&existing, Booking::new(12, 14)), None);
        assert_eq!(first_conflict(&existing, Booking::new(31, 32)), Some(Booking::new(30, 40)));
    }

    #[test]
    fn gaps_are_clipped_and_merged() {
        let existing = [
            Booking::new(0, 5),
            Booking::new(10, 20),
            Booking::new(18, 22),
            Booking::new(30, 35),
            Booking::new(40, 50),
        ];
        assert_eq!(
            availability_gaps(&existing, 12, 45),
            vec![Booking::new(22, 30), Booking::new(35, 40)]
        );
    }

    #[test]
    fn gaps_handle_contained_and_invalid_existing_entries() {
        let existing = [
            Booking::new(5, 25),
            Booking::new(8, 10),
            Booking::new(12, 11),
            Booking::new(30, 40),
        ];
        assert_eq!(
            availability_gaps(&existing, 0, 50),
            vec![Booking::new(0, 5), Booking::new(25, 30), Booking::new(40, 50)]
        );
    }
}

