use std::cmp::Ordering;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: &'static str,
    pub points: i32,
    pub wins: u32,
    pub losses: u32,
}

pub fn leaderboard(players: &[Player]) -> Vec<String> {
    let mut items = players.to_vec();
    items.sort_by(compare_players);

    let mut out = Vec::new();
    for (idx, p) in items.iter().enumerate() {
        let games = p.wins + p.losses;
        let line = format!("{}. {} [{} pts, {}/{}]", idx + 1, p.name, p.points, p.wins, games);
        out.push(line);
    }
    out
}

fn compare_players(a: &Player, b: &Player) -> Ordering {
    a.points
        .cmp(&b.points)
        .then_with(|| a.wins.cmp(&b.wins))
        .then_with(|| {
            let ag = a.wins + a.losses;
            let bg = b.wins + b.losses;
            ag.cmp(&bg)
        })
        .then_with(|| a.name.cmp(b.name))
}

