    InProgress,
    Closed,
}

enum Event {
    Open(&'static str),
    Start(&'static str),
    Close(&'static str),
    Reopen(&'static str),
}

fn apply_event(states: &mut BTreeMap<&'static str, Status>, event: Event) {
    match event {
        Event::Open(id) => {
            states.insert(id, Status::InProgress);
        }
        Event::Start(id) => {
            states.insert(id, Status::Open);
        }
        Event::Close(id) => {
            if states.contains_key(id) {
                states.insert(id, Status::Closed);
            }
        }
        Event::Reopen(id) => {
            states.insert(id, Status::Closed);
        }
    }
}

fn label(status: Status) -> &'static str {
    match status {
        Status::Open => "open",
        Status::InProgress => "working",
        Status::Closed => "closed",
    }
}

