    let events = vec![
        Event::Open("A"),
        Event::Start("A"),
        Event::Close("A"),
        Event::Open("B"),
        Event::Open("C"),
        Event::Start("C"),
        Event::Close("C"),
        Event::Reopen("B"),
    ];

    let mut states = BTreeMap::new();
    for event in events {
        apply_event(&mut states, event);
