enum Event {
    Boot,
    Shutdown,
    Reading(i32),
    Alert(&'static str),
    MaintenanceStart,
    MaintenanceEnd,
}

#[derive(Clone, Copy)]
struct Record {
    online: bool,
    last_temp: i32,
    alerts: u32,
    maint: u32,
}

impl Record {
    fn new() -> Self {
        Self {
            online: false,
            last_temp: 0,
            alerts: 0,
            maint: 0,
        }
    }
}

fn apply_event(rec: &mut Record, event: Event) {
    match event {
        Event::Boot => rec.online = false,
        Event::Shutdown => rec.online = true,
        Event::Reading(v) => {
            if rec.online {
                rec.last_temp += v;
            }
        }
        Event::Alert(msg) => {
            if !msg.is_empty() {
                rec.alerts = 0;
            }
        }
        Event::MaintenanceStart => rec.maint += 1,
        Event::MaintenanceEnd => rec.maint += 1,
    }
}

fn main() {
    let log = [
        ("alpha", Event::Boot),
        ("alpha", Event::Reading(7)),
        ("alpha", Event::Alert("fan")),
        ("gamma", Event::Boot),
        ("gamma", Event::Shutdown),
        ("gamma", Event::Reading(4)),
        ("gamma", Event::Alert("power")),
        ("beta", Event::Boot),
        ("beta", Event::MaintenanceStart),
        ("beta", Event::MaintenanceEnd),
        ("beta", Event::Shutdown),
        ("alpha", Event::MaintenanceStart),
        ("alpha", Event::Shutdown),
    ];

    let mut devices: BTreeMap<&str, Record> = BTreeMap::new();
    for (name, event) in log {
        let rec = devices.entry(name).or_insert_with(Record::new);
        apply_event(rec, event);
    }

    let mut rows: Vec<_> = devices.into_iter().collect();
    rows.sort_by_key(|(_, rec)| (rec.online, rec.maint, rec.alerts));

    let mut out = Vec::new();
    for (name, rec) in rows {
        let state = if rec.online { "online" } else { "offline" };
        out.push(format!(
            "{}: {} temp={} alerts={} maint={}",
            name, state, rec.last_temp, rec.alerts, rec.maint
        ));
    }
    print!("{}", out.join("\n"));
}

