use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Status {
    Open,
    InProgress,
    Resolved,
    Closed,
}

enum Event {
    Create(&'static str),
    Start(&'static str),
    Resolve(&'static str),
    Reopen(&'static str),
    Close(&'static str),
}

fn apply(status: &mut Status, event: &Event) {
    match event {
        Event::Create(_) => *status = Status::Open,
        Event::Start(_) => *status = Status::InProgress,
        Event::Resolve(_) => *status = Status::Closed,
        Event::Reopen(_) => *status = Status::Resolved,
        Event::Close(_) => {
            if *status == Status::Resolved {
                *status = Status::Closed;
            }
        }
    }
}

fn event_id(event: &Event) -> &'static str {
    match event {
        Event::Create(id)
        | Event::Start(id)
        | Event::Resolve(id)
        | Event::Reopen(id)
        | Event::Close(id) => id,
    }
}

fn label(status: Status) -> &'static str {
    match status {
        Status::Open => "Open",
        Status::InProgress => "Working",
        Status::Resolved => "Resolved",
        Status::Closed => "Closed",
    }
}

fn main() {
    let events = [
        Event::Create("A"),
        Event::Start("A"),
        Event::Resolve("A"),
        Event::Close("A"),
        Event::Create("B"),
        Event::Resolve("B"),
        Event::Close("B"),
        Event::Create("C"),
        Event::Start("C"),
        Event::Reopen("C"),
    ];

    let mut tickets: BTreeMap<&'static str, Status> = BTreeMap::new();
    for event in &events {
        let id = event_id(event);
        let status = tickets.entry(id).or_insert(Status::Open);
        apply(status, event);
    }

    for (id, status) in tickets {
        println!("{}:{}", id, label(status));
    }
}

