    start: u32,
    end: u32,
}

fn overlaps(a: &Booking, b: &Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn has_conflict(target: &Booking, all: &[Booking]) -> bool {
    for other in all {
        if target.name == other.name {
            continue;
        }
        if overlaps(target, other) {
            return true;
        }
    }
    false
}

