use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum State {
    New,
    Paid,
    Packed,
    Shipped,
    Delivered,
    Canceled,
}

impl State {
    fn as_str(&self) -> &'static str {
        match self {
            State::New => "new",
            State::Paid => "paid",
            State::Packed => "packed",
            State::Shipped => "shipped",
            State::Delivered => "delivered",
            State::Canceled => "canceled",
        }
    }
}

fn apply(state: State, event: &str) -> State {
    match event {
        "pay" => State::Paid,
        "pack" => State::Packed,
        "ship" => State::Shipped,
        "deliver" => State::Delivered,
        "cancel" => State::Canceled,
        _ => state,
    }
}

fn main() {
    let events = [
        ("A", "pay"),
        ("A", "pack"),
        ("A", "ship"),
        ("A", "deliver"),
        ("B", "pay"),
        ("B", "cancel"),
        ("C", "pay"),
        ("C", "deliver"),
    ];

    let mut orders: BTreeMap<&str, State> = BTreeMap::new();
    for (id, event) in events {
        let current = *orders.get(id).unwrap_or(&State::New);
        let next = apply(current, event);
        orders.insert(id, next);
    }

    let mut lines = Vec::new();
    for (id, state) in orders {
        lines.push(format!("{}: {}", id, state.as_str().to_uppercase()));
    }
    println!("{}", lines.join("\n"));
}

