enum Direction {
    North,
    South,
    East,
    West,
}

enum Action {
    Move(Direction, u8),
    Wait(u8),
    Say(&'static str),
    SetColor { r: u8, g: u8, b: u8 },
    Patrol(Vec<(Direction, u8)>),
    Done,
}

fn dir_name(dir: &Direction) -> &'static str {
    match dir {
        Direction::North => "north",
        Direction::South => "south",
        Direction::East => "east",
        Direction::West => "west",
    }
}

fn dir_code(dir: &Direction) -> &'static str {
    match dir {
        Direction::North => "NORTH",
        Direction::South => "SOUTH",
        Direction::East => "EAST",
        Direction::West => "WEST",
    }
}

fn summarize(action: &Action) -> String {
    match action {
        Action::Move(dir, steps) => format!("move({},{} )", dir_name(dir), steps).replace(", ", ","),
        Action::Wait(ticks) => format!("pause({})", ticks),
        Action::Say(msg) => format!("say({})", msg),
        Action::SetColor { r, g, b } => format!("color({}, {}, {})", r, g, b),
        Action::Patrol(legs) => {
            let mut parts = Vec::new();
            for (dir, n) in legs {
                parts.push(format!("{}x{}", dir_code(dir).to_lowercase(), n));
            }
            format!("patrol({})", parts.join(","))
        }
        Action::Done => "stop".to_string(),
    }
}

fn execute(action: &Action) -> String {
    match action {
        Action::Move(dir, steps) => format!("MOVE {} {}", dir_code(dir), steps),
        Action::Wait(ticks) => format!("WAIT {}", ticks),
        Action::Say(msg) => format!("SAY {}", msg),
        Action::SetColor { r, g, b } => format!("COLOR #{:02X}{:02X}{:02X}", b, g, r),
        Action::Patrol(legs) => {
            let mut out = String::from("PATROL ");
            for (i, (dir, n)) in legs.iter().enumerate() {
                if i > 0 {
                    out.push('|');
                }
                out.push_str(&format!("{}:{}", dir_name(dir), n));
            }
            out
        }
        Action::Done => "HALT".to_string(),
    }
}

fn build_plan() -> Vec<Action> {
    vec![
        Action::Move(Direction::North, 3),
        Action::Wait(2),
        Action::Say("ready"),
        Action::SetColor { r: 12, g: 34, b: 56 },
        Action::Patrol(vec![
            (Direction::East, 1),
            (Direction::South, 2),
            (Direction::West, 1),
        ]),
        Action::Done,
    ]
}

fn main() {
    let plan = build_plan();
    let summary = plan.iter().map(summarize).collect::<Vec<_>>().join(" ");
    let executed = plan.iter().map(execute).collect::<Vec<_>>().join("\n");
    println!("plan: {}\nexec:\n{}", summary, executed);
}

