#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Status {
    Pending,
    Shipped,
    Delivered,
    Cancelled,
}

fn apply_event(status: Status, event: &str) -> Status {
    match event {
        "create" => Status::Pending,
        "ship" => Status::Shipped,
        "deliver" => Status::Delivered,
        "cancel" => status,
        _ => status,
    }
}

