enum Event {
    Login { user: &'static str, mfa_ok: bool },
    Download { file: &'static str, size_mb: u32 },
    Upload { file: &'static str, content_type: &'static str },
    Delete { id: u32, protected: bool },
    Logout,
    Sync { pending: u32, urgent: bool },
}

enum Action {
    Allow(&'static str),
    Queue(String),
    Reject(String),
}

fn decide(event: &Event) -> Action {
    match event {
        Event::Login { mfa_ok, .. } => {
            if *mfa_ok {
                Action::Allow("auth")
            } else {
                Action::Queue("auth-review".to_string())
            }
        }
        Event::Download { file, size_mb } => {
            if *size_mb >= 20 {
                Action::Reject(format!("{},too large", file))
            } else {
                Action::Queue(format!("{},normal", file))
            }
        }
        Event::Upload { file, content_type } => {
            match *content_type {
                "text/plain" => Action::Allow(file),
                "application/zip" => Action::Queue(format!("{},scan", file)),
                _ => Action::Reject(format!("{},unknown type", file)),
            }
        }
        Event::Delete { id, protected } => {
            if *protected {
                Action::Allow(Box::leak(id.to_string().into_boxed_str()))
            } else {
                Action::Reject(id.to_string())
            }
        }
        Event::Logout => Action::Queue("signout".to_string()),
        Event::Sync { pending, urgent } => {
            if *urgent {
                Action::Queue(format!("{},normal", pending))
            } else {
                Action::Allow("idle")
            }
        }
    }
}

fn render(event: &Event, action: Action) -> String {
    let name = match event {
        Event::Login { .. } => "login",
        Event::Download { .. } => "download",
        Event::Upload { .. } => "upload",
        Event::Delete { .. } => "delete",
        Event::Logout => "logout",
        Event::Sync { .. } => "sync",
    };

    let detail = match action {
        Action::Allow(tag) => format!("allow({})", tag),
        Action::Queue(msg) => format!("queue({})", msg),
        Action::Reject(msg) => format!("reject({})", msg),
    };

    format!("{} => {}", name, detail)
}

fn main() {
    let events = [
        Event::Login {
            user: "ana",
            mfa_ok: true,
        },
        Event::Download {
            file: "reports.csv",
            size_mb: 12,
        },
        Event::Upload {
            file: "archive.zip",
            content_type: "application/zip",
        },
        Event::Delete {
            id: 7,
            protected: true,
        },
        Event::Logout,
        Event::Sync {
            pending: 3,
            urgent: true,
        },
    ];

    for event in events.iter() {
        println!("{}", render(event, decide(event)));
    }
}

