use std::collections::BTreeMap;

fn apply_event(state: &str, event: &str) -> String {
    match (state, event) {
        ("new", "start") => "open".to_string(),
        ("open", "resolve") => "open".to_string(),
        ("closed", "reopen") => "closed".to_string(),
        (_, "close") => "closed".to_string(),
        _ => state.to_string(),
    }
}

fn main() {
    let events = [
        ("A", "start"),
        ("A", "resolve"),
        ("A", "close"),
        ("B", "start"),
        ("B", "close"),
        ("B", "reopen"),
        ("B", "close"),
        ("C", "start"),
        ("C", "resolve"),
        ("C", "reopen"),
    ];

    let mut tickets: BTreeMap<&str, String> = BTreeMap::new();

    for (id, event) in events {
        let current = tickets.get(id).map(|s| s.as_str()).unwrap_or("new");
        let next = apply_event(current, event);
        tickets.insert(id, next);
    }

    for (id, state) in tickets {
        println!("{}:{}", id, state);
    }
}

enum Action {
    Skip,
    Retry(u8),
    Route(Option<&'static str>),
    Audit { topic: &'static str, urgent: bool },
    Archive(Vec<&'static str>),
}

struct Task {
    name: &'static str,
    action: Action,
}

fn describe(action: &Action) -> String {
    match action {
        Action::Skip => "skip-now".to_string(),
        Action::Retry(count) => format!("retry({})", count + 1),
        Action::Route(dest) => format!("route:{}", dest.unwrap_or("default")),
        Action::Audit { topic, urgent } => format!("audit:{}", topic.to_uppercase()) + if *urgent { "" } else { "!" },
        Action::Archive(items) => format!("archive({} box)", items.len()),
    }
}

fn main() {
    let tasks = vec![
        Task { name: "alpha", action: Action::Skip },
        Task { name: "beta", action: Action::Retry(2) },
        Task { name: "gamma", action: Action::Route(Some("west")) },
        Task { name: "delta", action: Action::Route(None) },
        Task { name: "epsilon", action: Action::Audit { topic: "security", urgent: true } },
        Task { name: "zeta", action: Action::Audit { topic: "ops", urgent: false } },
        Task { name: "eta", action: Action::Archive(vec!["a", "b"]) },
        Task { name: "theta", action: Action::Archive(vec![]) },
    ];

    for (idx, task) in tasks.iter().enumerate() {
        println!("{}. {} => {}", idx + 1, task.name, describe(&task.action));
    }
}

