#[derive(Clone, Copy)]
struct Booking {
    room: &'static str,
    start: u32,
    end: u32,
}

fn overlaps(a: &Booking, b: &Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn can_accept(existing: &[Booking], candidate: &Booking) -> bool {
    for current in existing {
        if overlaps(current, candidate) {
            return false;
        }
    }
    true
}

fn fmt_booking(b: &Booking) -> String {
    format!("{} {:02}-{:02}", b.room, b.start, b.end)
}

fn main() {
    let requests = [
        Booking {
            room: "Room A",
            start: 8,
            end: 10,
        },
        Booking {
            room: "Room A",
            start: 10,
            end: 12,
        },
        Booking {
            room: "Room B",
            start: 9,
            end: 11,
        },
        Booking {
            room: "Room A",
            start: 9,
            end: 11,
        },
        Booking {
            room: "Room A",
            start: 12,
            end: 13,
        },
    ];

    let mut accepted = Vec::new();
    for req in requests {
        if can_accept(&accepted, &req) {
            accepted.push(req);
        }
    }

    let joined = accepted
        .iter()
        .map(fmt_booking)
        .collect::<Vec<_>>()
        .join(", ");
    println!("accepted: {}", joined);
}

