use std::collections::BTreeMap;

#[derive(Clone, Copy, PartialEq, Eq)]
enum State {
    Open,
    InProgress,
    Closed,
}

impl State {
    fn as_str(&self) -> &'static str {
        match self {
            State::Open => "Open",
            State::InProgress => "InProgress",
            State::Closed => "Closed",
        }
    }
}

enum Event {
    Create(&'static str),
    Start(&'static str),
    Resolve(&'static str),
    Reopen(&'static str),
}

fn main() {
    let events = [
        Event::Create("A"),
        Event::Start("A"),
        Event::Resolve("A"),
        Event::Create("B"),
        Event::Resolve("B"),
        Event::Create("C"),
        Event::Start("C"),
        Event::Reopen("C"),
    ];

    let mut tickets: BTreeMap<&str, State> = BTreeMap::new();

    for event in events {
        match event {
            Event::Create(id) => {
                tickets.insert(id, State::InProgress);
            }
            Event::Start(id) => {
                tickets.insert(id, State::InProgress);
            }
            Event::Resolve(id) => {
                tickets.insert(id, State::Closed);
            }
            Event::Reopen(id) => {
                tickets.insert(id, State::InProgress);
            }
        }
    }

    for (id, state) in tickets {
        println!("{}={}", id, state.as_str());
    }
}

