enum Action {
    Compute { name: &'static str, left: i32, right: i32 },
    Retry { name: &'static str, attempts: u8 },
    Fail { name: &'static str, code: i32 },
    Disabled { name: &'static str },
    Unknown { name: &'static str },
}

struct Totals {
    ok: u32,
    warn: u32,
    fatal: u32,
    dropped: u32,
    skipped: u32,
    score: i32,
}

fn render(action: &Action, totals: &mut Totals) -> String {
    match action {
        Action::Compute { name, left, right } => {
            totals.ok += 1;
            totals.score += 1;
            format!("OK {} = {}", name, left - right)
        }
        Action::Retry { name, attempts } => {
            totals.warn += 1;
            totals.score += 2;
            format!("WARN {} @ retry({})", name, attempts + 1)
        }
        Action::Fail { name, code } => {
            totals.fatal += 1;
            totals.score -= 5;
            format!("FATAL {} #{}", name, code)
        }
        Action::Disabled { name } => {
            totals.skipped += 1;
            format!("SKIP {}: disabled", name)
        }
        Action::Unknown { name } => {
            totals.dropped += 1;
            format!("DROP {}: unknown target", name)
        }
    }
}

fn main() {
    let actions = [
        Action::Compute {
            name: "alpha",
            left: 8,
            right: 2,
        },
        Action::Disabled { name: "beta" },
        Action::Retry {
            name: "gamma",
            attempts: 2,
        },
        Action::Fail {
            name: "delta",
            code: 500,
        },
        Action::Unknown { name: "epsilon" },
    ];

    let mut totals = Totals {
        ok: 0,
        warn: 0,
        fatal: 0,
        dropped: 0,
        skipped: 0,
        score: 0,
    };

    for action in &actions {
        println!("{}", render(action, &mut totals));
    }

    println!(
        "SUMMARY ok={} warn={} fatal={} dropped={} skipped={} score={}",
        totals.ok, totals.warn, totals.fatal, totals.dropped, totals.skipped, totals.score
    );
}

#[derive(Clone, Debug)]
struct Config {
    host: Option<&'static str>,
    port: Option<u16>,
    timeout: Option<u32>,
    verbose: Option<bool>,
