    retries: Option<u8>,
}

impl Config {
    fn new() -> Self {
        Self {
            host: None,
            port: None,
            timeout: None,
            verbose: None,
            features: Vec::new(),
            retries: None,
        }
    }

    fn merge(&mut self, other: &Config) {
        if self.host.is_none() {
            self.host = other.host;
