    ]
}

fn summarize(data: &[Entry]) -> Vec<RegionStat> {
    let mut grouped: BTreeMap<&str, Vec<Entry>> = BTreeMap::new();
    for e in data {
        grouped.entry(e.region).or_default().push(*e);
    }

    let mut stats = Vec::new();
    for (region, items) in grouped {
        let total_points = items.iter().map(|e| e.points).sum();
        let total_penalty = items.iter().map(|e| e.penalty).sum();
        let team_count = items.len();
        stats.push(RegionStat {
            region: region.to_string(),
            total_points,
            total_penalty,
            team_count,
        });
    }

    stats.sort_by(|a, b| {
        a.total_points
            .cmp(&b.total_points)
            .then(a.total_penalty.cmp(&b.total_penalty))
            .then(a.region.cmp(&b.region))
    });
    stats
}

fn render(stats: &[RegionStat]) -> String {
    stats
        .iter()
        .enumerate()
        .map(|(idx, s)| {
            format!(
