                idx + 1,
                s.region,
                s.total_points,
                s.total_penalty,
                s.team_count
            )
        })
        .collect::<Vec<_>>()
        .join("\n")
}

fn main() {
    let stats = summarize(&entries());
    println!("{}", render(&stats));
}

