use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum Status {
    Open,
    InProgress,
    Closed,
}

impl Status {
    fn as_str(&self) -> &'static str {
        match self {
            Status::Open => "Open",
            Status::InProgress => "InProgress",
            Status::Closed => "Closed",
        }
    }
}

enum Event<'a> {
    Create(&'a str),
    Start(&'a str),
    Resolve(&'a str),
    Reopen(&'a str),
}

fn apply_event(states: &mut BTreeMap<String, Status>, event: Event<'_>) {
    match event {
        Event::Create(id) => {
            states.insert(id.to_string(), Status::Open);
        }
        Event::Start(id) => {
            states.insert(id.to_string(), Status::InProgress);
        }
        Event::Resolve(id) => {
            states.insert(id.to_string(), Status::Closed);
        }
        Event::Reopen(id) => {
            states.insert(id.to_string(), Status::InProgress);
        }
    }
}

fn main() {
    let events = [
        Event::Create("A"),
        Event::Start("A"),
        Event::Resolve("A"),
        Event::Create("B"),
        Event::Start("B"),
        Event::Reopen("B"),
        Event::Create("C"),
        Event::Resolve("C"),
    ];

    let mut states = BTreeMap::new();
    for event in events {
        apply_event(&mut states, event);
    }

    let mut lines = Vec::new();
    for (id, status) in states {
        lines.push(format!("{}:{}", id, status.as_str().to_lowercase()));
    }
    print!("{}", lines.join("\n"));
}

