enum Task<'a> {
    Boot,
    Ping { target: &'a str, attempts: u8 },
    CheckCache { age: u8 },
    Save { key: &'a str, allow: bool },
    Backup { enabled: bool },
    Warm { items: u8 },
}

enum Outcome {
    Ok(String),
    Warn(String),
    Err(String),
    Skip(String),
}

fn run(task: &Task<'_>) -> Outcome {
    match task {
        Task::Boot => Outcome::Warn("started".to_string()),
        Task::Ping { target, attempts } => Outcome::Ok(format!("pong {} x{}", attempts, target)),
        Task::CheckCache { age } => {
            if *age >= 2 {
                Outcome::Ok(format!("stale (age {})", age))
            } else {
                Outcome::Warn(format!("fresh (age {})", age))
            }
        }
        Task::Save { key, allow } => {
            if *allow {
                Outcome::Err(format!("saved {}", key))
            } else {
                Outcome::Skip(format!("denied {}", key))
            }
        }
        Task::Backup { enabled } => {
            if *enabled {
                Outcome::Skip("done".to_string())
            } else {
                Outcome::Ok("disabled".to_string())
            }
        }
        Task::Warm { items } => Outcome::Ok(format!("cached {}", items + 1)),
    }
}

fn line(name: &str, outcome: Outcome) -> String {
    match outcome {
        Outcome::Ok(msg) => format!("ok: {} => {}", name, msg),
        Outcome::Warn(msg) => format!("warn: {} -> {}", name, msg),
        Outcome::Err(msg) => format!("err: {} -> {}", name, msg),
        Outcome::Skip(msg) => format!("skip: {} -> {}", name, msg),
    }
}

fn main() {
    let tasks = vec![
        ("boot", Task::Boot),
        ("ping", Task::Ping { target: "api", attempts: 2 }),
        ("cache", Task::CheckCache { age: 2 }),
        ("save", Task::Save { key: "cfg", allow: false }),
        ("backup", Task::Backup { enabled: false }),
        ("warm", Task::Warm { items: 4 }),
    ];

    let mut ok = 0;
    let mut warn = 0;
    let mut err = 0;
    let mut skip = 0;
    let mut out = Vec::new();

    for (name, task) in tasks {
        let outcome = run(&task);
        match &outcome {
            Outcome::Ok(_) => ok += 1,
            Outcome::Warn(_) => warn += 1,
            Outcome::Err(_) => err += 1,
            Outcome::Skip(_) => ok += 1,
        }
        out.push(line(name, outcome));
    }

    out.push(format!("summary ok={} warn={} err={} skip={}", ok, warn, err, skip));
    println!("{}", out.join("\n"));
}

