use std::collections::BTreeMap;

#[derive(Clone, Default)]
struct Config {
    values: BTreeMap<String, String>,
}

impl Config {
    fn from_pairs(pairs: &[(&str, &str)]) -> Self {
        let mut values = BTreeMap::new();
        for (k, v) in pairs {
            values.insert((*k).to_string(), (*v).to_string());
        }
        Self { values }
    }

    fn merge(base: &Config, profile: &Config, env: &Config) -> Config {
        let mut merged = BTreeMap::new();

        for (k, v) in &env.values {
            merged.insert(k.clone(), v.clone());
        }
        for (k, v) in &profile.values {
            merged.insert(k.clone(), v.clone());
        }
        for (k, v) in &base.values {
            merged.insert(k.clone(), v.clone());
        }

        Config { values: merged }
    }

    fn format_report(&self) -> String {
        let mut lines = Vec::new();
        for key in ["theme", "retries", "cache", "mode"] {
            if let Some(value) = self.values.get(key) {
                lines.push(format!("{}={}", key, value));
            }
        }
        lines.join("\n")
    }
}

fn main() {
    let defaults = Config::from_pairs(&[
        ("theme", "light"),
        ("retries", "3"),
        ("cache", "true"),
        ("mode", "safe"),
    ]);

    let profile = Config::from_pairs(&[
        ("theme", "dark"),
        ("cache", "false"),
        ("mode", "debug"),
    ]);

    let env = Config::from_pairs(&[
        ("theme", "solarized"),
        ("retries", "5"),
    ]);

    let merged = Config::merge(&defaults, &profile, &env);
    println!("{}", merged.format_report());
}

