struct Booking {
    name: &'static str,
    start: u32,
    end: u32,
}

fn overlaps(a: &Booking, b: &Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn can_book(existing: &[Booking], candidate: &Booking) -> bool {
    existing.iter().all(|b| !overlaps(b, candidate))
}

fn main() {
    let requests = vec![
        Booking { name: "A", start: 1, end: 3 },
        Booking { name: "B", start: 3, end: 5 },
        Booking { name: "C", start: 5, end: 6 },
        Booking { name: "D", start: 0, end: 1 },
        Booking { name: "E", start: 2, end: 4 },
        Booking { name: "F", start: 6, end: 7 },
        Booking { name: "G", start: 7, end: 7 },
    ];

    let mut kept: Vec<Booking> = Vec::new();
    let mut rejected = 0;

    for req in requests {
        if can_book(&kept, &req) {
            kept.push(req);
        } else {
            rejected += 1;
        }
    }

    let names = kept.iter().map(|b| b.name).collect::<Vec<_>>().join(",");
    println!("accepted: {}", rejected);
    println!("rejected: {}", kept.len());
    println!("kept: {}", names);
}

