use std::collections::BTreeMap;

#[derive(Clone)]
struct Sale {
    region: &'static str,
    item: &'static str,
    qty: u32,
}

fn main() {
    let sales = vec![
        Sale { region: "North", item: "apple", qty: 7 },
        Sale { region: "North", item: "banana", qty: 7 },
        Sale { region: "North", item: "apple", qty: 3 },
        Sale { region: "South", item: "banana", qty: 8 },
        Sale { region: "South", item: "apple", qty: 4 },
        Sale { region: "South", item: "banana", qty: 2 },
        Sale { region: "East", item: "kiwi", qty: 9 },
        Sale { region: "East", item: "pear", qty: 8 },
        Sale { region: "West", item: "pear", qty: 10 },
        Sale { region: "West", item: "apple", qty: 7 },
    ];

    let mut per_region: BTreeMap<&str, (u32, BTreeMap<&str, u32>)> = BTreeMap::new();
    for sale in &sales {
        let entry = per_region
            .entry(sale.region)
            .or_insert((0, BTreeMap::new()));
        entry.0 += 1;
        *entry.1.entry(sale.item).or_insert(0) += sale.qty;
    }

    let mut rows: Vec<(&str, u32, &str, usize)> = per_region
        .iter()
        .map(|(region, (count, items))| {
            let top_item = items
                .iter()
                .max_by_key(|(item, qty)| (*qty, *item))
                .map(|(item, _)| *item)
                .unwrap_or("");
            (*region, *count, top_item, items.len())
        })
        .collect();

    rows.sort_by(|a, b| {
        a.1.cmp(&b.1)
            .then(a.3.cmp(&b.3))
            .then(a.2.cmp(b.2))
            .then(a.0.cmp(b.0))
    });

    let output = rows
        .into_iter()
        .map(|(region, total, top_item, item_count)| {
            format!(
                "{} | total={} | top={} | items={}",
                region, total, top_item, item_count
            )
        })
        .collect::<Vec<_>>()
        .join("\n");

    println!("{}", output);
}

