struct Booking {
    room: &'static str,
    start: u32,
    end: u32,
}

fn overlaps(a: &Booking, b: &Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn can_book(existing: &[Booking], candidate: &Booking) -> bool {
    existing.iter().all(|b| !overlaps(b, candidate))
}

fn main() {
    let requests = [
        Booking { room: "roomA", start: 10, end: 12 },
        Booking { room: "roomA", start: 12, end: 14 },
        Booking { room: "roomA", start: 11, end: 13 },
