        Booking { room: "roomB", start: 11, end: 12 },
        Booking { room: "roomB", start: 10, end: 10 },
        Booking { room: "roomA", start: 14, end: 16 },
    ];

    let mut accepted: Vec<Booking> = Vec::new();
    let mut out = Vec::new();

    for req in requests {
        if can_book(&accepted, &req) {
            accepted.push(req);
            out.push(format!("{} {}-{} ok", req.room, req.start, req.end));
        } else {
            out.push(format!("{} {}-{} conflict", req.room, req.start, req.end));
        }
    }

    print!("{}", out.join("\n"));
}

