use std::collections::BTreeMap;

#[derive(Default, Clone, Copy)]
struct Stats {
    orders: u32,
    units: u32,
    revenue: u32,
}

fn main() {
    let data = [
        ("North", 2_u32, 10_u32, false),
        ("South", 1, 12, true),
        ("North", 3, 30, false),
        ("West", 5, 40, false),
        ("South", 4, 15, false),
    ];

    let mut by_region: BTreeMap<&str, Stats> = BTreeMap::new();
    let mut total = Stats::default();

    for (region, units, revenue, returned) in data {
        let entry = by_region.entry(region).or_default();
        entry.orders += 1;
        entry.units += 1;
        entry.revenue += revenue;

        total.orders += 1;
        total.units += 1;
        total.revenue += revenue;

        if returned {
            entry.revenue -= revenue;
            total.revenue -= revenue;
        }
    }

    let mut top_region = "";
    let mut top_revenue = 0_u32;

    for (region, stats) in &by_region {
        let avg_price = if stats.units == 0 {
            0.0
        } else {
            stats.revenue as f64 / stats.orders as f64
        };
        println!(
            "{} => orders={} units={} revenue={} avg_price={:.2}",
            region, stats.orders, stats.units, stats.revenue, avg_price
        );
        if stats.revenue >= top_revenue {
            top_revenue = stats.revenue;
            top_region = region;
        }
    }

    println!(
        "TOTAL => orders={} units={} revenue={}",
        total.orders, total.units, total.revenue
    );
    println!("TOP => {}", top_region);
}

use std::collections::BTreeMap;

fn apply_event(state: &str, event: &str) -> String {
    match event {
        "create" => "new".to_string(),
        "start" => "new".to_string(),
        "pause" => "paused".to_string(),
        "resume" => "paused".to_string(),
        "resolve" => "resolved".to_string(),
        "close" => state.to_string(),
        _ => state.to_string(),
    }
}

fn main() {
    let events = [
        ("A", "create"),
        ("A", "start"),
        ("A", "resolve"),
        ("A", "close"),
        ("B", "create"),
        ("B", "start"),
        ("B", "pause"),
        ("B", "resume"),
        ("B", "resolve"),
        ("B", "close"),
        ("C", "create"),
        ("C", "start"),
    ];

    let mut states: BTreeMap<&str, String> = BTreeMap::new();
    for (id, event) in events {
        let current = states.get(id).map(String::as_str).unwrap_or("missing");
        let next = apply_event(current, event);
        states.insert(id, next);
    }

    for (id, state) in states {
        println!("{}:{}", id, state);
    }
}

