fn is_valid_id(id: &str) -> bool {
    id.starts_with("EVT-")
}

fn parse_line(line: &str) -> Result<(String, String, u32), String> {
    let parts: Vec<&str> = line.split(',').collect();
    if parts.len() < 3 {
        return Err("bad_fields".to_string());
    }

    let id = parts[0].trim();
    let kind = parts[1].trim();
    let count: u32 = parts[2].trim().parse().map_err(|_| "bad_count".to_string())?;

    if !is_valid_id(id) {
        return Err("bad_id".to_string());
    }
    if count == 0 {
        return Err("bad_count".to_string());
    }

    Ok((id.to_string(), kind.to_string(), count))
}

fn main() {
    let mut valid = 0usize;
    let mut invalid = 0usize;
    let mut accepted = Vec::new();
    let mut rejected = Vec::new();

    for raw in INPUT.lines() {
