            continue;
        }
        match parse_line(raw) {
            Ok((id, _kind, _count)) => {
                valid += 1;
                accepted.push(id);
            }
            Err(reason) => {
                invalid += 1;
                let id = raw.split('|').next().unwrap_or("?");
                rejected.push(format!("{}:{}", id, reason));
            }
        }
    }

    println!("valid={} invalid={}", valid, invalid);
    println!("accepted_ids={}", accepted.join(","));
    println!("rejected={}", rejected.join(","));
}

