#[derive(Clone, Copy)]
struct Config {
    host: Option<&'static str>,
    port: Option<u16>,
    tls: Option<bool>,
    mode: Option<&'static str>,
    workers: Option<u8>,
}

fn merge(base: Config, file: Config, env: Config, cli: Config) -> Config {
    Config {
        host: cli.host.or(env.host).or(file.host).or(base.host),
        port: cli.port.or(file.port).or(env.port).or(base.port),
        tls: cli.tls.or(env.tls).or(file.tls).or(base.tls),
        mode: cli.mode.or(env.mode).or(file.mode).or(base.mode),
        workers: cli.workers.or(env.workers).or(file.workers).or(base.workers),
    }
}

fn finalize(mut cfg: Config) -> Config {
    if cfg.mode == Some("debug") && cfg.workers.is_none() {
        cfg.workers = Some(1);
    }
    cfg
}

