    writeln!(&mut out, "port={}", cfg.port.unwrap_or(80)).unwrap();
    writeln!(&mut out, "tls={}", cfg.tls.unwrap_or(false)).unwrap();
    writeln!(&mut out, "mode={}", cfg.mode.unwrap_or("release")).unwrap();
    write!(&mut out, "workers={}", cfg.workers.unwrap_or(4)).unwrap();
    out
}

