#[derive(Clone, Copy)]
struct Booking {
    room: char,
    start: u8,
    end: u8,
}

fn overlaps(a: &Booking, b: &Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn contains(a: &Booking, b: &Booking) -> bool {
    a.start <= b.start && a.end <= b.end
}

fn fmt_booking(b: &Booking) -> String {
    format!("room {} [{},{}]", b.room, b.start, b.end)
}

fn main() {
    let bookings = vec![
        Booking { room: 'A', start: 9, end: 12 },
        Booking { room: 'A', start: 12, end: 14 },
        Booking { room: 'A', start: 11, end: 13 },
        Booking { room: 'B', start: 10, end: 12 },
        Booking { room: 'B', start: 11, end: 14 },
        Booking { room: 'C', start: 8, end: 12 },
        Booking { room: 'C', start: 9, end: 11 },
    ];

    let mut conflicts = Vec::new();
    let mut contained = Vec::new();

    for i in 0..bookings.len() {
        for j in (i + 1)..bookings.len() {
            let a = bookings[i];
            let b = bookings[j];
            if a.room != b.room {
                continue;
            }
            if overlaps(&a, &b) {
                conflicts.push(format!("{} overlaps {}", fmt_booking(&a), fmt_booking(&b)));
            }
            if contains(&a, &b) {
                contained.push(format!("{} contains {}", fmt_booking(&a), fmt_booking(&b)));
            }
        }
    }

    println!("conflicts:");
    for line in conflicts {
        println!("{}", line);
    }
    println!("contained:");
    for line in contained {
        println!("{}", line);
    }
}

