use std::collections::BTreeMap;

#[derive(Clone, Copy, PartialEq, Eq)]
enum Status {
    Open,
    InProgress,
    Closed,
    Reopened,
}

impl Status {
    fn label(self) -> &'static str {
        match self {
            Status::Open => "Open",
            Status::InProgress => "InProgress",
            Status::Closed => "Closed",
            Status::Reopened => "Reopened",
        }
    }
}

fn main() {
    let events = [
        ("A", "create"),
        ("A", "start"),
        ("A", "resolve"),
        ("A", "reopen"),
        ("A", "resolve"),
        ("B", "create"),
        ("B", "close"),
        ("B", "reopen"),
        ("C", "create"),
    ];

    let mut tickets: BTreeMap<&str, Status> = BTreeMap::new();

    for (id, event) in events {
        let state = tickets.entry(id).or_insert(Status::Open);
        match event {
            "create" => *state = Status::InProgress,
            "start" => *state = Status::InProgress,
            "resolve" => *state = Status::Closed,
            "close" => *state = Status::Closed,
            "reopen" => *state = Status::Open,
            _ => {}
        }
    }

    for (id, state) in tickets {
        println!("{}:{}", id, state.label());
    }
}

