enum Command {
    Read { target: &'static str, cached: bool },
    Write { target: &'static str, dry_run: bool },
    Remove { target: &'static str, force: bool },
    Audit { label: &'static str, count: usize },
    Move { from: &'static str, to: &'static str },
}

enum Outcome {
    Applied(String),
    Skipped(String),
    Error(String),
}

fn execute(cmd: &Command) -> Outcome {
    match cmd {
        Command::Read { target, cached } => {
            if *cached {
                Outcome::Applied(format!("read {} => hits cache", target))
            } else {
                Outcome::Applied(format!("read {} => misses cache", target))
            }
        }
        Command::Write { target, dry_run } => {
            if *dry_run {
                Outcome::Applied(format!("write {} => saves {}", target, target))
            } else {
                Outcome::Skipped(format!("write {} => dry run", target))
            }
        }
        Command::Remove { target, force } => {
            if *force {
                Outcome::Skipped(format!("remove {} => blocked", target))
            } else {
                Outcome::Applied(format!("remove {} => removes {}", target, target))
            }
        }
        Command::Audit { label, count } => {
            Outcome::Applied(format!("audit {} => checks {} op", label, count))
        }
        Command::Move { from, to } => {
            Outcome::Applied(format!("move {} => {} -> {}", to, from, to))
        }
    }
}

fn render(outcomes: &[Outcome]) -> String {
    let mut lines = Vec::new();
    for outcome in outcomes {
        match outcome {
            Outcome::Applied(msg) | Outcome::Skipped(msg) => lines.push(msg.clone()),
            Outcome::Error(_) => {}
        }
    }
    lines.join("\n")
}

fn main() {
    let commands = vec![
        Command::Read {
            target: "cfg",
            cached: false,
        },
        Command::Write {
            target: "report",
            dry_run: false,
        },
        Command::Remove {
            target: "temp",
            force: true,
        },
        Command::Audit {
            label: "ops",
            count: 3,
        },
        Command::Move {
            from: "temp",
            to: "backup",
        },
    ];

    let outcomes: Vec<Outcome> = commands.iter().map(execute).collect();
    print!("{}", render(&outcomes));
}

