    format!("{:02}:{:02}", mins / 60, mins % 60)
}

fn overlaps(a: &Booking, b: &Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn main() {
    let bookings = vec![
        Booking { room: "A", start: 9 * 60, end: 10 * 60 },
        Booking { room: "A", start: 9 * 60 + 30, end: 11 * 60 },
        Booking { room: "A", start: 11 * 60, end: 12 * 60 },
        Booking { room: "A", start: 11 * 60 + 30, end: 12 * 60 + 30 },
        Booking { room: "B", start: 13 * 60, end: 14 * 60 },
        Booking { room: "B", start: 14 * 60, end: 15 * 60 },
        Booking { room: "B", start: 13 * 60 + 30, end: 15 * 60 },
    ];

    let mut lines = Vec::new();

    for room in ["A", "B"] {
        let room_bookings: Vec<&Booking> = bookings.iter().filter(|b| b.room == room).collect();
        let mut conflicts = Vec::new();

        for i in 0..room_bookings.len() {
            for j in i + 1..room_bookings.len() {
                let a = room_bookings[i];
                let b = room_bookings[j];
                if overlaps(a, b) {
                    conflicts.push(format!(
                        "{} {}-{} overlaps {} {}-{}",
                        a.room,
                        fmt_time(a.start),
                        fmt_time(a.end),
                        b.room,
                        fmt_time(b.start),
                        fmt_time(b.end)
                    ));
                }
            }
        }

        lines.push(format!("room {} conflicts: {}", room, room_bookings.len()));
        lines.extend(conflicts);
