#[derive(Debug)]
struct Record {
    id: String,
    kind: String,
    qty: u32,
}

fn parse_record(line: &str) -> Option<Record> {
    let mut id = None;
    let mut kind = None;
    let mut qty = None;

    for part in line.split('|') {
        let (key, value) = part.split_once('=')?;
        match key {
            "id" => id = Some(value.to_string()),
            "kind" => kind = Some(value.to_string()),
            "qty" => qty = value.parse::<u32>().ok(),
            _ => {}
        }
    }

    Some(Record {
        id: id?,
        kind: kind?,
        qty: qty?,
    })
}

fn main() {
    let mut valid = Vec::new();
    let mut invalid = 0;

    for line in INPUT.lines() {
        if let Some(rec) = parse_record(line) {
            valid.push(rec);
        } else {
            invalid += 1;
        }
    }

    println!("valid={} invalid={}", valid.len(), invalid);
    for rec in valid {
        println!("{}:{}:{}", rec.id, rec.kind, rec.qty);
    }
}

