    Start,
    Resolve,
    Reopen,
}

#[derive(Clone, Copy)]
enum Status {
    New,
    Open,
    InProgress,
    Closed,
}

fn apply(status: Status, event: Event) -> Status {
    match event {
        Event::Open => Status::New,
        Event::Start => Status::Open,
        Event::Resolve => Status::InProgress,
        Event::Reopen => Status::Closed,
    }
}

fn status_name(status: Status) -> &'static str {
    match status {
        Status::New => "New",
        Status::Open => "Open",
        Status::InProgress => "InProgress",
        Status::Closed => "Closed",
    }
}

fn main() {
