        ("C", Event::Start),
        ("C", Event::Resolve),
        ("C", Event::Reopen),
        ("C", Event::Resolve),
    ];

    let mut states = BTreeMap::new();
    for (id, event) in events {
        let current = states.get(id).copied().unwrap_or(Status::New);
        let next = apply(current, event);
