fn parse_line(line: &str) -> Result<(String, String, usize), String> {
    let mut id = String::new();
    let mut name = String::new();
    let mut score = 0usize;
    let mut tags = 0usize;

    for part in line.split(';') {
        let Some((k, v)) = part.split_once('=') else {
            return Err("MALFORMED".to_string());
        };
        match k {
            "id" => id = v.to_string(),
            "name" => name = v.to_string(),
            "score" => score = v.parse::<usize>().unwrap_or(0),
            "tags" => {
                tags = if v.is_empty() {
                    0
                } else {
                    v.split(',').count()
                }
            }
            _ => {}
        }
    }

    if id.is_empty() {
        return Err("MISSING_ID".to_string());
    }
    if score == 0 {
        return Err("MISSING_SCORE".to_string());
    }

    Ok((id, name, tags))
}

