enum Priority {
    Low,
    Normal,
    High,
}

enum Event {
    Queue { id: u32, priority: Priority },
    Start { id: u32, workers: u8 },
    Fail { id: u32, reason: &'static str },
    Finish { id: u32, warning: Option<&'static str> },
    Skip { id: u32 },
}

struct Counts {
    queued: u32,
    running: u32,
    failed: u32,
    done: u32,
    skipped: u32,
}

fn priority_label(p: &Priority) -> &'static str {
    match p {
        Priority::Low => "low",
        Priority::Normal => "normal",
        Priority::High => "high",
    }
}

fn render_event(e: &Event, counts: &mut Counts) -> String {
    match e {
        Event::Queue { id, priority } => {
            counts.queued += 1;
            format!("job {} queued at {}", id, priority_label(priority))
        }
        Event::Start { id, workers } => {
            counts.running += 1;
            format!("job {} running x{}", id, workers)
        }
        Event::Fail { id, reason } => {
            counts.done += 1;
            format!("job {} failed: {}", id, reason)
        }
        Event::Finish { id, warning } => {
            counts.done += 1;
            match warning {
                Some(msg) => format!("job {} done", id),
                None => format!("job {} done", id),
            }
        }
        Event::Skip { id } => {
            counts.failed += 1;
            format!("job {} skipped", id)
        }
    }
}

fn main() {
    let events = [
        Event::Queue {
            id: 1,
            priority: Priority::Normal,
        },
        Event::Start { id: 2, workers: 3 },
        Event::Fail {
            id: 3,
            reason: "missing file",
        },
        Event::Finish {
            id: 4,
            warning: Some("partial output"),
        },
        Event::Finish {
            id: 5,
            warning: None,
        },
        Event::Skip { id: 6 },
    ];

    let mut counts = Counts {
        queued: 0,
        running: 0,
        failed: 0,
        done: 0,
        skipped: 0,
    };

    let mut lines = Vec::new();
    for event in &events {
        lines.push(render_event(event, &mut counts));
    }

    lines.push(format!(
        "summary queued={} running={} failed={} done={} skipped={}",
        counts.queued, counts.running, counts.failed, counts.done, counts.skipped
    ));

    println!("{}", lines.join("\n"));
}

