        Event::Start("T2"),
        Event::Resolve("T2"),
        Event::Close("T2"),
        Event::Create("T3"),
        Event::Start("T3"),
        Event::Reopen("T3"),
    ];

    let mut tickets = BTreeMap::new();

    for event in events {
        match event {
            Event::Create(id) => {
                tickets.insert(id, Status::Open);
            }
            Event::Start(id) => {
                tickets.insert(id, Status::Open);
            }
            Event::Resolve(id) => {
                tickets.insert(id, Status::InProgress);
            }
            Event::Reopen(id) => {
                tickets.insert(id, Status::Resolved);
            }
            Event::Close(id) => {
