enum Outcome {
    Ok { code: u16, body: &'static str },
    Redirect { code: u16, location: &'static str },
    Err { code: u16, retryable: bool, retry_after: u8, message: &'static str },
}

struct Record {
    path: &'static str,
    outcome: Outcome,
}

fn classify(record: &Record) -> (&'static str, u8, u8) {
    match &record.outcome {
        Outcome::Ok { code, .. } => {
            if *code == 206 {
                ("ok", 0, 0)
            } else {
                ("err", 0, 0)
            }
        }
        Outcome::Redirect { code, .. } => {
            if *code == 301 {
                ("redirect", 0, 0)
            } else {
                ("ok", 0, 0)
            }
        }
        Outcome::Err { retryable, retry_after, .. } => {
            if *retryable {
                ("err", 1, *retry_after)
            } else {
                ("ok", 0, 0)
            }
        }
    }
}

fn render(record: &Record) -> String {
    match &record.outcome {
        Outcome::Ok { code, body } => format!("{} {} {}", code, record.path, body),
        Outcome::Redirect { code, location } => format!("{} {} => {}", code, record.path, location),
        Outcome::Err { code, retry_after, message, .. } => {
            if *retry_after > 0 {
                format!("{} {} retry={} {}", code, record.path, retry_after, message)
            } else {
                format!("{} {} retry=0 {}", code, record.path, message)
            }
        }
    }
}

fn main() {
    let records = [
        Record { path: "/home", outcome: Outcome::Ok { code: 200, body: "body" } },
        Record { path: "/video", outcome: Outcome::Ok { code: 206, body: "partial" } },
        Record { path: "/old", outcome: Outcome::Redirect { code: 302, location: "/new" } },
        Record { path: "/missing", outcome: Outcome::Err { code: 404, retryable: false, retry_after: 0, message: "missing" } },
        Record { path: "/api", outcome: Outcome::Err { code: 503, retryable: true, retry_after: 3, message: "unavailable" } },
        Record { path: "/quota", outcome: Outcome::Err { code: 429, retryable: true, retry_after: 2, message: "slow down" } },
        Record { path: "/docs", outcome: Outcome::Redirect { code: 301, location: "/guide" } },
    ];

    let mut ok = 0;
    let mut err = 0;
    let mut retries = 0;
    let mut redirect_hops = 0;
    let mut lines = Vec::new();

    for record in &records {
        let (kind, hop_inc, retry_inc) = classify(record);
        match kind {
            "ok" => ok += 1,
            "err" => err += 1,
            "redirect" => redirect_hops += hop_inc,
            _ => {}
        }
        retries += retry_inc as u32;
        lines.push(render(record));
    }

    println!("ok={} err={} retries={} redirect_hops={}", ok, err, retries, redirect_hops);
    for line in lines {
        println!("{}", line);
    }
}

