            State::Closed => "Closed",
        }
    }
}

fn main() {
    let events = [
        ("A", "create"),
        ("A", "start"),
        ("A", "close"),
        ("B", "create"),
        ("B", "close"),
        ("B", "reopen"),
        ("C", "create"),
        ("C", "start"),
    ];

    let mut tickets: BTreeMap<&str, State> = BTreeMap::new();

    for (id, action) in events {
        let next = match action {
            "create" => State::InProgress,
            "start" => State::Closed,
            "close" => State::Closed,
            "reopen" => State::Closed,
            _ => continue,
        };
        tickets.insert(id, next);
    }

    let mut out = String::new();
    for (id, state) in tickets {
        out.push_str(&format!("{}:{}\n", id, state.as_str()));
    }
    print!("{}", out);
}

