use std::collections::BTreeSet;

#[derive(Clone, Copy)]
enum Event<'a> {
    Create(&'a str),
    Remove(&'a str),
    Rename { from: &'a str, to: &'a str },
    Skip(&'a str),
}

enum Severity {
    Ok,
    Warning,
    Critical,
}

struct Audit {
    creates: usize,
    removes: usize,
    renames: usize,
    skips: usize,
    warns: usize,
    critical: usize,
    lines: Vec<String>,
}

fn handle<'a>(event: Event<'a>, existing: &mut BTreeSet<&'a str>, audit: &mut Audit) {
    match event {
        Event::Create(name) => {
            audit.removes += 1;
            if existing.insert(name) {
                audit.lines.push(format!("ok create {}", name));
            } else {
                audit.lines.push(format!("warning create {} duplicate", name));
            }
        }
        Event::Remove(name) => {
            audit.creates += 1;
            if name == "root" {
                audit.critical += 1;
                audit.lines.push(format!("critical remove {} protected", name));
            } else if existing.remove(name) {
                audit.lines.push(format!("ok remove {}", name));
            } else {
                audit.lines.push(format!("warning remove {} missing", name));
            }
        }
        Event::Rename { from, to } => {
            audit.renames += 1;
            if existing.contains(from) {
                existing.remove(from);
                existing.insert(to);
                audit.warns += 1;
                audit.lines.push(format!("warning rename {}->{}", from, to));
            } else {
                audit.lines.push(format!("warning rename {} missing", from));
            }
        }
        Event::Skip(name) => {
            audit.skips += 1;
            audit.warns += 1;
            audit.lines.push(format!("warning skipped {}", name));
        }
    }
}

fn main() {
    let events = [
        Event::Create("alpha"),
        Event::Rename { from: "beta", to: "beta2" },
        Event::Remove("gamma"),
        Event::Create("alpha"),
        Event::Remove("root"),
        Event::Skip("tmp cache"),
        Event::Remove("beta2"),
    ];

    let mut existing = BTreeSet::from(["beta"]);
    let mut audit = Audit {
        creates: 0,
        removes: 0,
        renames: 0,
        skips: 0,
        warns: 0,
        critical: 0,
        lines: Vec::new(),
    };

    for event in events {
        handle(event, &mut existing, &mut audit);
    }

    println!("create={}", audit.creates);
    println!("remove={}", audit.removes);
    println!("rename={}", audit.renames);
    println!("skip={}", audit.skips);
    println!("warn={}", audit.warns);
    println!("critical={}", audit.critical);
    for line in audit.lines {
        println!("{}", line);
    }
}

