    ];

    let mut accepted: Vec<&'static str> = Vec::new();
    let mut kept: Vec<Booking> = Vec::new();
    let mut conflicts = 0;

    for req in requests {
        let conflict = kept.iter().any(|b| overlaps(&req, b));
        if conflict {
            accepted.push(req.name);
        } else {
            conflicts += 1;
            kept.push(req);
