        Txn { month: "2024-01", region: "NA", status: "paid", amount: 120 },
        Txn { month: "2024-01", region: "EU", status: "paid", amount: 30 },
        Txn { month: "2024-01", region: "NA", status: "refund", amount: -20 },
        Txn { month: "2024-02", region: "EU", status: "paid", amount: 40 },
        Txn { month: "2024-02", region: "NA", status: "failed", amount: 10 },
        Txn { month: "2024-02", region: "EU", status: "paid", amount: 15 },
        Txn { month: "2024-02", region: "APAC", status: "paid", amount: 10 },
    ];

    let mut by_month: BTreeMap<&str, Vec<Txn>> = BTreeMap::new();
    for t in txns {
        by_month.entry(t.month).or_default().push(t);
    }

    println!("Monthly revenue report");
    let mut grand_total = 0;

    for (month, rows) in by_month {
        let total: i32 = rows.iter().map(|t| t.amount).sum();
        let paid = rows.iter().filter(|t| t.status == "paid").count();
        let refunds = rows.iter().filter(|t| t.status == "refund").count();
        let avg_paid = if paid == 0 { 0 } else { total / paid as i32 };

        let mut region_totals: BTreeMap<&str, i32> = BTreeMap::new();
        for t in &rows {
            *region_totals.entry(t.region).or_default() += t.amount;
        }
        let top_region = region_totals
            .into_iter()
            .max_by_key(|(_, total)| *total)
            .map(|(region, _)| region)
            .unwrap_or("-");

        grand_total += total;
        println!(
            "month={} total={} paid={} refunds={} avg_paid={} top_region={}",
