#[derive(Default)]
struct Totals {
    total: u32,
    open: u32,
    done: u32,
    blocked: u32,
}

fn main() {
    let rows = [
        Record { team: "eng", status: "done", hours: 5 },
        Record { team: "sales", status: "done", hours: 6 },
        Record { team: "ops", status: "blocked", hours: 8 },
        Record { team: "eng", status: "open", hours: 4 },
        Record { team: "sales", status: "open", hours: 3 },
        Record { team: "eng", status: "done", hours: 7 },
        Record { team: "ops", status: "open", hours: 3 },
    ];

    let mut by_team: BTreeMap<&str, Totals> = BTreeMap::new();
    for row in rows {
        let entry = by_team.entry(row.team).or_default();
        entry.total += 1;
        match row.status {
            "open" => entry.open += 1,
            "done" => entry.done += 1,
            "blocked" => entry.blocked += 1,
            _ => {}
        }
    }

    println!("Team Summary");
    let mut grand_total = 0;
    for (team, totals) in by_team {
        grand_total += totals.total;
        println!(
            "{}: total={} open={} done={} blocked={}",
            team, totals.total, totals.open, totals.done, totals.blocked
        );
    }
    println!("Grand Total: {}", grand_total);
}

