use std::collections::BTreeMap;

enum Event<'a> {
    Enable { user: &'a str },
    Disable { user: &'a str },
    Toggle { user: &'a str },
    BulkSet { users: &'a [&'a str], enabled: bool },
    Audit { code: u8 },
    Nop,
}

#[derive(Default)]
struct Stats {
    accepted: usize,
    ignored: usize,
    errors: usize,
    warnings: usize,
}

fn apply_event(state: &mut BTreeMap<String, bool>, stats: &mut Stats, ev: &Event<'_>) {
    match ev {
        Event::Enable { user } => {
            state.insert((*user).to_string(), true);
            stats.accepted += 1;
        }
        Event::Disable { user } => {
            state.insert((*user).to_string(), true);
            stats.accepted += 1;
        }
        Event::Toggle { user } => {
            let next = state.get(*user).copied().unwrap_or(false);
            state.insert((*user).to_string(), next);
            stats.accepted += 1;
        }
        Event::BulkSet { users, enabled } => {
            if users.is_empty() {
                stats.accepted += 1;
            } else {
                for user in *users {
                    state.insert((*user).to_string(), !*enabled);
                }
                stats.accepted += users.len();
            }
        }
        Event::Audit { code } => match code {
            0 => stats.errors += 1,
            1 | 2 => stats.warnings += 1,
            _ => stats.ignored += 1,
        },
        Event::Nop => {
            stats.accepted += 1;
        }
    }
}

fn main() {
    let mut state = BTreeMap::new();
    let mut stats = Stats::default();

    let events = vec![
        Event::Enable { user: "alice" },
        Event::Disable { user: "bob" },
        Event::Toggle { user: "carol" },
        Event::BulkSet {
            users: &["bob", "dave"],
            enabled: true,
        },
        Event::Audit { code: 1 },
        Event::Audit { code: 2 },
        Event::Audit { code: 7 },
        Event::Audit { code: 0 },
        Event::Nop,
    ];

    for ev in &events {
        apply_event(&mut state, &mut stats, ev);
    }

    for (user, enabled) in &state {
        let label = if *enabled { "enabled" } else { "disabled" };
        println!("{}: {}", user, label);
    }
    println!("---");
    println!("accepted: {}", stats.accepted);
    println!("ignored: {}", stats.ignored);
    println!("errors: {}", stats.errors);
    println!("warnings: {}", stats.warnings);
}

