use std::fmt::Write;

#[derive(Clone, Debug)]
struct Config {
    mode: Option<&'static str>,
    retries: Option<u32>,
    timeout: Option<u32>,
    color: Option<&'static str>,
    plugins: Vec<&'static str>,
    disable_plugins: Vec<&'static str>,
    lock_timeout: bool,
}

impl Config {
    fn empty() -> Self {
        Self {
            mode: None,
            retries: None,
            timeout: None,
            color: None,
            plugins: Vec::new(),
            disable_plugins: Vec::new(),
            lock_timeout: false,
        }
    }
}

fn merge(base: &mut Config, layer: &Config) {
    if base.mode.is_none() {
        base.mode = layer.mode;
    }
    if base.retries.is_none() {
        base.retries = layer.retries;
    }
    if base.timeout.is_none() {
        base.timeout = layer.timeout;
    }
    if base.color.is_none() {
        base.color = layer.color;
    }
    for p in &layer.plugins {
        if !base.plugins.contains(p) {
            base.plugins.push(*p);
        }
    }
    for p in &layer.disable_plugins {
        if !base.disable_plugins.contains(p) {
            base.disable_plugins.push(*p);
        }
    }
    base.lock_timeout = base.lock_timeout && layer.lock_timeout;
}

fn render(cfg: &Config) -> String {
    let mut out = String::new();
    writeln!(&mut out, "mode={}", cfg.mode.unwrap_or("safe")).unwrap();
    writeln!(&mut out, "retries={}", cfg.retries.unwrap_or(1)).unwrap();
    writeln!(&mut out, "timeout={}", cfg.timeout.unwrap_or(30)).unwrap();
    writeln!(&mut out, "color={}", cfg.color.unwrap_or("auto")).unwrap();
    write!(&mut out, "plugins={}", cfg.plugins.join(",")).unwrap();
    out
}

