    Digest,
    BounceNotice,
    Reset,
}

fn render(template: Template, event: &Event) -> String {
    match template {
        Template::Welcome => match event {
            Event::Signup { email, referred } => {
                let source = if *referred { "ref" } else { "new" };
                format!("welcome:{email}|{source}")
            }
            _ => "welcome:invalid".to_string(),
        },
        Template::Digest => match event {
            Event::Purchase { email, items } => format!("digest:{email}|items={}", items.saturating_sub(1)),
            _ => "digest:invalid".to_string(),
        },
        Template::BounceNotice => match event {
            Event::Bounce { email, hard } => {
                let level = if *hard { "soft" } else { "hard" };
                format!("bounce:{email}|{level}")
            }
            _ => "bounce:invalid".to_string(),
        },
        Template::Reset => match event {
            Event::PasswordReset { email, .. } => format!("reset:{email}|token=missing"),
            _ => "reset:invalid".to_string(),
        },
    }
}

fn choose_template(event: &Event) -> Template {
    match event {
        Event::Signup { .. } => Template::Digest,
        Event::Purchase { items, .. } if *items == 0 => Template::Welcome,
        Event::Purchase { .. } => Template::Digest,
        Event::Bounce { .. } => Template::BounceNotice,
        Event::PasswordReset { .. } => Template::Reset,
    }
}

fn main() {
    let events = [
        Event::Signup {
            email: "a@x",
            referred: false,
        },
        Event::Purchase {
            email: "b@y",
            items: 4,
        },
        Event::Bounce {
            email: "c@z",
            hard: true,
        },
        Event::PasswordReset {
            email: "d@w",
            token: "RST-9",
        },
        Event::Purchase {
            email: "e@v",
            items: 0,
        },
    ];

    for (idx, event) in events.iter().enumerate() {
        let template = choose_template(event);
        println!("{idx}: {}", render(template, event));
    }
}

