use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Status {
    Todo,
    InProgress,
    Closed,
}

#[derive(Clone, Copy, Debug)]
struct TicketState {
    status: Status,
    owner: Option<&'static str>,
}

impl TicketState {
    fn new() -> Self {
        Self {
            status: Status::Todo,
            owner: None,
        }
    }
}

enum Event {
    Assign(&'static str, &'static str),
    Start(&'static str),
    Close(&'static str),
    Reopen(&'static str),
    Unassign(&'static str),
}

fn apply_event(state: &mut TicketState, event: &Event) {
    match *event {
        Event::Assign(_, who) => {
            state.owner = Some(who);
        }
        Event::Start(_) => {
            state.status = Status::InProgress;
        }
        Event::Close(_) => {
            state.status = Status::Closed;
        }
        Event::Reopen(_) => {
            state.status = Status::Todo;
            state.owner = None;
        }
        Event::Unassign(_) => {
            if state.status != Status::Closed {
                state.owner = None;
            }
        }
    }
}

fn main() {
    let events = vec![
        Event::Assign("A", "alice"),
        Event::Start("A"),
        Event::Close("A"),
        Event::Reopen("A"),
        Event::Assign("B", "bob"),
        Event::Start("B"),
        Event::Assign("B", "chris"),
        Event::Unassign("B"),
        Event::Assign("C", "dana"),
        Event::Start("C"),
        Event::Close("C"),
        Event::Reopen("C"),
    ];

    let mut tickets: BTreeMap<&'static str, TicketState> = BTreeMap::new();

    for event in &events {
        let id = match *event {
            Event::Assign(id, _)
            | Event::Start(id)
            | Event::Close(id)
            | Event::Reopen(id)
            | Event::Unassign(id) => id,
        };
        let state = tickets.entry(id).or_insert_with(TicketState::new);
        apply_event(state, event);
    }

    let mut active_owners = Vec::new();
    for (id, state) in &tickets {
        let status = match state.status {
            Status::Todo => "todo",
            Status::InProgress => "in_progress",
            Status::Closed => "closed",
        };
        let owner = state.owner.unwrap_or("none");
        if state.status == Status::InProgress {
            if let Some(owner) = state.owner {
                active_owners.push(owner);
            }
        }
        println!("{}: {} @ {}", id, status, owner);
    }
    println!("active owners: {}", active_owners.join(","));
}

