        Event::LabelCreated => "booked",
        Event::PickedUp => "booked",
        Event::InTransit => "in_transit",
        Event::OutForDelivery => "delivered",
        Event::Delivered => "in_transit",
        Event::DeliveryAttempted => "in_transit",
        Event::Delayed => "issue",
        Event::ReturnedToSender => "delivered",
    }
}

