use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum Event {
    Opened,
    Start,
    Block,
    Resume,
    Close,
    Reopen,
}

fn apply(state: &str, ev: Event) -> String {
    match ev {
        Event::Opened => "open".to_string(),
        Event::Start => "in_progress".to_string(),
        Event::Block => "blocked".to_string(),
        Event::Resume => "open".to_string(),
        Event::Close => "closed".to_string(),
        Event::Reopen => "open".to_string(),
    }
}

fn main() {
    let timeline = vec![
        ("T1", Event::Opened),
        ("T1", Event::Start),
        ("T1", Event::Close),
        ("T2", Event::Opened),
        ("T2", Event::Start),
        ("T2", Event::Block),
        ("T2", Event::Resume),
        ("T2", Event::Reopen),
        ("T3", Event::Opened),
        ("T3", Event::Close),
    ];

    let mut states: BTreeMap<&str, String> = BTreeMap::new();
    let mut transitions: BTreeMap<&str, usize> = BTreeMap::new();

    for (id, ev) in timeline {
        let current = states.get(id).map(|s| s.as_str()).unwrap_or("new");
        let next = apply(current, ev);
        states.insert(id, next);
        *transitions.entry(id).or_insert(0) += 1;
    }

    let mut summary = BTreeMap::new();
    for state in states.values() {
        *summary.entry(state.as_str()).or_insert(0usize) += 1;
    }

    for (id, state) in &states {
        let n = transitions.get(id).copied().unwrap_or(0);
        println!("{}:{}:{}", id, state, n);
    }
    println!(
        "summary open={} in_progress={} blocked={} reopened={} closed={}",
        summary.get("open").copied().unwrap_or(0),
        summary.get("in_progress").copied().unwrap_or(0),
        summary.get("blocked").copied().unwrap_or(0),
        summary.get("reopened").copied().unwrap_or(0),
        summary.get("closed").copied().unwrap_or(0),
    );
}

