        "alpha:2",
        "beta:1",
        "skip:10",
        "alpha:3",
        "gamma:2",
        "beta:0",
        "beta:3",
        "bad",
        "alpha:-1",
        "gamma:x",
        "delta:4",
        "beta:1",
    ];

    let report = rows
        .iter()
        .filter_map(|row| row.split_once(':'))
        .filter(|(tag, _)| *tag != "skip")
        .filter_map(|(tag, n)| n.parse::<i32>().ok().map(|value| (*tag, value)))
        .filter(|(_, value)| *value >= 0)
        .fold(Vec::<(&str, i32)>::new(), |mut acc, (tag, value)| {
            if let Some((_, total)) = acc.iter_mut().find(|(name, _)| *name == tag) {
                *total += value;
            } else {
                acc.push((tag, value));
            }
            acc
        })
        .into_iter()
        .filter(|(_, total)| *total > 0)
        .map(|(tag, total)| format!("{}={}", tag, total))
        .collect::<Vec<_>>()
        .join(",");

    println!("{}", report);
}

enum Action {
    Accept { bytes: u32, note: &'static str },
    Reject { code: u16 },
    Delay(u8),
    Drop,
}

fn classify(action: &Action) -> (&'static str, i32, Option<&'static str>) {
    match action {
        Action::Accept { bytes, note } => {
            let delta = if *bytes >= 100 { 2 } else { 1 };
            ("allow", delta, Some(*note))
        }
        Action::Reject { code } => {
            if *code >= 500 {
                ("deny", -3, None)
            } else {
                ("deny", -1, None)
            }
        }
        Action::Delay(secs) => {
            if *secs >= 5 {
                ("delay", 0, None)
            } else {
                ("allow", 0, None)
            }
        }
        Action::Drop => ("deny", -2, None),
    }
}

fn main() {
    let actions = [
        Action::Accept {
            bytes: 120,
            note: "alpha",
        },
        Action::Reject { code: 403 },
        Action::Delay(7),
        Action::Drop,
        Action::Accept {
            bytes: 20,
            note: "beta",
        },
        Action::Delay(1),
        Action::Accept {
            bytes: 100,
            note: "gamma",
        },
    ];

    let mut allow = 0;
    let mut deny = 0;
    let mut throttle = 0;
    let mut drops = 0;
    let mut net = 0;
    let mut notes: Vec<&'static str> = Vec::new();

    for action in actions.iter() {
        let (label, delta, note) = classify(action);
        match label {
            "allow" => allow += 1,
            "deny" => deny += 1,
            "throttle" => throttle += 1,
            _ => {}
        }

        if let Action::Drop = action {
            drops += 1;
        }

        if let Some(note) = note {
            notes.push(note);
        }

        net += delta;
    }

    println!("allow={}", allow);
    println!("deny={}", deny);
    println!("throttle={}", throttle);
    println!("drops={}", drops);
    println!("net={:+}", net);
    println!("notes={}", notes.join(","));
}

