struct Booking {
    name: &'static str,
    start: u32,
    end: u32,
}

fn overlaps(a: &Booking, b: &Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn conflicts_for<'a>(target: &'a Booking, all: &'a [Booking]) -> Vec<&'a str> {
    let mut out = Vec::new();
    for booking in all {
        if booking.name == target.name {
            continue;
        }
        if overlaps(target, booking) {
            out.push(target.name);
        }
    }
    out.sort();
    out
}

fn main() {
    let bookings = vec![
        Booking { name: "alpha", start: 60, end: 120 },
        Booking { name: "beta", start: 120, end: 180 },
        Booking { name: "gamma", start: 180, end: 210 },
        Booking { name: "delta", start: 90, end: 150 },
        Booking { name: "epsilon", start: 30, end: 70 },
    ];

    for i in 0..bookings.len() {
        for j in i + 1..bookings.len() {
            println!(
                "{}-{}={}",
                bookings[i].name,
                bookings[j].name,
                overlaps(&bookings[i], &bookings[j])
            );
        }
    }

    let alpha = &bookings[0];
    let list = conflicts_for(alpha, &bookings);
    println!("conflicts_for_{}={}", alpha.name, list.join("|"));
}

