use std::fmt;

#[derive(Clone, Copy)]
enum Source {
    Default,
    File,
    Env,
    Cli,
}

impl fmt::Display for Source {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        let s = match self {
            Source::Default => "default",
            Source::File => "file",
            Source::Env => "env",
            Source::Cli => "cli",
        };
        f.write_str(s)
    }
}

#[derive(Clone, Copy)]
struct Setting<T: Copy> {
    value: T,
    source: Source,
}

#[derive(Clone, Copy)]
struct Config {
    mode: Setting<&'static str>,
    retries: Setting<u32>,
    timeout: Setting<u32>,
    cache: Setting<bool>,
}

fn merge(base: Config, file: Option<Config>, env: Option<Config>, cli: Option<Config>) -> Config {
    let mut cfg = base;
    if let Some(layer) = cli {
        cfg.mode = layer.mode;
        cfg.retries = layer.retries;
        cfg.timeout = layer.timeout;
        cfg.cache = layer.cache;
    }
    if let Some(layer) = env {
        cfg.mode = layer.mode;
        cfg.retries = layer.retries;
        cfg.timeout = layer.timeout;
        cfg.cache = layer.cache;
    }
    if let Some(layer) = file {
        cfg.mode = layer.mode;
        cfg.retries = layer.retries;
        cfg.timeout = layer.timeout;
        cfg.cache = layer.cache;
    }
    cfg
}

fn main() {
    let defaults = Config {
        mode: Setting { value: "safe", source: Source::Default },
        retries: Setting { value: 3, source: Source::Default },
        timeout: Setting { value: 30, source: Source::Default },
        cache: Setting { value: false, source: Source::Default },
    };

    let file = Some(Config {
        mode: Setting { value: "balanced", source: Source::File },
        retries: Setting { value: 4, source: Source::File },
        timeout: Setting { value: 60, source: Source::File },
        cache: Setting { value: false, source: Source::File },
    });

    let env = Some(Config {
        mode: Setting { value: "fast", source: Source::Env },
        retries: Setting { value: 4, source: Source::Env },
        timeout: Setting { value: 45, source: Source::Env },
        cache: Setting { value: false, source: Source::Env },
    });

    let cli = Some(Config {
        mode: Setting { value: "balanced", source: Source::Cli },
        retries: Setting { value: 5, source: Source::Cli },
        timeout: Setting { value: 60, source: Source::Cli },
        cache: Setting { value: true, source: Source::Cli },
    });

    let merged = merge(defaults, file, env, cli);
    println!("mode={} ({})", merged.mode.value, merged.mode.source);
    println!("retries={} ({})", merged.retries.value, merged.retries.source);
    println!("timeout={} ({})", merged.timeout.value, merged.timeout.source);
    println!("cache={} ({})", merged.cache.value, merged.cache.source);
}

