#[derive(Clone, Copy)]
struct Request {
    id: &'static str,
    start: u32,
    end: u32,
}

#[derive(Clone, Copy)]
struct Booking {
    id: &'static str,
    start: u32,
    end: u32,
}

fn overlaps(a: &Booking, b: &Request) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn contains_request(existing: &Booking, req: &Request) -> bool {
    req.start <= existing.start && req.end >= existing.end
}

fn touches_existing(existing: &Booking, req: &Request) -> bool {
    existing.end == req.start || req.end == existing.start
}

fn main() {
    let requests = [
        Request { id: "A", start: 10, end: 12 },
        Request { id: "B", start: 12, end: 14 },
        Request { id: "C", start: 14, end: 16 },
        Request { id: "D", start: 9, end: 17 },
        Request { id: "E", start: 16, end: 18 },
        Request { id: "F", start: 20, end: 22 },
        Request { id: "G", start: 18, end: 20 },
        Request { id: "H", start: 12, end: 14 },
        Request { id: "I", start: 22, end: 24 },
    ];

    let mut accepted: Vec<Booking> = Vec::new();
    let mut rejected: Vec<String> = Vec::new();

    for req in requests {
        let mut reason = None;

        for existing in &accepted {
            if overlaps(existing, &req) {
                reason = Some("overlap");
                break;
            }
            if contains_request(existing, &req) {
                reason = Some("contains-existing");
                break;
            }
            if touches_existing(existing, &req) {
                reason = Some("touching");
                break;
            }
            if existing.id == req.id {
                reason = Some("duplicate-id");
                break;
            }
        }

        match reason {
            Some(r) => rejected.push(format!("{}:{}", req.id, r)),
            None => accepted.push(Booking {
                id: req.id,
                start: req.start,
                end: req.end,
            }),
        }
    }

    let accepted_ids = accepted.iter().map(|b| b.id).collect::<Vec<_>>().join(",");
    println!("accepted: {}", accepted_ids);
    println!("rejected: {}", rejected.join(","));
}

