use std::collections::BTreeMap;

#[derive(Clone, Copy, PartialEq, Eq)]
enum State {
    Open,
    InProgress,
    Blocked,
    Closed,
}

impl State {
    fn as_str(&self) -> &'static str {
        match self {
            State::Open => "Open",
            State::InProgress => "InProgress",
            State::Blocked => "Blocked",
            State::Closed => "Closed",
        }
    }
}

fn main() {
    let events = [
        "A:create",
        "A:start",
        "A:block",
        "A:resume",
        "A:close",
        "B:create",
        "B:start",
        "B:close",
        "C:create",
        "C:block",
        "C:resume",
        "C:close",
        "D:create",
        "D:start",
        "D:reopen",
    ];

    let mut tickets: BTreeMap<&str, State> = BTreeMap::new();

    for line in events {
        let (id, action) = line.split_once(':').unwrap();
        let current = tickets.get(id).copied().unwrap_or(State::Open);
        let next = match action {
            "create" => current,
            "start" => State::Open,
            "block" => State::Blocked,
            "resume" => State::Open,
            "close" => State::Closed,
            "reopen" => State::Closed,
            _ => current,
        };
        tickets.insert(id, next);
    }

    let mut open = 0;
    let mut progress = 0;
    let mut blocked = 0;
    let mut closed = 0;

    for (id, state) in &tickets {
        println!("{}:{}", id, state.as_str());
        match state {
            State::Open => open += 1,
            State::InProgress => progress += 1,
            State::Blocked => blocked += 1,
            State::Closed => blocked += 1,
        }
    }

    println!(
        "Open={} InProgress={} Blocked={} Closed={}",
        open, progress, blocked, closed
    );
}

