        "ops,1,hold",
    ];

    let mut totals: Vec<(String, i32)> = rows
        .iter()
        .filter_map(|line| {
            let mut parts = line.split(',');
            let team = parts.next()?;
            let score = parts.next()?.parse::<i32>().ok()?;
            let tag = parts.next()?;
            Some((team.to_string(), score, tag.to_string()))
        })
        .filter(|(_, score, _)| *score >= 4)
        .fold(Vec::new(), |mut acc, (team, score, _)| {
            if let Some((_, total)) = acc.iter_mut().find(|(name, _)| name == &team) {
                *total += score;
            } else {
                acc.push((team, score));
            }
            acc
        });

    totals.sort_by(|a, b| a.0.cmp(&b.0));

    let out = totals
        .into_iter()
        .map(|(team, total)| format!("{}={}", team, total))
        .collect::<Vec<_>>()
        .join("\n");

    println!("{}", out);
}

