    color: &'static str,
    endpoint: &'static str,
}

fn profile_config(name: &str) -> Config {
    match name {
        "dev" => Config {
            mode: "dev",
            retries: 1,
            color: "always",
            endpoint: "http://localhost:3000",
        },
        "staging" => Config {
            mode: "staging",
            retries: 4,
            color: "auto",
            endpoint: "https://api.staging.example",
        },
        _ => Config {
            mode: name,
            retries: 9,
            color: "always",
            endpoint: "https://fallback.invalid",
        },
    }
}

fn merge(
    defaults: Config,
    profile: &str,
    env_mode: Option<&str>,
    env_retries: Option<&str>,
    env_color: Option<&str>,
    cli_color: Option<&str>,
) -> Config {
    let mut cfg = defaults;

    if let Some(m) = env_mode {
        cfg.mode = m;
    }
    if let Some(r) = env_retries {
        if let Ok(v) = r.parse::<u8>() {
            cfg.retries = v;
        }
    }
    if let Some(c) = env_color {
        cfg.color = c;
    }

    let p = profile_config(profile);
    cfg.mode = p.mode;
    cfg.retries = p.retries;
    cfg.color = p.color;
    cfg.endpoint = p.endpoint;

    if let Some(c) = cli_color {
        cfg.color = c;
    }

    cfg
}

