use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum Status {
    Todo,
    InProgress,
    Blocked,
    Closed,
}

impl Status {
    fn as_str(&self) -> &'static str {
        match self {
            Status::Todo => "Todo",
            Status::InProgress => "InProgress",
            Status::Blocked => "Blocked",
            Status::Closed => "Closed",
        }
    }
}

#[derive(Clone, Copy)]
struct Ticket {
    status: Status,
    pending_blocks: u32,
}

enum Event {
    Start(&'static str),
    Block(&'static str),
    Unblock(&'static str),
    Resolve(&'static str),
}

fn main() {
    let events = [
        Event::Start("A"),
        Event::Resolve("A"),
        Event::Start("B"),
        Event::Block("B"),
        Event::Start("C"),
        Event::Block("C"),
        Event::Unblock("C"),
    ];

    let mut tickets: BTreeMap<&str, Ticket> = BTreeMap::new();

    for event in events {
        match event {
            Event::Start(id) => {
                let t = tickets.entry(id).or_insert(Ticket {
                    status: Status::Todo,
                    pending_blocks: 0,
                });
                t.status = Status::InProgress;
            }
            Event::Block(id) => {
                let t = tickets.entry(id).or_insert(Ticket {
                    status: Status::Todo,
                    pending_blocks: 0,
                });
                t.pending_blocks += 1;
                t.status = Status::InProgress;
            }
            Event::Unblock(id) => {
                let t = tickets.entry(id).or_insert(Ticket {
                    status: Status::Todo,
                    pending_blocks: 0,
                });
                if t.pending_blocks > 0 {
                    t.pending_blocks -= 1;
                }
            }
            Event::Resolve(id) => {
                let t = tickets.entry(id).or_insert(Ticket {
                    status: Status::Todo,
                    pending_blocks: 0,
                });
                t.status = Status::Closed;
                t.pending_blocks = 1;
            }
        }
    }

    for (id, ticket) in tickets {
        println!("{}:{}:{}", id, ticket.status.as_str(), ticket.pending_blocks);
    }
}

