use std::collections::BTreeMap;

#[derive(Clone, Copy)]
struct Record {
    state: &'static str,
    changes: u32,
}

fn apply_event(rec: &mut Record, event: &str) {
    let next = match event {
        "create" => Some("new"),
        "start" => Some("in_progress"),
        "block" => Some("blocked"),
        "unblock" => Some("in_progress"),
        "resolve" => Some("resolved"),
        "reopen" => Some("new"),
        "close" => Some("closed"),
        _ => None,
    };

    if let Some(state) = next {
        rec.state = state;
        rec.changes += 1;
    }
}

fn main() {
    let events = [
        ("A", "create"),
        ("A", "start"),
        ("A", "resolve"),
        ("A", "close"),
        ("A", "reopen"),
        ("A", "start"),
        ("A", "resolve"),
        ("B", "start"),
