        ("B", "reopen"),
        ("C", "create"),
        ("C", "block"),
        ("C", "unblock"),
        ("D", "create"),
        ("D", "close"),
        ("D", "start"),
        ("D", "resolve"),
        ("D", "close"),
    ];

    let mut map: BTreeMap<&str, Record> = BTreeMap::new();

    for (id, event) in events {
        let rec = map.entry(id).or_insert(Record {
