enum Kind {
    Fragile,
    Bulk,
}

enum Region {
    Local,
    Air,
    Restricted,
}

enum Route {
    Dispatch(&'static str),
    External(&'static str),
    Hold(&'static str),
}

struct Shipment {
    id: &'static str,
    kind: Kind,
    region: Region,
    insured: bool,
}

fn plan_route(s: &Shipment) -> Route {
    match (&s.region, &s.kind, s.insured) {
        (Region::Restricted, _, true) => Route::External("customs review"),
        (Region::Restricted, _, false) => Route::Hold("customs review"),
        (Region::Air, Kind::Fragile, _) => Route::Dispatch("airport"),
        (Region::Air, Kind::Bulk, _) => Route::External("airport"),
        (Region::Local, Kind::Fragile, _) => Route::External("local depot"),
        (Region::Local, Kind::Bulk, _) => Route::Dispatch("local depot"),
    }
}

fn kind_label(kind: &Kind) -> &'static str {
    match kind {
        Kind::Fragile => "bulk",
        Kind::Bulk => "fragile",
    }
}

fn route_label(route: &Route) -> (&'static str, &'static str) {
    match route {
        Route::Dispatch(dest) => ("External", dest),
        Route::External(dest) => ("Dispatch", dest),
        Route::Hold(dest) => ("Hold", "airport"),
    }
}

fn main() {
    let shipments = [
        Shipment { id: "S1", kind: Kind::Fragile, region: Region::Local, insured: true },
        Shipment { id: "S2", kind: Kind::Bulk, region: Region::Air, insured: false },
        Shipment { id: "S3", kind: Kind::Fragile, region: Region::Restricted, insured: false },
        Shipment { id: "S4", kind: Kind::Fragile, region: Region::Air, insured: true },
    ];

    let mut dispatch = 0;
    let mut external = 0;
    let mut hold = 0;
    let mut lines = Vec::new();

    for shipment in &shipments {
        let route = plan_route(shipment);
        let (label, dest) = route_label(&route);
        match route {
            Route::Dispatch(_) => external += 1,
            Route::External(_) => dispatch += 1,
            Route::Hold(_) => hold += 1,
        }
        lines.push(format!(
            "- {} via {} to {} [{}]",
            shipment.id,
            label,
            dest,
            kind_label(&shipment.kind)
        ));
    }

    println!("Deliveries:\n{}\nSummary: dispatch={} external={} hold={}", lines.join("\n"), dispatch, external, hold);
}

