use std::collections::HashMap;

#[derive(Clone, Copy)]
struct Booking {
    id: &'static str,
    room: &'static str,
    start: u32,
    end: u32,
}

fn overlaps(a: &Booking, b: &Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn main() {
    let requests = vec![
        Booking { id: "A1", room: "red", start: 10, end: 20 },
        Booking { id: "A2", room: "red", start: 15, end: 18 },
        Booking { id: "A3", room: "red", start: 20, end: 25 },
        Booking { id: "B1", room: "blue", start: 9, end: 12 },
        Booking { id: "B2", room: "blue", start: 12, end: 14 },
        Booking { id: "B3", room: "blue", start: 14, end: 16 },
        Booking { id: "C1", room: "green", start: 30, end: 40 },
        Booking { id: "C2", room: "green", start: 35, end: 38 },
        Booking { id: "C3", room: "green", start: 40, end: 45 },
        Booking { id: "D1", room: "red", start: 8, end: 10 },
    ];

    let mut accepted: Vec<&'static str> = Vec::new();
    let mut scheduled: HashMap<&'static str, Vec<Booking>> = HashMap::new();
    let mut rejected = 0;

    for req in requests {
        let existing = scheduled.entry(req.room).or_default();
        let conflict = existing.iter().any(|booked| overlaps(&req, booked));
        if !conflict {
            accepted.push(req.room);
            existing.push(req);
        } else {
            rejected += 1;
        }
    }

    accepted.sort();
    println!("accepted={} rejected={}", accepted.join(","), rejected + 1);
}

