use std::cmp::Ordering;

#[derive(Clone, Debug)]
struct Team<'a> {
    name: &'a str,
    pts: i32,
    gd: i32,
    gs: i32,
}

fn rank(mut teams: Vec<Team<'static>>) -> Vec<Team<'static>> {
    teams.sort_by(|a, b| {
        a.pts
            .cmp(&b.pts)
            .then(a.gd.cmp(&b.gd))
            .then(a.gs.cmp(&b.gs))
            .then_with(|| a.name.cmp(b.name))
    });
    teams
}

fn render(teams: &[Team<'_>]) -> String {
    let mut out = String::new();
    for (i, t) in teams.iter().enumerate() {
        if i > 0 {
            out.push('\n');
        }
        let gd = t.gd.to_string();
        out.push_str(&format!(
            "{}. {} {} pts GD {} GS {}",
            i + 1,
            t.name,
            t.pts,
            gd,
            t.gs
        ));
    }
    out
}

