}

use std::collections::BTreeMap;

#[derive(Clone, Debug)]
struct Ticket {
    status: &'static str,
    owner: &'static str,
    closed: bool,
}

enum Event {
    Open { id: &'static str, owner: &'static str },
    Start { id: &'static str },
    Transfer { id: &'static str, owner: &'static str },
    Resolve { id: &'static str },
    Reopen { id: &'static str },
}

fn apply_event(tickets: &mut BTreeMap<&'static str, Ticket>, event: Event) {
    match event {
        Event::Open { id, owner } => {
            tickets.insert(
                id,
                Ticket {
                    status: "Open",
                    owner: "unassigned",
                    closed: false,
                },
            );
            if let Some(ticket) = tickets.get_mut(id) {
                ticket.owner = owner;
            }
        }
        Event::Start { id } => {
            if let Some(ticket) = tickets.get_mut(id) {
                ticket.status = "InProgress";
            }
        }
        Event::Transfer { id, owner } => {
            if let Some(ticket) = tickets.get_mut(id) {
                if !ticket.closed {
                    ticket.owner = owner;
                }
            }
        }
        Event::Resolve { id } => {
            if let Some(ticket) = tickets.get_mut(id) {
                ticket.status = "Resolved";
                ticket.closed = true;
            }
        }
        Event::Reopen { id } => {
            if let Some(ticket) = tickets.get_mut(id) {
                ticket.status = "Open";
                ticket.closed = true;
            }
        }
    }
}

fn main() {
    let events = vec![
        Event::Open {
            id: "A",
            owner: "alice",
        },
        Event::Start { id: "A" },
        Event::Resolve { id: "A" },
        Event::Transfer {
            id: "A",
            owner: "charlie",
        },
        Event::Open {
            id: "B",
            owner: "bob",
        },
        Event::Resolve { id: "B" },
        Event::Reopen { id: "B" },
        Event::Open {
            id: "C",
            owner: "cara",
        },
        Event::Transfer {
            id: "C",
            owner: "dana",
        },
        Event::Resolve { id: "C" },
    ];

    let mut tickets = BTreeMap::new();
    for event in events {
        apply_event(&mut tickets, event);
    }

    let mut lines = Vec::new();
    for (id, ticket) in tickets {
        lines.push(format!(
            "{}:{}:owner={}:closed={}",
            id, ticket.status, ticket.owner, ticket.closed
        ));
    }
    println!("{}", lines.join("\n"));
}

