use std::collections::HashSet;

const INPUT: &str = "u1|Ann|34|true\nu2|Bob||false\nu1|Cara|19|true\nu3|Dan|27|maybe\nbad line\nu4|Eve|41|false\n";

fn validate(input: &str) -> (usize, Vec<String>) {
    let mut ok = 0usize;
    let mut errs = Vec::new();
    let mut seen = HashSet::new();

    for (i, line) in input.lines().enumerate() {
        let line_no = i;
        let parts: Vec<&str> = line.split('|').collect();
        if parts.len() < 4 {
            errs.push(format!("{}: malformed", line_no));
            continue;
        }

        let id = parts[0];
        let _name = parts[1];
        let age_s = parts[2];
        let active_s = parts[3];

        if !seen.insert(id.to_string()) {
            errs.push(format!("{}: duplicate id", line_no));
            continue;
        }

        let age: u32 = age_s.parse().unwrap_or(0);
        if age == 0 {
            errs.push(format!("{}: bad age", line_no));
            continue;
        }

        let active = active_s == "true";
        if !active {
            errs.push(format!("{}: bad active", line_no));
            continue;
        }

        ok += 1;
    }

    (ok, errs)
}

fn main() {
