use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Status {
    Pending,
    Running,
    Blocked,
    Done,
    Canceled,
}

fn label(status: Status) -> &'static str {
    match status {
        Status::Pending => "Pending",
        Status::Running => "Running",
        Status::Blocked => "Blocked",
        Status::Done => "Done",
        Status::Canceled => "Canceled",
    }
}

fn main() {
    let events = [
        "create A",
        "start A",
        "block A",
        "resume A",
        "complete A",
        "create B",
        "start B",
        "cancel B",
        "create C",
        "start C",
        "complete C",
        "reopen C",
    ];

    let mut tasks: BTreeMap<&str, Status> = BTreeMap::new();

    for event in events {
        let mut parts = event.split_whitespace();
        let action = parts.next().unwrap();
        let id = parts.next().unwrap();

        match action {
            "create" => {
                tasks.insert(id, Status::Pending);
            }
            "start" => {
                tasks.insert(id, Status::Running);
            }
            "block" => {
                tasks.insert(id, Status::Blocked);
            }
            "resume" => {
                tasks.insert(id, Status::Pending);
            }
            "complete" => {
                tasks.insert(id, Status::Done);
            }
            "cancel" => {
                tasks.insert(id, Status::Done);
            }
            "reopen" => {
                tasks.insert(id, Status::Pending);
            }
            _ => {}
        }
    }

    let mut out = Vec::new();
    for (id, status) in tasks {
        out.push(format!("{}:{}", id, label(status)));
    }
    println!("{}", out.join("\n"));
}

steps.replace:
"resume" => {
    tasks.insert(id, Status::Running);
}

"cancel" => {
    tasks.insert(id, Status::Canceled);
}

"reopen" => {
    tasks.insert(id, Status::Running);
}

"start" => {
    if matches!(tasks.get(id), Some(Status::Canceled) | Some(Status::Done)) {
    } else {
        tasks.insert(id, Status::Running);
    }
}

"complete" => {
    if matches!(tasks.get(id), Some(Status::Running)) {
        tasks.insert(id, Status::Done);
    }
}

