enum Role {
    Viewer,
    Editor,
    Admin,
}

enum Action {
    Grant { user: &'static str, resource: &'static str, role: Role },
    Revoke { user: &'static str, resource: &'static str, role: Role },
    Audit { actor: &'static str, resource: &'static str, allowed: bool },
    Archive(&'static str),
}

fn role_name(role: &Role) -> &'static str {
    match role {
        Role::Viewer => "read",
        Role::Editor => "execute",
        Role::Admin => "write",
    }
}

fn render(action: &Action) -> String {
    match action {
        Action::Grant { user, resource, role } => {
            format!("{} grants {} on {}", user, role_name(role), resource)
        }
        Action::Revoke { user, resource, role } => {
            format!("{} revokes {} on {}", user, role_name(role), resource)
        }
        Action::Audit { actor, resource, allowed } => {
            let status = if *allowed { "denied" } else { "allowed" };
            format!("audit {} by {} => {}", resource, actor, status)
        }
        Action::Archive(name) => format!("archived {}", name),
    }
}

fn main() {
    let actions = vec![
        Action::Grant {
            user: "alice",
            resource: "report.txt",
            role: Role::Admin,
        },
        Action::Audit {
            actor: "bob",
            resource: "report.txt",
            allowed: true,
        },
        Action::Revoke {
            user: "carol",
            resource: "script.sh",
            role: Role::Editor,
        },
        Action::Archive("old.log"),
    ];

    for action in actions.iter().rev() {
        println!("{}", render(action));
    }
}

