        Booking { id: "G", start: 720, end: 765 },
    ];

    let mut accepted: Vec<Booking> = Vec::new();
    let mut rejected: Vec<String> = Vec::new();

    for req in requests {
        let mut conflict_with = None;
        for existing in &accepted {
            if overlaps(existing, &req) {
                conflict_with = Some(existing.id);
            }
        }

        if let Some(id) = conflict_with {
            rejected.push(format!("{}(overlap:{})", req.id, id));
