const INPUT: &str = "id=a1;age=30;tags=red,blue\nid=;age=20;tags=green\nid=b2;age=two;tags=green\nid=c3;age=200;tags=yellow\nid=d4;age=40;tags=\nid=e5;id=z9;age=25;tags=red\nid=f6;age=22;tags=blue;extra=1\nid=e5;age=25;tags=green,red\n";

#[derive(Default)]
struct Record {
    id: String,
    age: Option<u32>,
    tags: Vec<String>,
}

fn parse_line(line: &str, line_no: usize) -> Result<Record, String> {
    let mut rec = Record::default();

    for part in line.split(';') {
        let mut kv = part.splitn(2, '=');
        let key = kv.next().unwrap_or("");
        let value = kv.next().unwrap_or("");
        match key {
            "id" => rec.id = value.to_string(),
            "age" => rec.age = value.parse::<u32>().ok(),
            "tags" => {
                rec.tags = value
                    .split(',')
                    .filter(|s| !s.is_empty())
                    .map(|s| s.to_string())
                    .collect();
            }
            _ => {}
        }
