use std::collections::BTreeMap;

#[derive(Clone, Debug)]
struct Entry {
    name: String,
    score: i32,
    penalties: i32,
    wins: i32,
}

fn parse(input: &str) -> Vec<Entry> {
    input
        .lines()
        .filter(|line| !line.trim().is_empty())
        .map(|line| {
            let mut parts = line.split(',');
            Entry {
                name: parts.next().unwrap().to_string(),
                score: parts.next().unwrap().parse().unwrap(),
                penalties: parts.next().unwrap().parse().unwrap(),
                wins: parts.next().unwrap().parse().unwrap(),
            }
        })
        .collect()
}

fn aggregate(entries: Vec<Entry>) -> Vec<Entry> {
    let mut by_name: BTreeMap<String, Entry> = BTreeMap::new();
    for e in entries {
        by_name
            .entry(e.name.clone())
            .and_modify(|cur| {
                cur.score += e.score;
                cur.penalties += e.penalties;
                cur.wins += e.wins;
            })
            .or_insert(e);
    }
    by_name.into_values().collect()
}

fn sort_entries(entries: &mut [Entry]) {
    entries.sort_by(|a, b| {
        b.score
            .cmp(&a.score)
            .then(a.penalties.cmp(&b.penalties))
            .then(a.name.cmp(&b.name))
    });
}

fn format_board(entries: &[Entry]) -> String {
    let mut out = Vec::new();
    for (idx, e) in entries.iter().enumerate() {
        out.push(format!(
            "{}. {} score={} penalties={} wins={}",
            idx + 1,
            e.name,
            e.score,
            e.penalties,
            e.wins
        ));
    }
    out.join("\n")
}

fn main() {
    let input = "Ada,10,1,3
Bo,8,1,2
Cy,8,1,2
Ada,5,0,1
Bo,7,1,3
Cy,7,1,3
Di,12,0,3
Eli,12,0,4";

    let mut entries = parse(input);
    sort_entries(&mut entries);
    let report = format_board(&entries);
    println!("{}", report);
}

