}

fn main() {
    let entries = [
        Entry { region: "NA", team: "alpha", planned: 10, approved: 8, active: true },
        Entry { region: "NA", team: "beta", planned: 5, approved: 2, active: true },
        Entry { region: "NA", team: "gamma", planned: 7, approved: 7, active: false },
        Entry { region: "EU", team: "delta", planned: 8, approved: 7, active: true },
        Entry { region: "EU", team: "epsilon", planned: 4, approved: 4, active: false },
        Entry { region: "APAC", team: "zeta", planned: 6, approved: 3, active: true },
        Entry { region: "APAC", team: "eta", planned: 4, approved: 5, active: true },
    ];

    let mut by_region: BTreeMap<&str, Vec<Entry>> = BTreeMap::new();
    for entry in entries {
        by_region.entry(entry.region).or_default().push(entry);
    }

    let mut lines = Vec::new();
    let mut grand_total = 0u32;

    for (region, group) in by_region {
        let teams = group.len();
        let approved_hours: u32 = group.iter().map(|e| e.approved).sum();
        let utilization_sum: f64 = group
            .iter()
            .map(|e| e.approved as f64 / e.planned as f64)
            .sum();
        let average_utilization = utilization_sum / teams as f64;
        grand_total += approved_hours;

        lines.push(format!("Region {}", region));
        lines.push(format!("  teams: {}", teams));
        lines.push(format!("  approved_hours: {}", approved_hours));
        lines.push(format!("  average_utilization: {:.2}", average_utilization));
    }

    lines.push(format!("Grand total approved_hours: {}", grand_total));
    println!("{}", lines.join("\n"));
}

use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum State {
    Draft,
    Submitted,
    Approved,
    Rejected,
    Cancelled,
}

impl State {
    fn as_str(&self) -> &'static str {
        match self {
            State::Draft => "draft",
            State::Submitted => "submitted",
            State::Approved => "approved",
            State::Rejected => "rejected",
            State::Cancelled => "cancelled",
        }
    }

    fn terminal(&self) -> bool {
        matches!(self, State::Approved | State::Rejected)
    }
}

#[derive(Clone)]
struct Request {
    state: State,
    reopen_count: u8,
    flagged: bool,
}

impl Request {
    fn new() -> Self {
        Self {
            state: State::Draft,
            reopen_count: 0,
            flagged: false,
        }
    }
}

fn apply(req: &mut Request, event: &str) {
    match event {
        "submit" => {
            if matches!(req.state, State::Draft | State::Rejected) {
                req.state = State::Submitted;
            }
        }
        "approve" => {
            if matches!(req.state, State::Submitted) {
                req.state = State::Approved;
            }
        }
        "reject" => {
            if matches!(req.state, State::Submitted) {
                req.state = State::Rejected;
            }
        }
        "reopen" => {
            req.reopen_count += 1;
            req.state = State::Draft;
        }
        "flag" => {
            req.flagged = true;
        }
        "clear_flag" => {
            req.flagged = false;
        }
        "cancel" => {
            if !req.state.terminal() {
                req.state = State::Cancelled;
            }
        }
        _ => {}
    }
}

fn main() {
    let input = [
        ("REQ-1", "submit"),
        ("REQ-1", "approve"),
        ("REQ-1", "flag"),
        ("REQ-2", "submit"),
        ("REQ-2", "reject"),
        ("REQ-2", "reopen"),
        ("REQ-2", "submit"),
        ("REQ-2", "cancel"),
        ("REQ-3", "submit"),
        ("REQ-3", "reject"),
        ("REQ-3", "reopen"),
        ("REQ-3", "reopen"),
        ("REQ-3", "submit"),
        ("REQ-3", "clear_flag"),
    ];

    let mut requests: BTreeMap<&str, Request> = BTreeMap::new();
    for (id, event) in input {
        let req = requests.entry(id).or_insert_with(Request::new);
        apply(req, event);
    }

    let mut lines = Vec::new();
    for (id, req) in requests {
        lines.push(format!("{}:{}:{}", id, req.state.as_str(), req.flagged));
    }
    println!("{}", lines.join("\n"));
}

