        req.reopen_count += 1;
        req.state = State::Draft;
    }
}

"cancel" => {
    if matches!(req.state, State::Draft | State::Submitted) {
        req.state = State::Cancelled;
    }
}

"approve" => {
    if matches!(req.state, State::Submitted) && !req.flagged {
        req.state = State::Approved;
    }
}

