enum Channel {
    Email,
    Slack,
    Pager,
    Push,
}

enum Priority {
    Low,
    Normal,
    High,
}

enum Event {
    Notify {
        channel: Channel,
        priority: Priority,
        recipient: &'static str,
        acked: bool,
    },
    Digest {
        recipient: &'static str,
        count: u8,
    },
}

enum Action {
    Sent,
    Queued,
    Skipped,
    Escalated,
    Muted,
}

fn decide(event: &Event) -> Action {
    match event {
        Event::Notify {
            channel: Channel::Email,
            priority: Priority::High,
            ..
        } => Action::Queued,
        Event::Notify {
            channel: Channel::Email,
            ..
        } => Action::Sent,
        Event::Notify {
            channel: Channel::Slack,
            priority: Priority::Low,
            ..
        } => Action::Sent,
        Event::Notify {
            channel: Channel::Slack,
            ..
        } => Action::Muted,
        Event::Notify {
            channel: Channel::Pager,
            acked: true,
            ..
        } => Action::Escalated,
        Event::Notify {
            channel: Channel::Pager,
            ..
        } => Action::Queued,
        Event::Notify {
            channel: Channel::Push,
            priority: Priority::High,
            ..
        } => Action::Escalated,
        Event::Notify {
            channel: Channel::Push,
            ..
        } => Action::Sent,
        Event::Digest { count, .. } if *count >= 5 => Action::Skipped,
        Event::Digest { .. } => Action::Queued,
    }
}

fn label(event: &Event) -> String {
    match event {
        Event::Notify {
            channel,
            recipient,
            ..
        } => {
            let ch = match channel {
                Channel::Email => "email",
                Channel::Slack => "slack",
                Channel::Pager => "pager",
                Channel::Push => "push",
            };
            format!("{} to {}", ch, recipient)
        }
        Event::Digest { recipient, .. } => format!("email to {}", recipient),
    }
}

fn action_word(action: &Action) -> &'static str {
    match action {
        Action::Sent => "send",
        Action::Queued => "queue",
        Action::Skipped => "skip",
        Action::Escalated => "escalate",
        Action::Muted => "mute",
    }
}

fn score(action: &Action) -> i32 {
    match action {
        Action::Sent => 10,
        Action::Queued => 3,
        Action::Skipped => 0,
        Action::Escalated => 9,
        Action::Muted => 1,
    }
}

fn main() {
    let events = [
        Event::Notify {
            channel: Channel::Email,
            priority: Priority::High,
            recipient: "ops",
            acked: false,
        },
        Event::Notify {
            channel: Channel::Slack,
            priority: Priority::Low,
            recipient: "eng",
            acked: false,
        },
        Event::Notify {
            channel: Channel::Pager,
            priority: Priority::Normal,
            recipient: "oncall",
            acked: true,
        },
        Event::Digest {
            recipient: "team",
            count: 5,
        },
        Event::Notify {
            channel: Channel::Push,
            priority: Priority::Normal,
            recipient: "mobile",
            acked: false,
        },
    ];

    let mut total_score = 0;
    let mut sent = 0;
    let mut queued = 0;
    let mut skipped = 0;
    let mut escalated = 0;
    let mut muted = 0;

    for event in &events {
        let action = decide(event);
        total_score += score(&action);
        match action {
            Action::Sent => sent += 1,
            Action::Queued => queued += 1,
            Action::Skipped => skipped += 1,
            Action::Escalated => escalated += 1,
            Action::Muted => muted += 1,
        }
        println!("{} => {}", label(event), action_word(&action));
    }

    println!(
        "score={} sent={} queued={} skipped={} escalated={} muted={}",
        total_score, sent, queued, skipped, escalated, muted
    );
}

