use std::collections::BTreeSet;

#[derive(Clone)]
struct Config {
    host: Option<&'static str>,
    port: Option<u16>,
    tls: Option<bool>,
    mode: Option<&'static str>,
    retries: Option<u8>,
    features: Vec<&'static str>,
    timeout: Option<u32>,
}

fn merge(base: &Config, env: &Config, user: &Config, cli: &Config) -> Config {
    let host = base.host.or(env.host).or(user.host).or(cli.host);
    let port = base.port.or(env.port).or(user.port).or(cli.port);
    let tls = base.tls.or(env.tls).or(user.tls).or(cli.tls);
    let mode = base.mode.or(env.mode).or(user.mode).or(cli.mode);
    let retries = cli.retries.or(user.retries).or(env.retries).or(base.retries);

    let mut features = Vec::new();
    features.extend(base.features.iter().copied());
    features.extend(env.features.iter().copied());
    features.extend(user.features.iter().copied());
    features.extend(cli.features.iter().copied());

    let timeout = cli.timeout.or(user.timeout).or(env.timeout).or(base.timeout);

    Config {
        host,
        port,
        tls,
        mode,
        retries,
        features,
        timeout,
    }
}

fn fmt_timeout(v: Option<u32>) -> String {
    match v {
        Some(n) => n.to_string(),
        None => "none".to_string(),
    }
}

