struct Booking {
    id: &'static str,
    start: u32,
    end: u32,
    room: &'static str,
}

fn overlaps(a: &Booking, b: &Booking) -> bool {
    a.room == b.room && a.start <= b.end && b.start <= a.end
}

fn main() {
    let requests = vec![
        Booking { id: "A", start: 540, end: 600, room: "red" },
        Booking { id: "B", start: 600, end: 630, room: "red" },
        Booking { id: "C", start: 590, end: 610, room: "red" },
        Booking { id: "D", start: 600, end: 660, room: "blue" },
        Booking { id: "E", start: 620, end: 650, room: "blue" },
        Booking { id: "F", start: 660, end: 720, room: "red" },
        Booking { id: "G", start: 700, end: 730, room: "red" },
        Booking { id: "H", start: 720, end: 750, room: "red" },
    ];

    let mut accepted: Vec<&Booking> = Vec::new();
    let mut rejected: Vec<&Booking> = Vec::new();
    let mut conflicts: Vec<(&str, &str)> = Vec::new();

    for req in &requests {
        let mut blocker = None;
        for existing in &accepted {
            if overlaps(req, existing) {
                blocker = Some(existing.id);
            }
        }
        if let Some(id) = blocker {
            rejected.push(req);
            conflicts.push((id, req.id));
        } else {
            accepted.push(req);
        }
    }

    let accepted_ids = accepted.iter().map(|b| b.id).collect::<Vec<_>>().join(",");
    let rejected_ids = rejected.iter().map(|b| b.id).collect::<Vec<_>>().join(",");

    println!("accepted: {}", accepted_ids);
    println!("rejected: {}", rejected_ids);
    println!("conflicts:");
    for (a, b) in conflicts {
        println!("{} -> {}", a, b);
    }
}

